import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // --- MEMOIZED BRACKET GENERATION (With Robust Progression) ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const getLoserTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA || !teamB) return null;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > 0 || scoreB > 0) {
            if (scoreA < scoreB) return teamA;
            if (scoreB < scoreA) return teamB;
        }
        return null;
      };

      const hasQuarterFinals = match.teams.length > 5; // Adjust to include 5 as special

      // Special Logic for 3 teams: Stepladder / Lower Bracket style
      if (match.teams.length === 3) {
        const m0 = {
          id: 0,
          label: 'ELIMINATION',
          mode: 'BO1',
          teamA: match.teams[0],
          teamB: match.teams[1]
        };
        const m1 = {
          id: 1,
          label: 'CHALLENGER',
          mode: 'BO1',
          teamA: getLoserTeam(0, match.teams[0], match.teams[1]),
          teamB: match.teams[2]
        };
        const m2 = {
            id: 2,
            label: 'GRAND FINAL',
            mode: 'BO3',
            teamA: getWinnerTeam(0, match.teams[0], match.teams[1]),
            teamB: getWinnerTeam(1, m1.teamA, match.teams[2])
        };
        return { 
          quarterMatches: [], 
          semiMatches: [m0, m1], 
          grandFinalMatch: m2, 
          allMatches: [m0, m1, m2], 
          hasQuarterFinals: false 
        };
      }

      // NEW: Special Logic for 5 teams: Stepladder expansion
      // Tim kalah melawan tim waiting
      if (match.teams.length === 5) {
        const m0 = {
          id: 0,
          label: 'ELIMINATION 1',
          mode: 'BO1',
          teamA: match.teams[0],
          teamB: match.teams[1]
        };
        const m1 = {
          id: 1,
          label: 'ELIMINATION 2',
          mode: 'BO1',
          teamA: getLoserTeam(0, match.teams[0], match.teams[1]),
          teamB: match.teams[2]
        };
        const m2 = {
          id: 2,
          label: 'ELIMINATION 3',
          mode: 'BO1',
          teamA: getLoserTeam(1, m1.teamA, match.teams[2]),
          teamB: match.teams[3]
        };
        const m3 = {
          id: 3,
          label: 'CHALLENGER',
          mode: 'BO1',
          teamA: getLoserTeam(2, m2.teamA, match.teams[3]),
          teamB: match.teams[4]
        };
        const m4 = {
            id: 4,
            label: 'GRAND FINAL',
            mode: 'BO3',
            teamA: getWinnerTeam(0, match.teams[0], match.teams[1]), // Winner of first match is first finalist
            teamB: getWinnerTeam(3, m3.teamA, match.teams[4]) // Final survivor is second finalist
        };
        return { 
          quarterMatches: [], 
          semiMatches: [m0, m1, m2, m3], 
          grandFinalMatch: m4, 
          allMatches: [m0, m1, m2, m3, m4], 
          hasQuarterFinals: false 
        };
      }

      // Default logic for even/other odd counts
      const qMatches: any[] = [];
      if (hasQuarterFinals) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({
                  id: i,
                  label: `QUARTER ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      const sMatches: any[] = [];
      if (hasQuarterFinals) {
          sMatches.push({
              id: 4,
              label: 'SEMI FINAL 1',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[0].id, qMatches[0].teamA, qMatches[0].teamB),
              teamB: getWinnerTeam(qMatches[1].id, qMatches[1].teamA, qMatches[1].teamB)
          });
          sMatches.push({
              id: 5,
              label: 'SEMI FINAL 2',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[2].id, qMatches[2].teamA, qMatches[2].teamB),
              teamB: getWinnerTeam(qMatches[3].id, qMatches[3].teamA, qMatches[3].teamB)
          });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({
                  id: i,
                  label: `SEMI FINAL ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      const gfIndex = hasQuarterFinals ? 6 : 2;
      const grandFinalMatch = {
          id: gfIndex,
          label: 'GRAND FINAL',
          mode: 'BO3',
          teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB),
          teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB)
      };

      return { 
          quarterMatches: qMatches, 
          semiMatches: sMatches, 
          grandFinalMatch, 
          allMatches: [...qMatches, ...sMatches, grandFinalMatch], 
          hasQuarterFinals 
      };
  }, [match, scores]); 

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);
    if (m && !m.teamB) {
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }
    setCurrentMatchIdx(idx);
    if (idx === grandFinalMatch.id) setPhase('TRANSITION');
    else {
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const EnergyConnector = ({ type, height }: { type: 'fork' | 'straight', height: number }) => (
    <div 
        className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" 
        style={{ height: `${height}px` }}
    >
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3" result="blur"/>
                <feComposite in="SourceGraphic" in2="blur" operator="over"/>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path 
                d={`M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          ) : (
             <path 
                d={`M 0,0 L 100,0`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          )}
          {/* Moving particles */}
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion 
                path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,0 L 100,0`} 
                dur="2s" 
                repeatCount="indefinite" 
              />
          </circle>
          {type === 'fork' && (
            <circle r="3" fill="#fff" filter="url(#energyGlow)">
                <animateMotion 
                  path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} 
                  dur="2s" 
                  begin="1s"
                  repeatCount="indefinite" 
                />
            </circle>
          )}
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';

      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-sm p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>

            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>

                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1">
                        <div className="h-[1px] flex-1 bg-white"></div>
                        <span className="text-[8px] font-black italic text-[#8a9db8]">VS</span>
                        <div className="h-[1px] flex-1 bg-white"></div>
                    </div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>

            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input 
                              type="text" 
                              value={matchRoomIds[m.id] || ''} 
                              onChange={(e) => {
                                const val = e.target.value.replace(/\D/g,'').slice(0,4);
                                setMatchRoomIds(prev => ({ ...prev, [m.id]: val }));
                              }} 
                              className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" 
                              placeholder="----"
                            />
                        </div>
                        {!isDone && m.teamA && m.teamB && (
                            <Button 
                              onClick={() => startMatchFlow(m.id)} 
                              disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} 
                              size="sm" 
                              className="h-[28px] text-[8px] px-3"
                            >
                              START
                            </Button>
                        )}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const handleNextReveal = () => {
    if (!activeMatchData) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    const crimsonId = `m${currentMatchIdx}-B-${role}`;

    // Choose team to reveal
    let side: 'azure' | 'crimson' = 'azure';
    if (revealedSlots.has(azureId)) {
        side = 'crimson';
    }

    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    const winner = teamData?.slots.find((s:TeamSlot) => s.role === role)?.player;
    if (!winner) return;

    // Filter candidates just like MatchDisplay
    const revealedPlayerIds = new Set<string>();
    activeMatchData.teamA?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-A-${s.role}`)) revealedPlayerIds.add(s.player.id); });
    activeMatchData.teamB?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-B-${s.role}`)) revealedPlayerIds.add(s.player.id); });

    const candidates = activePlayers.filter(p => {
        if (revealedPlayerIds.has(p.id)) return false;
        return p.isAllRoles || p.roles.includes(role);
    });

    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);

    const randomDuration = Math.floor(Math.random() * (9000 - 4500 + 1)) + 4500;

    setWheelState({
        isOpen: true,
        type: 'reveal',
        team: side,
        role: role,
        winnerName: winner.name,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleSkipAll = () => {
    const allCards = new Set<string>();
    ROLES_ORDER.forEach(r => { 
        allCards.add(`m${currentMatchIdx}-A-${r}`); 
        allCards.add(`m${currentMatchIdx}-B-${r}`); 
    });
    setRevealedSlots(allCards);
    setCurrentRoleIdx(ROLES_ORDER.length - 1);
  };

  const handleRerollClick = (side: 'azure' | 'crimson', role: Role) => {
    const teamData = side === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    if (!teamData) return;

    // Find original team index in match.teams to call parent onReroll
    const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
    if (originalTeamIndex === -1) return;

    const azureIds = new Set(activeMatchData?.teamA?.slots.map(s => s.player.id));
    const crimsonIds = new Set(activeMatchData?.teamB?.slots.map(s => s.player.id));

    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));
    if (benchPlayers.length === 0) return;

    const candidates = benchPlayers.filter(p => p.isAllRoles || p.roles.includes(role));
    if (candidates.length === 0) return;

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);

    // Use wheel for reroll as well
    const randomDuration = Math.floor(Math.random() * (8000 - 4000 + 1)) + 4000;
    setWheelState({
        isOpen: true,
        type: 'reroll',
        team: side,
        role: role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
        const { team, role } = wheelState;
        const id = `m${currentMatchIdx}-${team === 'azure' ? 'A' : 'B'}-${role}`;
        setRevealedSlots(prev => new Set(prev).add(id));
        if (team === 'crimson') setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        const teamData = wheelState.team === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
        if (teamData) {
            const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
            if (originalTeamIndex !== -1) {
                onReroll(originalTeamIndex, wheelState.role, wheelState.winnerPlayer);
            }
        }
    }
    setWheelState(null);
  };

  const renderPlayerCard = (role: Role, teamSide: 'azure' | 'crimson') => {
    const teamData = teamSide === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    const slot = teamData?.slots.find(s => s.role === role);
    const id = `m${currentMatchIdx}-${teamSide === 'azure' ? 'A' : 'B'}-${role}`;
    const isRevealed = revealedSlots.has(id);

    if (!isRevealed) {
       return (
         <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">
               {RoleIcons[role]}
            </div>
         </div>
       );
    }

    const theme = teamSide === 'azure' ? 
      { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' } : 
      { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#ef4444]/20 to-transparent' };

    return (
      <div className="relative h-16 w-full animate-slide-in perspective-container group">
        <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
           <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${teamSide === 'crimson' ? 'right' : 'left'} opacity-90`}>
                {RoleIcons[role]}
             </div>
             <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                {slot?.player.name}
             </span>
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>
           <button 
             onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role); }} 
             className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${teamSide === 'azure' ? 'right-4' : 'left-4'}`}
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
             </svg>
           </button>
        </div>
      </div>
    );
  };

  if (phase === 'TOURNAMENT_END') {
      return (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
            <div className="god-rays opacity-20"></div>
            <h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">GRAND FINAL WINNER</h3>
            <h1 className="text-4xl md:text-7xl font-cinzel font-black text-white mb-8 tracking-widest">TOURNAMENT CHAMPION</h1>
            <div className="bg-[#0a1a2f] border-4 border-[#dcb06b] px-16 py-8 clip-corner-md shadow-[0_0_60px_rgba(220,176,107,0.4)]">
                <h2 className="text-5xl md:text-7xl font-black font-cinzel text-white" style={{ color: tournamentChampion?.color || '#fff' }}>{tournamentChampion?.name}</h2>
            </div>
            <Button onClick={onReset} size="lg" className="mt-16 px-16">RETURN TO LOBBY</Button>
        </div>
      );
  }

  if (phase === 'TRANSITION' && activeMatchData) {
      return (
        <PortalTransition 
            azureTeam={activeMatchData.teamA?.slots || []} 
            crimsonTeam={activeMatchData.teamB?.slots || []} 
            onComplete={() => setPhase('DECLARE_WIN')} 
        />
      );
  }

  if (phase === 'DECLARE_WIN' && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <MatchSummary match={matchObj} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) {
      const slots = currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots;
      return <VictoryCelebration winner={currentRoundWinner} teamSlots={slots || []} onDismiss={() => setPhase('EVALUATION')} />;
  }

  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <EvaluationScreen match={matchObj} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p>
          </div>

          <div className="flex gap-24 md:gap-40 items-center justify-center relative py-20">
            {hasQuarterFinals && (
                <div className="flex flex-col gap-16 relative">
                    {quarterMatches.map((m, i) => (
                        <div key={m.id} className="relative">
                            {renderBracketMatchCard(m)}
                            {i % 2 === 0 && <EnergyConnector type="fork" height={274} />}
                        </div>
                    ))}
                </div>
            )}

            <div className={`flex flex-col ${hasQuarterFinals ? 'gap-72' : (match.teams.length === 5 ? 'gap-12' : 'gap-32')} relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {match.teams.length === 3 && i === 0 && <EnergyConnector type="fork" height={338} />}
                  {match.teams.length === 5 && i === 3 && <EnergyConnector type="fork" height={550} style={{ transform: 'translateY(-420px)' }} />}
                  {hasQuarterFinals && i % 2 === 0 && <EnergyConnector type="fork" height={498} />}
                </div>
              ))}
            </div>

            <div className={`relative scale-125 ml-10 ${match.teams.length === 5 ? 'translate-y-[-100px]' : ''}`}>
                {renderBracketMatchCard(grandFinalMatch)}
            </div>
          </div>

          <button onClick={onReset} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        /* REVEAL PHASE UI */
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState && wheelState.isOpen && (
                <SpinWheel 
                  candidates={wheelState.candidates} 
                  winnerName={wheelState.winnerName} 
                  team={wheelState.team} 
                  roleName={wheelState.role} 
                  roomId={activeRoomId} 
                  duration={wheelState.duration} 
                  onComplete={handleWheelComplete} 
                  onCancel={() => setWheelState(null)} 
                />
            )}

            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center">
                <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">
                    BACK TO BRACKET
                </Button>

                {/* ROOM ID CENTERED IN TOP BAR */}
                <div className="flex flex-col items-center gap-0 scale-[0.85] origin-top">
                    <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.5em] font-black uppercase mb-1 opacity-70">ROOM ID</span>
                    <div className="relative">
                        <div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div>
                        <div className="relative bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]">
                            <span className="text-2xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b]">
                            {activeRoomId}
                            </span>
                        </div>
                    </div>
                </div>

                {revealedSlots.size < 10 ? (
                    <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">
                        SKIP ALL
                    </Button>
                ) : (
                    <div className="w-[120px]"></div> 
                )}
            </div>

            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                {/* TEAM TITLES */}
                <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6">
                    <div className="text-left">
                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-cyan-600 tracking-widest drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]" style={{ color: activeMatchData?.teamA?.color }}>
                            {activeMatchData?.teamA?.name.split(' ')[0]} <span className="hidden md:inline">{activeMatchData?.teamA?.name.split(' ')[1] || 'GOLEM'}</span>
                        </h2>
                        <div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div>
                    </div>
                    <div className="text-right">
                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-100 to-red-600 tracking-widest drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]" style={{ color: activeMatchData?.teamB?.color }}>
                            <span className="hidden md:inline">{activeMatchData?.teamB?.name.split(' ')[0] || 'CRIMSON'}</span> {activeMatchData?.teamB?.name.split(' ')[1] || 'GOLEM'}
                        </h2>
                        <div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div>
                    </div>
                </div>

                {/* VS INDICATOR FLOATING BEHIND GRID */}
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20">
                    <span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span>
                </div>

                {/* PLAYER CARDS */}
                <div className="space-y-4 relative z-10">
                    {ROLES_ORDER.map((role) => (
                        <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center">
                            <div>{renderPlayerCard(role, 'azure')}</div>
                            <div>{renderPlayerCard(role, 'crimson')}</div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none">
                <div className="pointer-events-auto">
                    {revealedSlots.size < 10 ? (
                        <button 
                            onClick={handleNextReveal} 
                            className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]"
                        >
                            {revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? 
                                `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : 
                                `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`
                            }
                        </button>
                    ) : (
                        <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">
                            INITIALIZE BATTLE
                        </Button>
                    )}
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // --- MEMOIZED BRACKET GENERATION (With Robust Progression) ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const getLoserTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA || !teamB) return null;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > 0 || scoreB > 0) {
            if (scoreA < scoreB) return teamA;
            if (scoreB < scoreA) return teamB;
        }
        return null;
      };

      const hasQuarterFinals = match.teams.length > 5; // Adjust to include 5 as special

      // Special Logic for 3 teams: Stepladder / Lower Bracket style
      if (match.teams.length === 3) {
        const m0 = {
          id: 0,
          label: 'ELIMINATION',
          mode: 'BO1',
          teamA: match.teams[0],
          teamB: match.teams[1]
        };
        const m1 = {
          id: 1,
          label: 'CHALLENGER',
          mode: 'BO1',
          teamA: getLoserTeam(0, match.teams[0], match.teams[1]),
          teamB: match.teams[2]
        };
        const m2 = {
            id: 2,
            label: 'GRAND FINAL',
            mode: 'BO3',
            teamA: getWinnerTeam(0, match.teams[0], match.teams[1]),
            teamB: getWinnerTeam(1, m1.teamA, match.teams[2])
        };
        return { 
          quarterMatches: [], 
          semiMatches: [m0, m1], 
          grandFinalMatch: m2, 
          allMatches: [m0, m1, m2], 
          hasQuarterFinals: false 
        };
      }

      // NEW: Special Logic for 5 teams: Stepladder expansion
      // Tim kalah melawan tim waiting
      if (match.teams.length === 5) {
        const m0 = {
          id: 0,
          label: 'ELIMINATION 1',
          mode: 'BO1',
          teamA: match.teams[0],
          teamB: match.teams[1]
        };
        const m1 = {
          id: 1,
          label: 'ELIMINATION 2',
          mode: 'BO1',
          teamA: getLoserTeam(0, match.teams[0], match.teams[1]),
          teamB: match.teams[2]
        };
        const m2 = {
          id: 2,
          label: 'ELIMINATION 3',
          mode: 'BO1',
          teamA: getLoserTeam(1, m1.teamA, match.teams[2]),
          teamB: match.teams[3]
        };
        const m3 = {
          id: 3,
          label: 'CHALLENGER',
          mode: 'BO1',
          teamA: getLoserTeam(2, m2.teamA, match.teams[3]),
          teamB: match.teams[4]
        };
        const m4 = {
            id: 4,
            label: 'GRAND FINAL',
            mode: 'BO3',
            teamA: getWinnerTeam(0, match.teams[0], match.teams[1]), // Winner of first match is first finalist
            teamB: getWinnerTeam(3, m3.teamA, match.teams[4]) // Final survivor is second finalist
        };
        return { 
          quarterMatches: [], 
          semiMatches: [m0, m1, m2, m3], 
          grandFinalMatch: m4, 
          allMatches: [m0, m1, m2, m3, m4], 
          hasQuarterFinals: false 
        };
      }

      // Default logic for even/other odd counts
      const qMatches: any[] = [];
      if (hasQuarterFinals) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({
                  id: i,
                  label: `QUARTER ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      const sMatches: any[] = [];
      if (hasQuarterFinals) {
          sMatches.push({
              id: 4,
              label: 'SEMI FINAL 1',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[0].id, qMatches[0].teamA, qMatches[0].teamB),
              teamB: getWinnerTeam(qMatches[1].id, qMatches[1].teamA, qMatches[1].teamB)
          });
          sMatches.push({
              id: 5,
              label: 'SEMI FINAL 2',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[2].id, qMatches[2].teamA, qMatches[2].teamB),
              teamB: getWinnerTeam(qMatches[3].id, qMatches[3].teamA, qMatches[3].teamB)
          });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({
                  id: i,
                  label: `SEMI FINAL ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      const gfIndex = hasQuarterFinals ? 6 : 2;
      const grandFinalMatch = {
          id: gfIndex,
          label: 'GRAND FINAL',
          mode: 'BO3',
          teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB),
          teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB)
      };

      return { 
          quarterMatches: qMatches, 
          semiMatches: sMatches, 
          grandFinalMatch, 
          allMatches: [...qMatches, ...sMatches, grandFinalMatch], 
          hasQuarterFinals 
      };
  }, [match, scores]); 

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);
    if (m && !m.teamB) {
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }
    setCurrentMatchIdx(idx);
    if (idx === grandFinalMatch.id) setPhase('TRANSITION');
    else {
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  // Fixed: Added style prop to EnergyConnector interface
  const EnergyConnector = ({ type, height, style }: { type: 'fork' | 'straight', height: number, style?: React.CSSProperties }) => (
    <div 
        className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" 
        style={{ height: `${height}px`, ...style }}
    >
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3" result="blur"/>
                <feComposite in="SourceGraphic" in2="blur" operator="over"/>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path 
                d={`M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          ) : (
             <path 
                d={`M 0,0 L 100,0`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          )}
          {/* Moving particles */}
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion 
                path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,0 L 100,0`} 
                dur="2s" 
                repeatCount="indefinite" 
              />
          </circle>
          {type === 'fork' && (
            <circle r="3" fill="#fff" filter="url(#energyGlow)">
                <animateMotion 
                  path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} 
                  dur="2s" 
                  begin="1s"
                  repeatCount="indefinite" 
                />
            </circle>
          )}
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';

      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-sm p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>

            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>

                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1">
                        <div className="h-[1px] flex-1 bg-white"></div>
                        <span className="text-[8px] font-black italic text-[#8a9db8]">VS</span>
                        <div className="h-[1px] flex-1 bg-white"></div>
                    </div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#4a5f78]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>

            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input 
                              type="text" 
                              value={matchRoomIds[m.id] || ''} 
                              onChange={(e) => {
                                const val = e.target.value.replace(/\D/g,'').slice(0,4);
                                setMatchRoomIds(prev => ({ ...prev, [m.id]: val }));
                              }} 
                              className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" 
                              placeholder="----"
                            />
                        </div>
                        {!isDone && m.teamA && m.teamB && (
                            <Button 
                              onClick={() => startMatchFlow(m.id)} 
                              disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} 
                              size="sm" 
                              className="h-[28px] text-[8px] px-3"
                            >
                              START
                            </Button>
                        )}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const handleNextReveal = () => {
    if (!activeMatchData) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    const crimsonId = `m${currentMatchIdx}-B-${role}`;

    // Choose team to reveal
    let side: 'azure' | 'crimson' = 'azure';
    if (revealedSlots.has(azureId)) {
        side = 'crimson';
    }

    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    const winner = teamData?.slots.find((s:TeamSlot) => s.role === role)?.player;
    if (!winner) return;

    // Filter candidates just like MatchDisplay
    const revealedPlayerIds = new Set<string>();
    activeMatchData.teamA?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-A-${s.role}`)) revealedPlayerIds.add(s.player.id); });
    activeMatchData.teamB?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-B-${s.role}`)) revealedPlayerIds.add(s.player.id); });

    const candidates = activePlayers.filter(p => {
        if (revealedPlayerIds.has(p.id)) return false;
        return p.isAllRoles || p.roles.includes(role);
    });

    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);

    const randomDuration = Math.floor(Math.random() * (9000 - 4500 + 1)) + 4500;

    setWheelState({
        isOpen: true,
        type: 'reveal',
        team: side,
        role: role,
        winnerName: winner.name,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleSkipAll = () => {
    const allCards = new Set<string>();
    ROLES_ORDER.forEach(r => { 
        allCards.add(`m${currentMatchIdx}-A-${r}`); 
        allCards.add(`m${currentMatchIdx}-B-${r}`); 
    });
    setRevealedSlots(allCards);
    setCurrentRoleIdx(ROLES_ORDER.length - 1);
  };

  const handleRerollClick = (side: 'azure' | 'crimson', role: Role) => {
    const teamData = side === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    if (!teamData) return;

    // Find original team index in match.teams to call parent onReroll
    const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
    if (originalTeamIndex === -1) return;

    const azureIds = new Set(activeMatchData?.teamA?.slots.map(s => s.player.id));
    const crimsonIds = new Set(activeMatchData?.teamB?.slots.map(s => s.player.id));

    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));
    if (benchPlayers.length === 0) return;

    const candidates = benchPlayers.filter(p => p.isAllRoles || p.roles.includes(role));
    if (candidates.length === 0) return;

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);

    // Use wheel for reroll as well
    const randomDuration = Math.floor(Math.random() * (8000 - 4000 + 1)) + 4000;
    setWheelState({
        isOpen: true,
        type: 'reroll',
        team: side,
        role: role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
        const { team, role } = wheelState;
        const id = `m${currentMatchIdx}-${team === 'azure' ? 'A' : 'B'}-${role}`;
        setRevealedSlots(prev => new Set(prev).add(id));
        if (team === 'crimson') setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        const teamData = wheelState.team === 'azure' ? activeMatchData?.teamA : wheelState.team === 'crimson' ? activeMatchData?.teamB : null;
        if (teamData) {
            const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
            if (originalTeamIndex !== -1) {
                onReroll(originalTeamIndex, wheelState.role, wheelState.winnerPlayer);
            }
        }
    }
    setWheelState(null);
  };

  const renderPlayerCard = (role: Role, teamSide: 'azure' | 'crimson') => {
    const teamData = teamSide === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    const slot = teamData?.slots.find(s => s.role === role);
    const id = `m${currentMatchIdx}-${teamSide === 'azure' ? 'A' : 'B'}-${role}`;
    const isRevealed = revealedSlots.has(id);

    if (!isRevealed) {
       return (
         <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">
               {RoleIcons[role]}
            </div>
         </div>
       );
    }

    const theme = teamSide === 'azure' ? 
      { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' } : 
      { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#ef4444]/20 to-transparent' };

    return (
      <div className="relative h-16 w-full animate-slide-in perspective-container group">
        <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
           <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${teamSide === 'crimson' ? 'right' : 'left'} opacity-90`}>
                {RoleIcons[role]}
             </div>
             <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                {slot?.player.name}
             </span>
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>
           <button 
             onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role); }} 
             className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${teamSide === 'azure' ? 'right-4' : 'left-4'}`}
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
             </svg>
           </button>
        </div>
      </div>
    );
  };

  if (phase === 'TOURNAMENT_END') {
      return (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
            <div className="god-rays opacity-20"></div>
            <h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">GRAND FINAL WINNER</h3>
            <h1 className="text-4xl md:text-7xl font-cinzel font-black text-white mb-8 tracking-widest">TOURNAMENT CHAMPION</h1>
            <div className="bg-[#0a1a2f] border-4 border-[#dcb06b] px-16 py-8 clip-corner-md shadow-[0_0_60px_rgba(220,176,107,0.4)]">
                <h2 className="text-5xl md:text-7xl font-black font-cinzel text-white" style={{ color: tournamentChampion?.color || '#fff' }}>{tournamentChampion?.name}</h2>
            </div>
            <Button onClick={onReset} size="lg" className="mt-16 px-16">RETURN TO LOBBY</Button>
        </div>
      );
  }

  if (phase === 'TRANSITION' && activeMatchData) {
      return (
        <PortalTransition 
            azureTeam={activeMatchData.teamA?.slots || []} 
            crimsonTeam={activeMatchData.teamB?.slots || []} 
            onComplete={() => setPhase('DECLARE_WIN')} 
        />
      );
  }

  if (phase === 'DECLARE_WIN' && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <MatchSummary match={matchObj} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) {
      const slots = currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots;
      return <VictoryCelebration winner={currentRoundWinner} teamSlots={slots || []} onDismiss={() => setPhase('EVALUATION')} />;
  }

  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <EvaluationScreen match={matchObj} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p>
          </div>

          <div className="flex gap-24 md:gap-40 items-center justify-center relative py-20">
            {hasQuarterFinals && (
                <div className="flex flex-col gap-16 relative">
                    {quarterMatches.map((m, i) => (
                        <div key={m.id} className="relative">
                            {renderBracketMatchCard(m)}
                            {i % 2 === 0 && <EnergyConnector type="fork" height={274} />}
                        </div>
                    ))}
                </div>
            )}

            <div className={`flex flex-col ${hasQuarterFinals ? 'gap-72' : (match.teams.length === 5 ? 'gap-12' : 'gap-32')} relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {match.teams.length === 3 && i === 0 && <EnergyConnector type="fork" height={338} />}
                  {match.teams.length === 5 && i === 3 && <EnergyConnector type="fork" height={550} style={{ transform: 'translateY(-420px)' }} />}
                  {hasQuarterFinals && i % 2 === 0 && <EnergyConnector type="fork" height={498} />}
                </div>
              ))}
            </div>

            <div className={`relative scale-125 ml-10 ${match.teams.length === 5 ? 'translate-y-[-100px]' : ''}`}>
                {renderBracketMatchCard(grandFinalMatch)}
            </div>
          </div>

          <button onClick={onReset} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        /* REVEAL PHASE UI */
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState && wheelState.isOpen && (
                <SpinWheel 
                  candidates={wheelState.candidates} 
                  winnerName={wheelState.winnerName} 
                  team={wheelState.team} 
                  roleName={wheelState.role} 
                  roomId={activeRoomId} 
                  duration={wheelState.duration} 
                  onComplete={handleWheelComplete} 
                  onCancel={() => setWheelState(null)} 
                />
            )}

            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center">
                <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">
                    BACK TO BRACKET
                </Button>

                {/* ROOM ID CENTERED IN TOP BAR */}
                <div className="flex flex-col items-center gap-0 scale-[0.85] origin-top">
                    <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.5em] font-black uppercase mb-1 opacity-70">ROOM ID</span>
                    <div className="relative">
                        <div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div>
                        <div className="relative bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]">
                            <span className="text-2xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b]">
                            {activeRoomId}
                            </span>
                        </div>
                    </div>
                </div>

                {revealedSlots.size < 10 ? (
                    <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">
                        SKIP ALL
                    </Button>
                ) : (
                    <div className="w-[120px]"></div> 
                )}
            </div>

            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                {/* TEAM TITLES */}
                <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6">
                    <div className="text-left">
                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-cyan-600 tracking-widest drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]" style={{ color: activeMatchData?.teamA?.color }}>
                            {activeMatchData?.teamA?.name.split(' ')[0]} <span className="hidden md:inline">{activeMatchData?.teamA?.name.split(' ')[1] || 'GOLEM'}</span>
                        </h2>
                        <div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div>
                    </div>
                    <div className="text-right">
                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-100 to-red-600 tracking-widest drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]" style={{ color: activeMatchData?.teamB?.color }}>
                            <span className="hidden md:inline">{activeMatchData?.teamB?.name.split(' ')[0] || 'CRIMSON'}</span> {activeMatchData?.teamB?.name.split(' ')[1] || 'GOLEM'}
                        </h2>
                        <div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div>
                    </div>
                </div>

                {/* VS INDICATOR FLOATING BEHIND GRID */}
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20">
                    <span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span>
                </div>

                {/* PLAYER CARDS */}
                <div className="space-y-4 relative z-10">
                    {ROLES_ORDER.map((role) => (
                        <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center">
                            <div>{renderPlayerCard(role, 'azure')}</div>
                            <div>{renderPlayerCard(role, 'crimson')}</div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none">
                <div className="pointer-events-auto">
                    {revealedSlots.size < 10 ? (
                        <button 
                            onClick={handleNextReveal} 
                            className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]"
                        >
                            {revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? 
                                `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : 
                                `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`
                            }
                        </button>
                    ) : (
                        <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">
                            INITIALIZE BATTLE
                        </Button>
                    )}
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // --- MEMOIZED BRACKET GENERATION (With Robust Progression) ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const getLoserTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA || !teamB) return null;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > 0 || scoreB > 0) {
            if (scoreA < scoreB) return teamA;
            if (scoreB < scoreA) return teamB;
        }
        return null;
      };

      const hasQuarterFinals = match.teams.length > 5; // Adjust to include 5 as special

      // Special Logic for 3 teams: Stepladder / Lower Bracket style
      if (match.teams.length === 3) {
        const m0 = {
          id: 0,
          label: 'ELIMINATION',
          mode: 'BO1',
          teamA: match.teams[0],
          teamB: match.teams[1]
        };
        const m1 = {
          id: 1,
          label: 'CHALLENGER',
          mode: 'BO1',
          teamA: getLoserTeam(0, match.teams[0], match.teams[1]),
          teamB: match.teams[2]
        };
        const m2 = {
            id: 2,
            label: 'GRAND FINAL',
            mode: 'BO3',
            teamA: getWinnerTeam(0, match.teams[0], match.teams[1]),
            teamB: getWinnerTeam(1, m1.teamA, match.teams[2])
        };
        return { 
          quarterMatches: [], 
          semiMatches: [m0, m1], 
          grandFinalMatch: m2, 
          allMatches: [m0, m1, m2], 
          hasQuarterFinals: false 
        };
      }

      // NEW: Special Logic for 5 teams: Stepladder expansion
      // Tim kalah melawan tim waiting
      if (match.teams.length === 5) {
        const m0 = {
          id: 0,
          label: 'ELIMINATION 1',
          mode: 'BO1',
          teamA: match.teams[0],
          teamB: match.teams[1]
        };
        const m1 = {
          id: 1,
          label: 'ELIMINATION 2',
          mode: 'BO1',
          teamA: getLoserTeam(0, match.teams[0], match.teams[1]),
          teamB: match.teams[2]
        };
        const m2 = {
          id: 2,
          label: 'ELIMINATION 3',
          mode: 'BO1',
          teamA: getLoserTeam(1, m1.teamA, match.teams[2]),
          teamB: match.teams[3]
        };
        const m3 = {
          id: 3,
          label: 'CHALLENGER',
          mode: 'BO1',
          teamA: getLoserTeam(2, m2.teamA, match.teams[3]),
          teamB: match.teams[4]
        };
        const m4 = {
            id: 4,
            label: 'GRAND FINAL',
            mode: 'BO3',
            teamA: getWinnerTeam(0, match.teams[0], match.teams[1]), // Winner of first match is first finalist
            teamB: getWinnerTeam(3, m3.teamA, match.teams[4]) // Final survivor is second finalist
        };
        return { 
          quarterMatches: [], 
          semiMatches: [m0, m1, m2, m3], 
          grandFinalMatch: m4, 
          allMatches: [m0, m1, m2, m3, m4], 
          hasQuarterFinals: false 
        };
      }

      // Default logic for even/other odd counts
      const qMatches: any[] = [];
      if (hasQuarterFinals) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({
                  id: i,
                  label: `QUARTER ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      const sMatches: any[] = [];
      if (hasQuarterFinals) {
          sMatches.push({
              id: 4,
              label: 'SEMI FINAL 1',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[0].id, qMatches[0].teamA, qMatches[0].teamB),
              teamB: getWinnerTeam(qMatches[1].id, qMatches[1].teamA, qMatches[1].teamB)
          });
          sMatches.push({
              id: 5,
              label: 'SEMI FINAL 2',
              mode: 'BO1',
              teamA: getWinnerTeam(qMatches[2].id, qMatches[2].teamA, qMatches[2].teamB),
              teamB: getWinnerTeam(qMatches[3].id, qMatches[3].teamA, qMatches[3].teamB)
          });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({
                  id: i,
                  label: `SEMI FINAL ${i + 1}`,
                  mode: 'BO1',
                  teamA: match.teams[i * 2] || null,
                  teamB: match.teams[i * 2 + 1] || null
              });
          }
      }

      const gfIndex = hasQuarterFinals ? 6 : 2;
      const grandFinalMatch = {
          id: gfIndex,
          label: 'GRAND FINAL',
          mode: 'BO3',
          teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB),
          teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB)
      };

      return { 
          quarterMatches: qMatches, 
          semiMatches: sMatches, 
          grandFinalMatch, 
          allMatches: [...qMatches, ...sMatches, grandFinalMatch], 
          hasQuarterFinals 
      };
  }, [match, scores]); 

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);
    if (m && !m.teamB) {
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }
    setCurrentMatchIdx(idx);
    if (idx === grandFinalMatch.id) setPhase('TRANSITION');
    else {
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  // Fixed: Added style prop to the EnergyConnector component definition
  const EnergyConnector = ({ type, height, style }: { type: 'fork' | 'straight', height: number, style?: React.CSSProperties }) => (
    <div 
        className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" 
        style={{ height: `${height}px`, ...style }}
    >
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3" result="blur"/>
                <feComposite in="SourceGraphic" in2="blur" operator="over"/>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path 
                d={`M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          ) : (
             <path 
                d={`M 0,0 L 100,0`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          )}
          {/* Moving particles */}
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion 
                path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,0 L 100,0`} 
                dur="2s" 
                repeatCount="indefinite" 
              />
          </circle>
          {type === 'fork' && (
            <circle r="3" fill="#fff" filter="url(#energyGlow)">
                <animateMotion 
                  path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} 
                  dur="2s" 
                  begin="1s"
                  repeatCount="indefinite" 
                />
            </circle>
          )}
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;

      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';

      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-sm p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>

            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>

                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1">
                        <div className="h-[1px] flex-1 bg-white"></div>
                        <span className="text-[8px] font-black italic text-[#8a9db8]">VS</span>
                        <div className="h-[1px] flex-1 bg-white"></div>
                    </div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>

            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input 
                              type="text" 
                              value={matchRoomIds[m.id] || ''} 
                              onChange={(e) => {
                                const val = e.target.value.replace(/\D/g,'').slice(0,4);
                                setMatchRoomIds(prev => ({ ...prev, [m.id]: val }));
                              }} 
                              className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" 
                              placeholder="----"
                            />
                        </div>
                        {!isDone && m.teamA && m.teamB && (
                            <Button 
                              onClick={() => startMatchFlow(m.id)} 
                              disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} 
                              size="sm" 
                              className="h-[28px] text-[8px] px-3"
                            >
                              START
                            </Button>
                        )}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const handleNextReveal = () => {
    if (!activeMatchData) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    const crimsonId = `m${currentMatchIdx}-B-${role}`;

    // Choose team to reveal
    let side: 'azure' | 'crimson' = 'azure';
    if (revealedSlots.has(azureId)) {
        side = 'crimson';
    }

    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    const winner = teamData?.slots.find((s:TeamSlot) => s.role === role)?.player;
    if (!winner) return;

    // Filter candidates just like MatchDisplay
    const revealedPlayerIds = new Set<string>();
    activeMatchData.teamA?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-A-${s.role}`)) revealedPlayerIds.add(s.player.id); });
    activeMatchData.teamB?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-B-${s.role}`)) revealedPlayerIds.add(s.player.id); });

    const candidates = activePlayers.filter(p => {
        if (revealedPlayerIds.has(p.id)) return false;
        return p.isAllRoles || p.roles.includes(role);
    });

    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);

    const randomDuration = Math.floor(Math.random() * (9000 - 4500 + 1)) + 4500;

    setWheelState({
        isOpen: true,
        type: 'reveal',
        team: side,
        role: role,
        winnerName: winner.name,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleSkipAll = () => {
    const allCards = new Set<string>();
    ROLES_ORDER.forEach(r => { 
        allCards.add(`m${currentMatchIdx}-A-${r}`); 
        allCards.add(`m${currentMatchIdx}-B-${r}`); 
    });
    setRevealedSlots(allCards);
    setCurrentRoleIdx(ROLES_ORDER.length - 1);
  };

  const handleRerollClick = (side: 'azure' | 'crimson', role: Role) => {
    const teamData = side === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    if (!teamData) return;

    // Find original team index in match.teams to call parent onReroll
    const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
    if (originalTeamIndex === -1) return;

    const azureIds = new Set(activeMatchData?.teamA?.slots.map(s => s.player.id));
    const crimsonIds = new Set(activeMatchData?.teamB?.slots.map(s => s.player.id));

    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));
    if (benchPlayers.length === 0) return;

    const candidates = benchPlayers.filter(p => p.isAllRoles || p.roles.includes(role));
    if (candidates.length === 0) return;

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const candidateNames = candidates.map(p => p.name);

    // Use wheel for reroll as well
    const randomDuration = Math.floor(Math.random() * (8000 - 4000 + 1)) + 4000;
    setWheelState({
        isOpen: true,
        type: 'reroll',
        team: side,
        role: role,
        winnerName: newPlayer.name,
        winnerPlayer: newPlayer,
        candidates: candidateNames,
        duration: randomDuration
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
        const { team, role } = wheelState;
        const id = `m${currentMatchIdx}-${team === 'azure' ? 'A' : 'B'}-${role}`;
        setRevealedSlots(prev => new Set(prev).add(id));
        if (team === 'crimson') setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        const teamData = wheelState.team === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
        if (teamData) {
            const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
            if (originalTeamIndex !== -1) {
                onReroll(originalTeamIndex, wheelState.role, wheelState.winnerPlayer);
            }
        }
    }
    setWheelState(null);
  };

  const renderPlayerCard = (role: Role, teamSide: 'azure' | 'crimson') => {
    const teamData = teamSide === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    const slot = teamData?.slots.find(s => s.role === role);
    const id = `m${currentMatchIdx}-${teamSide === 'azure' ? 'A' : 'B'}-${role}`;
    const isRevealed = revealedSlots.has(id);

    if (!isRevealed) {
       return (
         <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group">
            <div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">
               {RoleIcons[role]}
            </div>
         </div>
       );
    }

    const theme = teamSide === 'azure' ? 
      { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' } : 
      { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#ef4444]/20 to-transparent' };

    return (
      <div className="relative h-16 w-full animate-slide-in perspective-container group">
        <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
           <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
             <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${teamSide === 'crimson' ? 'right' : 'left'} opacity-90`}>
                {RoleIcons[role]}
             </div>
             <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">
                {slot?.player.name}
             </span>
             <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
           </div>
           <button 
             onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role); }} 
             className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${teamSide === 'azure' ? 'right-4' : 'left-4'}`}
           >
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
               <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
             </svg>
           </button>
        </div>
      </div>
    );
  };

  if (phase === 'TOURNAMENT_END') {
      return (
        <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
            <div className="god-rays opacity-20"></div>
            <h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">GRAND FINAL WINNER</h3>
            <h1 className="text-4xl md:text-7xl font-cinzel font-black text-white mb-8 tracking-widest">TOURNAMENT CHAMPION</h1>
            <div className="bg-[#0a1a2f] border-4 border-[#dcb06b] px-16 py-8 clip-corner-md shadow-[0_0_60px_rgba(220,176,107,0.4)]">
                <h2 className="text-5xl md:text-7xl font-black font-cinzel text-white" style={{ color: tournamentChampion?.color || '#fff' }}>{tournamentChampion?.name}</h2>
            </div>
            <Button onClick={onReset} size="lg" className="mt-16 px-16">RETURN TO LOBBY</Button>
        </div>
      );
  }

  if (phase === 'TRANSITION' && activeMatchData) {
      return (
        <PortalTransition 
            azureTeam={activeMatchData.teamA?.slots || []} 
            crimsonTeam={activeMatchData.teamB?.slots || []} 
            onComplete={() => setPhase('DECLARE_WIN')} 
        />
      );
  }

  if (phase === 'DECLARE_WIN' && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <MatchSummary match={matchObj} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  }

  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) {
      const slots = currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots;
      return <VictoryCelebration winner={currentRoundWinner} teamSlots={slots || []} onDismiss={() => setPhase('EVALUATION')} />;
  }

  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) {
      const matchObj = { 
        roomId: activeRoomId, 
        azureTeam: activeMatchData.teamA?.slots || [], 
        crimsonTeam: activeMatchData.teamB?.slots || [], 
        isCoachMode: false, 
        timestamp: Date.now() 
      };
      return <EvaluationScreen match={matchObj} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;
  }

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>

      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16">
             <h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1>
             <p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p>
          </div>

          <div className="flex gap-24 md:gap-40 items-center justify-center relative py-20">
            {hasQuarterFinals && (
                <div className="flex flex-col gap-16 relative">
                    {quarterMatches.map((m, i) => (
                        <div key={m.id} className="relative">
                            {renderBracketMatchCard(m)}
                            {i % 2 === 0 && <EnergyConnector type="fork" height={274} />}
                        </div>
                    ))}
                </div>
            )}

            <div className={`flex flex-col ${hasQuarterFinals ? 'gap-72' : (match.teams.length === 5 ? 'gap-12' : 'gap-32')} relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {match.teams.length === 3 && i === 0 && <EnergyConnector type="fork" height={338} />}
                  {match.teams.length === 5 && i === 3 && <EnergyConnector type="fork" height={550} style={{ transform: 'translateY(-420px)' }} />}
                  {hasQuarterFinals && i % 2 === 0 && <EnergyConnector type="fork" height={498} />}
                </div>
              ))}
            </div>

            <div className={`relative scale-125 ml-10 ${match.teams.length === 5 ? 'translate-y-[-100px]' : ''}`}>
                {renderBracketMatchCard(grandFinalMatch)}
            </div>
          </div>

          <button onClick={onReset} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        /* REVEAL PHASE UI */
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState && wheelState.isOpen && (
                <SpinWheel 
                  candidates={wheelState.candidates} 
                  winnerName={wheelState.winnerName} 
                  team={wheelState.team} 
                  roleName={wheelState.role} 
                  roomId={activeRoomId} 
                  duration={wheelState.duration} 
                  onComplete={handleWheelComplete} 
                  onCancel={() => setWheelState(null)} 
                />
            )}

            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center">
                <Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">
                    BACK TO BRACKET
                </Button>

                {/* ROOM ID CENTERED IN TOP BAR */}
                <div className="flex flex-col items-center gap-0 scale-[0.85] origin-top">
                    <span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.5em] font-black uppercase mb-1 opacity-70">ROOM ID</span>
                    <div className="relative">
                        <div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div>
                        <div className="relative bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]">
                            <span className="text-2xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b]">
                            {activeRoomId}
                            </span>
                        </div>
                    </div>
                </div>

                {revealedSlots.size < 10 ? (
                    <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">
                        SKIP ALL
                    </Button>
                ) : (
                    <div className="w-[120px]"></div> 
                )}
            </div>

            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                {/* TEAM TITLES */}
                <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6">
                    <div className="text-left">
                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-cyan-600 tracking-widest drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]" style={{ color: activeMatchData?.teamA?.color }}>
                            {activeMatchData?.teamA?.name.split(' ')[0]} <span className="hidden md:inline">{activeMatchData?.teamA?.name.split(' ')[1] || 'GOLEM'}</span>
                        </h2>
                        <div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div>
                    </div>
                    <div className="text-right">
                        <h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-100 to-red-600 tracking-widest drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]" style={{ color: activeMatchData?.teamB?.color }}>
                            <span className="hidden md:inline">{activeMatchData?.teamB?.name.split(' ')[0] || 'CRIMSON'}</span> {activeMatchData?.teamB?.name.split(' ')[1] || 'GOLEM'}
                        </h2>
                        <div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div>
                    </div>
                </div>

                {/* VS INDICATOR FLOATING BEHIND GRID */}
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20">
                    <span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span>
                </div>

                {/* PLAYER CARDS */}
                <div className="space-y-4 relative z-10">
                    {ROLES_ORDER.map((role) => (
                        <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center">
                            <div>{renderPlayerCard(role, 'azure')}</div>
                            <div>{renderPlayerCard(role, 'crimson')}</div>
                        </div>
                    ))}
                </div>
            </div>

            <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none">
                <div className="pointer-events-auto">
                    {revealedSlots.size < 10 ? (
                        <button 
                            onClick={handleNextReveal} 
                            className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]"
                        >
                            {revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? 
                                `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : 
                                `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`
                            }
                        </button>
                    ) : (
                        <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">
                            INITIALIZE BATTLE
                        </Button>
                    )}
                </div>
            </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // --- MEMOIZED BRACKET GENERATION ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const getLoserTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA || !teamB) return null;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > 0 || scoreB > 0) {
            if (scoreA < scoreB) return teamA;
            if (scoreB < scoreA) return teamB;
        }
        return null;
      };

      const hasQuarterFinals = match.teams.length > 7; 

      // Logic for 3 teams (Stepladder)
      if (match.teams.length === 3) {
        const m0 = { id: 0, label: 'ELIMINATION', mode: 'BO1', teamA: match.teams[0], teamB: match.teams[1] };
        const m1 = { id: 1, label: 'CHALLENGER', mode: 'BO1', teamA: getLoserTeam(0, match.teams[0], match.teams[1]), teamB: match.teams[2] };
        const m2 = { id: 2, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, match.teams[0], match.teams[1]), teamB: getWinnerTeam(1, m1.teamA, match.teams[2]) };
        return { quarterMatches: [], semiMatches: [m0, m1], grandFinalMatch: m2, allMatches: [m0, m1, m2], hasQuarterFinals: false };
      }

      // Logic for 5 teams (Stepladder)
      if (match.teams.length === 5) {
        const m0 = { id: 0, label: 'ELIMINATION 1', mode: 'BO1', teamA: match.teams[0], teamB: match.teams[1] };
        const m1 = { id: 1, label: 'ELIMINATION 2', mode: 'BO1', teamA: getLoserTeam(0, match.teams[0], match.teams[1]), teamB: match.teams[2] };
        const m2 = { id: 2, label: 'ELIMINATION 3', mode: 'BO1', teamA: getLoserTeam(1, m1.teamA, match.teams[2]), teamB: match.teams[3] };
        const m3 = { id: 3, label: 'CHALLENGER', mode: 'BO1', teamA: getLoserTeam(2, m2.teamA, match.teams[3]), teamB: match.teams[4] };
        const m4 = { id: 4, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, match.teams[0], match.teams[1]), teamB: getWinnerTeam(3, m3.teamA, match.teams[4]) };
        return { quarterMatches: [], semiMatches: [m0, m1, m2, m3], grandFinalMatch: m4, allMatches: [m0, m1, m2, m3, m4], hasQuarterFinals: false };
      }

      // NEW: Logic for 7 teams (Stepladder Gauntlet)
      if (match.teams.length === 7) {
        const m0 = { id: 0, label: 'ELIMINATION 1', mode: 'BO1', teamA: match.teams[0], teamB: match.teams[1] };
        const m1 = { id: 1, label: 'ELIMINATION 2', mode: 'BO1', teamA: getLoserTeam(0, match.teams[0], match.teams[1]), teamB: match.teams[2] };
        const m2 = { id: 2, label: 'ELIMINATION 3', mode: 'BO1', teamA: getLoserTeam(1, m1.teamA, match.teams[2]), teamB: match.teams[3] };
        const m3 = { id: 3, label: 'ELIMINATION 4', mode: 'BO1', teamA: getLoserTeam(2, m2.teamA, match.teams[3]), teamB: match.teams[4] };
        const m4 = { id: 4, label: 'ELIMINATION 5', mode: 'BO1', teamA: getLoserTeam(3, m3.teamA, match.teams[4]), teamB: match.teams[5] };
        const m5 = { id: 5, label: 'CHALLENGER', mode: 'BO1', teamA: getLoserTeam(4, m4.teamA, match.teams[5]), teamB: match.teams[6] };
        const m6 = { id: 6, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, match.teams[0], match.teams[1]), teamB: getWinnerTeam(5, m5.teamA, match.teams[6]) };
        return { quarterMatches: [], semiMatches: [m0, m1, m2, m3, m4, m5], grandFinalMatch: m6, allMatches: [m0, m1, m2, m3, m4, m5, m6], hasQuarterFinals: false };
      }

      // Default logic for even/other counts
      const qMatches: any[] = [];
      if (hasQuarterFinals) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({ id: i, label: `QUARTER ${i + 1}`, mode: 'BO1', teamA: match.teams[i * 2] || null, teamB: match.teams[i * 2 + 1] || null });
          }
      }

      const sMatches: any[] = [];
      if (hasQuarterFinals) {
          sMatches.push({ id: 4, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(qMatches[0].id, qMatches[0].teamA, qMatches[0].teamB), teamB: getWinnerTeam(qMatches[1].id, qMatches[1].teamA, qMatches[1].teamB) });
          sMatches.push({ id: 5, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(qMatches[2].id, qMatches[2].teamA, qMatches[2].teamB), teamB: getWinnerTeam(qMatches[3].id, qMatches[3].teamA, qMatches[3].teamB) });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({ id: i, label: `SEMI FINAL ${i + 1}`, mode: 'BO1', teamA: match.teams[i * 2] || null, teamB: match.teams[i * 2 + 1] || null });
          }
      }

      const gfIndex = hasQuarterFinals ? 6 : 2;
      const grandFinalMatch = { id: gfIndex, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB), teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB) };
      return { quarterMatches: qMatches, semiMatches: sMatches, grandFinalMatch, allMatches: [...qMatches, ...sMatches, grandFinalMatch], hasQuarterFinals };
  }, [match, scores]); 

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);
    if (m && !m.teamB) {
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }
    setCurrentMatchIdx(idx);
    if (idx === grandFinalMatch.id) setPhase('TRANSITION');
    else {
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const EnergyConnector = ({ type, height, style }: { type: 'fork' | 'straight', height: number, style?: React.CSSProperties }) => (
    <div 
        className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" 
        style={{ height: `${height}px`, ...style }}
    >
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3" result="blur"/>
                <feComposite in="SourceGraphic" in2="blur" operator="over"/>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path 
                d={`M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          ) : (
             <path 
                d={`M 0,0 L 100,0`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          )}
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,0 L 100,0`} dur="2s" repeatCount="indefinite" />
          </circle>
          {type === 'fork' && (
            <circle r="3" fill="#fff" filter="url(#energyGlow)">
                <animateMotion path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} dur="2s" begin="1s" repeatCount="indefinite" />
            </circle>
          )}
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;
      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';
      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-sm p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>
            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>
                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1"><div className="h-[1px] flex-1 bg-white"></div><span className="text-[8px] font-black italic text-[#8a9db8]">VS</span><div className="h-[1px] flex-1 bg-white"></div></div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>
            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input type="text" value={matchRoomIds[m.id] || ''} onChange={(e) => { const val = e.target.value.replace(/\D/g,'').slice(0,4); setMatchRoomIds(prev => ({ ...prev, [m.id]: val })); }} className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" placeholder="----" />
                        </div>
                        {!isDone && m.teamA && m.teamB && <Button onClick={() => startMatchFlow(m.id)} disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} size="sm" className="h-[28px] text-[8px] px-3">START</Button>}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const handleNextReveal = () => {
    if (!activeMatchData) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;
    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    const side = revealedSlots.has(azureId) ? 'crimson' : 'azure';
    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    const winner = teamData?.slots.find((s:TeamSlot) => s.role === role)?.player;
    if (!winner) return;
    const revealedPlayerIds = new Set<string>();
    activeMatchData.teamA?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-A-${s.role}`)) revealedPlayerIds.add(s.player.id); });
    activeMatchData.teamB?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-B-${s.role}`)) revealedPlayerIds.add(s.player.id); });
    const candidates = activePlayers.filter(p => !revealedPlayerIds.has(p.id) && (p.isAllRoles || p.roles.includes(role)));
    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);
    const randomDuration = Math.floor(Math.random() * (9000 - 4500 + 1)) + 4500;
    setWheelState({ isOpen: true, type: 'reveal', team: side, role: role, winnerName: winner.name, candidates: candidateNames, duration: randomDuration });
  };

  const handleSkipAll = () => {
    const allCards = new Set<string>();
    ROLES_ORDER.forEach(r => { allCards.add(`m${currentMatchIdx}-A-${r}`); allCards.add(`m${currentMatchIdx}-B-${r}`); });
    setRevealedSlots(allCards);
    setCurrentRoleIdx(ROLES_ORDER.length - 1);
  };

  const handleRerollClick = (side: 'azure' | 'crimson', role: Role) => {
    const teamData = side === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    if (!teamData) return;
    const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
    if (originalTeamIndex === -1) return;
    const azureIds = new Set(activeMatchData?.teamA?.slots.map(s => s.player.id));
    const crimsonIds = new Set(activeMatchData?.teamB?.slots.map(s => s.player.id));
    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));
    if (benchPlayers.length === 0) return;
    const candidates = benchPlayers.filter(p => p.isAllRoles || p.roles.includes(role));
    if (candidates.length === 0) return;
    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const randomDuration = Math.floor(Math.random() * (8000 - 4000 + 1)) + 4000;
    setWheelState({ isOpen: true, type: 'reroll', team: side, role: role, winnerName: newPlayer.name, winnerPlayer: newPlayer, candidates: candidates.map(p => p.name), duration: randomDuration });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
        const { team, role } = wheelState;
        const id = `m${currentMatchIdx}-${team === 'azure' ? 'A' : 'B'}-${role}`;
        setRevealedSlots(prev => new Set(prev).add(id));
        if (team === 'crimson') setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        const teamData = wheelState.team === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
        if (teamData) {
            const idx = match.teams.findIndex(t => t.name === teamData.name);
            if (idx !== -1) onReroll(idx, wheelState.role, wheelState.winnerPlayer);
        }
    }
    setWheelState(null);
  };

  const renderPlayerCard = (role: Role, teamSide: 'azure' | 'crimson') => {
    const teamData = teamSide === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    const slot = teamData?.slots.find(s => s.role === role);
    const id = `m${currentMatchIdx}-${teamSide === 'azure' ? 'A' : 'B'}-${role}`;
    if (!revealedSlots.has(id)) return <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group"><div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">{RoleIcons[role]}</div></div>;
    const theme = teamSide === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' } : { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#ef4444]/20 to-transparent' };
    return <div className="relative h-16 w-full animate-slide-in perspective-container group"><div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}><div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}><div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${teamSide === 'crimson' ? 'right' : 'left'} opacity-90`}>{RoleIcons[role]}</div><span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">{slot?.player.name}</span><div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div></div><button onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role); }} className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${teamSide === 'azure' ? 'right-4' : 'left-4'}`}><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button></div></div>;
  };

  if (phase === 'TOURNAMENT_END') return <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden"><div className="god-rays opacity-20"></div><h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">GRAND FINAL WINNER</h3><h1 className="text-4xl md:text-7xl font-cinzel font-black text-white mb-8 tracking-widest">TOURNAMENT CHAMPION</h1><div className="bg-[#0a1a2f] border-4 border-[#dcb06b] px-16 py-8 clip-corner-md shadow-[0_0_60px_rgba(220,176,107,0.4)]"><h2 className="text-5xl md:text-7xl font-black font-cinzel text-white" style={{ color: tournamentChampion?.color || '#fff' }}>{tournamentChampion?.name}</h2></div><Button onClick={onReset} size="lg" className="mt-16 px-16">RETURN TO LOBBY</Button></div>;
  if (phase === 'TRANSITION' && activeMatchData) return <PortalTransition azureTeam={activeMatchData.teamA?.slots || []} crimsonTeam={activeMatchData.teamB?.slots || []} onComplete={() => setPhase('DECLARE_WIN')} />;
  if (phase === 'DECLARE_WIN' && activeMatchData) return <MatchSummary match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) return <VictoryCelebration winner={currentRoundWinner} teamSlots={(currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots) || []} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) return <EvaluationScreen match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>
      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16"><h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1><p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p></div>
          <div className="flex gap-24 md:gap-40 items-center justify-center relative py-20">
            {hasQuarterFinals && <div className="flex flex-col gap-16 relative">{quarterMatches.map((m, i) => <div key={m.id} className="relative">{renderBracketMatchCard(m)}{i % 2 === 0 && <EnergyConnector type="fork" height={274} />}</div>)}</div>}
            <div className={`flex flex-col ${match.teams.length === 7 ? 'gap-6' : (match.teams.length === 5 ? 'gap-12' : 'gap-32')} relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {match.teams.length === 3 && i === 0 && <EnergyConnector type="fork" height={338} />}
                  {match.teams.length === 5 && i === 3 && <EnergyConnector type="fork" height={550} style={{ transform: 'translateY(-420px)' }} />}
                  {match.teams.length === 7 && i === 5 && <EnergyConnector type="fork" height={770} style={{ transform: 'translateY(-645px)' }} />}
                  {hasQuarterFinals && i % 2 === 0 && <EnergyConnector type="fork" height={498} />}
                </div>
              ))}
            </div>
            <div className={`relative scale-125 ml-10 ${match.teams.length === 7 ? 'translate-y-[-215px]' : (match.teams.length === 5 ? 'translate-y-[-100px]' : '')}`}>{renderBracketMatchCard(grandFinalMatch)}</div>
          </div>
          <button onClick={onReset} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState && wheelState.isOpen && <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} team={wheelState.team} roleName={wheelState.role} roomId={activeRoomId} duration={wheelState.duration} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}
            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center"><Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">BACK TO BRACKET</Button><div className="flex flex-col items-center gap-0 scale-[0.85] origin-top"><span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.5em] font-black uppercase mb-1 opacity-70">ROOM ID</span><div className="relative"><div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div><div className="relative bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]"><span className="text-2xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b]">{activeRoomId}</span></div></div></div>{revealedSlots.size < 10 ? <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">SKIP ALL</Button> : <div className="w-[120px]"></div>}</div>
            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6"><div className="text-left"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-cyan-600 tracking-widest drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]" style={{ color: activeMatchData?.teamA?.color }}>{activeMatchData?.teamA?.name.split(' ')[0]} <span className="hidden md:inline">{activeMatchData?.teamA?.name.split(' ')[1] || 'GOLEM'}</span></h2><div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div></div><div className="text-right"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-100 to-red-600 tracking-widest drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]" style={{ color: activeMatchData?.teamB?.color }}><span className="hidden md:inline">{activeMatchData?.teamB?.name.split(' ')[0] || 'CRIMSON'}</span> {activeMatchData?.teamB?.name.split(' ')[1] || 'GOLEM'}</h2><div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div></div></div>
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20"><span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span></div>
                <div className="space-y-4 relative z-10">{ROLES_ORDER.map((role) => <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center"><div>{renderPlayerCard(role, 'azure')}</div><div>{renderPlayerCard(role, 'crimson')}</div></div>)}</div>
            </div>
            <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none"><div className="pointer-events-auto">{revealedSlots.size < 10 ? <button onClick={handleNextReveal} className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]">{revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`}</button> : <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">INITIALIZE BATTLE</Button>}</div></div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // --- MEMOIZED BRACKET GENERATION ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const getLoserTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA || !teamB) return null;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > 0 || scoreB > 0) {
            if (scoreA < scoreB) return teamA;
            if (scoreB < scoreA) return teamB;
        }
        return null;
      };

      const hasQuarterFinals = match.teams.length > 7; 

      // Logic for 3 teams (Stepladder)
      if (match.teams.length === 3) {
        const m0 = { id: 0, label: 'ELIMINATION', mode: 'BO1', teamA: match.teams[0], teamB: match.teams[1] };
        const m1 = { id: 1, label: 'CHALLENGER', mode: 'BO1', teamA: getLoserTeam(0, match.teams[0], match.teams[1]), teamB: match.teams[2] };
        const m2 = { id: 2, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, match.teams[0], match.teams[1]), teamB: getWinnerTeam(1, m1.teamA, match.teams[2]) };
        return { quarterMatches: [], semiMatches: [m0, m1], grandFinalMatch: m2, allMatches: [m0, m1, m2], hasQuarterFinals: false };
      }

      // NEW Logic for 5 teams (Following 3-team Survivor pattern)
      if (match.teams.length === 5) {
        const m0 = { id: 0, label: 'ELIMINATION 1', mode: 'BO1', teamA: match.teams[0], teamB: match.teams[1] };
        // Tim kalah M0 melawan Team 2
        const m1 = { id: 1, label: 'ELIMINATION 2', mode: 'BO1', teamA: getLoserTeam(0, match.teams[0], match.teams[1]), teamB: match.teams[2] };
        // Pemenang M1 (Survivor) melawan Team 3
        const m2 = { id: 2, label: 'ELIMINATION 3', mode: 'BO1', teamA: getWinnerTeam(1, m1.teamA, match.teams[2]), teamB: match.teams[3] };
        // Pemenang M2 (Survivor) melawan Team 4 (Challenger)
        const m3 = { id: 3, label: 'CHALLENGER', mode: 'BO1', teamA: getWinnerTeam(2, m2.teamA, match.teams[3]), teamB: match.teams[4] };
        // Final: Pemenang M0 melawan Pemenang M3
        const m4 = { id: 4, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, match.teams[0], match.teams[1]), teamB: getWinnerTeam(3, m3.teamA, match.teams[4]) };
        return { quarterMatches: [], semiMatches: [m0, m1, m2, m3], grandFinalMatch: m4, allMatches: [m0, m1, m2, m3, m4], hasQuarterFinals: false };
      }

      // NEW Logic for 7 teams (Following 3-team Survivor pattern)
      if (match.teams.length === 7) {
        const m0 = { id: 0, label: 'ELIMINATION 1', mode: 'BO1', teamA: match.teams[0], teamB: match.teams[1] };
        const m1 = { id: 1, label: 'ELIMINATION 2', mode: 'BO1', teamA: getLoserTeam(0, match.teams[0], match.teams[1]), teamB: match.teams[2] };
        const m2 = { id: 2, label: 'ELIMINATION 3', mode: 'BO1', teamA: getWinnerTeam(1, m1.teamA, match.teams[2]), teamB: match.teams[3] };
        const m3 = { id: 3, label: 'ELIMINATION 4', mode: 'BO1', teamA: getWinnerTeam(2, m2.teamA, match.teams[3]), teamB: match.teams[4] };
        const m4 = { id: 4, label: 'ELIMINATION 5', mode: 'BO1', teamA: getWinnerTeam(3, m3.teamA, match.teams[4]), teamB: match.teams[5] };
        const m5 = { id: 5, label: 'CHALLENGER', mode: 'BO1', teamA: getWinnerTeam(4, m4.teamA, match.teams[5]), teamB: match.teams[6] };
        const m6 = { id: 6, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, match.teams[0], match.teams[1]), teamB: getWinnerTeam(5, m5.teamA, match.teams[6]) };
        return { quarterMatches: [], semiMatches: [m0, m1, m2, m3, m4, m5], grandFinalMatch: m6, allMatches: [m0, m1, m2, m3, m4, m5, m6], hasQuarterFinals: false };
      }

      // Default logic for even/other counts
      const qMatches: any[] = [];
      if (hasQuarterFinals) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({ id: i, label: `QUARTER ${i + 1}`, mode: 'BO1', teamA: match.teams[i * 2] || null, teamB: match.teams[i * 2 + 1] || null });
          }
      }

      const sMatches: any[] = [];
      if (hasQuarterFinals) {
          sMatches.push({ id: 4, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(qMatches[0].id, qMatches[0].teamA, qMatches[0].teamB), teamB: getWinnerTeam(qMatches[1].id, qMatches[1].teamA, qMatches[1].teamB) });
          sMatches.push({ id: 5, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(qMatches[2].id, qMatches[2].teamA, qMatches[2].teamB), teamB: getWinnerTeam(qMatches[3].id, qMatches[3].teamA, qMatches[3].teamB) });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({ id: i, label: `SEMI FINAL ${i + 1}`, mode: 'BO1', teamA: match.teams[i * 2] || null, teamB: match.teams[i * 2 + 1] || null });
          }
      }

      const gfIndex = hasQuarterFinals ? 6 : 2;
      const grandFinalMatch = { id: gfIndex, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB), teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB) };
      return { quarterMatches: qMatches, semiMatches: sMatches, grandFinalMatch, allMatches: [...qMatches, ...sMatches, grandFinalMatch], hasQuarterFinals };
  }, [match, scores]); 

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);
    if (m && !m.teamB) {
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }
    setCurrentMatchIdx(idx);
    if (idx === grandFinalMatch.id) setPhase('TRANSITION');
    else {
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const EnergyConnector = ({ type, height, style }: { type: 'fork' | 'straight', height: number, style?: React.CSSProperties }) => (
    <div 
        className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" 
        style={{ height: `${height}px`, ...style }}
    >
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3" result="blur"/>
                <feComposite in="SourceGraphic" in2="blur" operator="over"/>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path 
                d={`M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          ) : (
             <path 
                d={`M 0,0 L 100,0`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          )}
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,0 L 100,0`} dur="2s" repeatCount="indefinite" />
          </circle>
          {type === 'fork' && (
            <circle r="3" fill="#fff" filter="url(#energyGlow)">
                <animateMotion path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} dur="2s" begin="1s" repeatCount="indefinite" />
            </circle>
          )}
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;
      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';
      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-md p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>
            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>
                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1"><div className="h-[1px] flex-1 bg-white"></div><span className="text-[8px] font-black italic text-[#8a9db8]">VS</span><div className="h-[1px] flex-1 bg-white"></div></div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>
            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input type="text" value={matchRoomIds[m.id] || ''} onChange={(e) => { const val = e.target.value.replace(/\D/g,'').slice(0,4); setMatchRoomIds(prev => ({ ...prev, [m.id]: val })); }} className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" placeholder="----" />
                        </div>
                        {!isDone && m.teamA && m.teamB && <Button onClick={() => startMatchFlow(m.id)} disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} size="sm" className="h-[28px] text-[8px] px-3">START</Button>}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const handleNextReveal = () => {
    if (!activeMatchData) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;
    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    const side = revealedSlots.has(azureId) ? 'crimson' : 'azure';
    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    const winner = teamData?.slots.find((s:TeamSlot) => s.role === role)?.player;
    if (!winner) return;
    const revealedPlayerIds = new Set<string>();
    activeMatchData.teamA?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-A-${s.role}`)) revealedPlayerIds.add(s.player.id); });
    activeMatchData.teamB?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-B-${s.role}`)) revealedPlayerIds.add(s.player.id); });
    const candidates = activePlayers.filter(p => !revealedPlayerIds.has(p.id) && (p.isAllRoles || p.roles.includes(role)));
    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);
    const randomDuration = Math.floor(Math.random() * (9000 - 4500 + 1)) + 4500;
    setWheelState({ isOpen: true, type: 'reveal', team: side, role: role, winnerName: winner.name, candidates: candidateNames, duration: randomDuration });
  };

  const handleSkipAll = () => {
    const allCards = new Set<string>();
    ROLES_ORDER.forEach(r => { allCards.add(`m${currentMatchIdx}-A-${r}`); allCards.add(`m${currentMatchIdx}-B-${r}`); });
    setRevealedSlots(allCards);
    setCurrentRoleIdx(ROLES_ORDER.length - 1);
  };

  const handleRerollClick = (side: 'azure' | 'crimson', role: Role) => {
    const teamData = side === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    if (!teamData) return;
    const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
    if (originalTeamIndex === -1) return;
    const azureIds = new Set(activeMatchData?.teamA?.slots.map(s => s.player.id));
    const crimsonIds = new Set(activeMatchData?.teamB?.slots.map(s => s.player.id));
    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));
    if (benchPlayers.length === 0) return;
    const candidates = benchPlayers.filter(p => p.isAllRoles || p.roles.includes(role));
    if (candidates.length === 0) return;
    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const randomDuration = Math.floor(Math.random() * (8000 - 4000 + 1)) + 4000;
    setWheelState({ isOpen: true, type: 'reroll', team: side, role: role, winnerName: newPlayer.name, winnerPlayer: newPlayer, candidates: candidates.map(p => p.name), duration: randomDuration });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
        const { team, role } = wheelState;
        const id = `m${currentMatchIdx}-${team === 'azure' ? 'A' : 'B'}-${role}`;
        setRevealedSlots(prev => new Set(prev).add(id));
        if (team === 'crimson') setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        const teamData = wheelState.team === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
        if (teamData) {
            const idx = match.teams.findIndex(t => t.name === teamData.name);
            if (idx !== -1) onReroll(idx, wheelState.role, wheelState.winnerPlayer);
        }
    }
    setWheelState(null);
  };

  const renderPlayerCard = (role: Role, teamSide: 'azure' | 'crimson') => {
    const teamData = teamSide === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    const slot = teamData?.slots.find(s => s.role === role);
    const id = `m${currentMatchIdx}-${teamSide === 'azure' ? 'A' : 'B'}-${role}`;
    if (!revealedSlots.has(id)) return <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group"><div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">{RoleIcons[role]}</div></div>;
    const theme = teamSide === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' } : { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#ef4444]/20 to-transparent' };
    return <div className="relative h-16 w-full animate-slide-in perspective-container group"><div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}><div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}><div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${teamSide === 'crimson' ? 'right' : 'left'} opacity-90`}>{RoleIcons[role]}</div><span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">{slot?.player.name}</span><div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div></div><button onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role); }} className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${teamSide === 'azure' ? 'right-4' : 'left-4'}`}><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button></div></div>;
  };

  if (phase === 'TOURNAMENT_END') return <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden"><div className="god-rays opacity-20"></div><h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">GRAND FINAL WINNER</h3><h1 className="text-4xl md:text-7xl font-cinzel font-black text-white mb-8 tracking-widest">TOURNAMENT CHAMPION</h1><div className="bg-[#0a1a2f] border-4 border-[#dcb06b] px-16 py-8 clip-corner-md shadow-[0_0_60px_rgba(220,176,107,0.4)]"><h2 className="text-5xl md:text-7xl font-black font-cinzel text-white" style={{ color: tournamentChampion?.color || '#fff' }}>{tournamentChampion?.name}</h2></div><Button onClick={onReset} size="lg" className="mt-16 px-16">RETURN TO LOBBY</Button></div>;
  if (phase === 'TRANSITION' && activeMatchData) return <PortalTransition azureTeam={activeMatchData.teamA?.slots || []} crimsonTeam={activeMatchData.teamB?.slots || []} onComplete={() => setPhase('DECLARE_WIN')} />;
  if (phase === 'DECLARE_WIN' && activeMatchData) return <MatchSummary match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) return <VictoryCelebration winner={currentRoundWinner} teamSlots={(currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots) || []} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) return <EvaluationScreen match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>
      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16"><h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1><p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p></div>
          <div className="flex gap-24 md:gap-40 items-center justify-center relative py-20">
            {hasQuarterFinals && <div className="flex flex-col gap-16 relative">{quarterMatches.map((m, i) => <div key={m.id} className="relative">{renderBracketMatchCard(m)}{i % 2 === 0 && <EnergyConnector type="fork" height={274} />}</div>)}</div>}
            <div className={`flex flex-col ${match.teams.length === 7 ? 'gap-6' : (match.teams.length === 5 ? 'gap-12' : 'gap-32')} relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {match.teams.length === 3 && i === 0 && <EnergyConnector type="fork" height={338} />}
                  {match.teams.length === 5 && i === 3 && <EnergyConnector type="fork" height={550} style={{ transform: 'translateY(-420px)' }} />}
                  {match.teams.length === 7 && i === 5 && <EnergyConnector type="fork" height={770} style={{ transform: 'translateY(-645px)' }} />}
                  {hasQuarterFinals && i % 2 === 0 && <EnergyConnector type="fork" height={498} />}
                </div>
              ))}
            </div>
            <div className={`relative scale-125 ml-10 ${match.teams.length === 7 ? 'translate-y-[-215px]' : (match.teams.length === 5 ? 'translate-y-[-100px]' : '')}`}>{renderBracketMatchCard(grandFinalMatch)}</div>
          </div>
          <button onClick={onReset} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState && wheelState.isOpen && <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} team={wheelState.team} roleName={wheelState.role} roomId={activeRoomId} duration={wheelState.duration} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}
            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center"><Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">BACK TO BRACKET</Button><div className="flex flex-col items-center gap-0 scale-[0.85] origin-top"><span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1 opacity-70">ROOM ID</span><div className="relative"><div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div><div className="relative bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]"><span className="text-2xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b]">{activeRoomId}</span></div></div></div>{revealedSlots.size < 10 ? <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">SKIP ALL</Button> : <div className="w-[120px]"></div>}</div>
            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6"><div className="text-left"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-cyan-600 tracking-widest drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]" style={{ color: activeMatchData?.teamA?.color }}>{activeMatchData?.teamA?.name.split(' ')[0]} <span className="hidden md:inline">{activeMatchData?.teamA?.name.split(' ')[1] || 'GOLEM'}</span></h2><div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div></div><div className="text-right"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-100 to-red-600 tracking-widest drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]" style={{ color: activeMatchData?.teamB?.color }}><span className="hidden md:inline">{activeMatchData?.teamB?.name.split(' ')[0] || 'CRIMSON'}</span> {activeMatchData?.teamB?.name.split(' ')[1] || 'GOLEM'}</h2><div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div></div></div>
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20"><span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span></div>
                <div className="space-y-4 relative z-10">{ROLES_ORDER.map((role) => <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center"><div>{renderPlayerCard(role, 'azure')}</div><div>{renderPlayerCard(role, 'crimson')}</div></div>)}</div>
            </div>
            <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none"><div className="pointer-events-auto">{revealedSlots.size < 10 ? <button onClick={handleNextReveal} className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]">{revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`}</button> : <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">INITIALIZE BATTLE</Button>}</div></div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // --- MEMOIZED BRACKET GENERATION ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const getLoserTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA || !teamB) return null;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > 0 || scoreB > 0) {
            if (scoreA < scoreB) return teamA;
            if (scoreB < scoreA) return teamB;
        }
        return null;
      };

      const hasQuarterFinals = match.teams.length > 7; 

      // Logic for 3 teams (Stepladder)
      if (match.teams.length === 3) {
        const m0 = { id: 0, label: 'ELIMINATION', mode: 'BO1', teamA: match.teams[0], teamB: match.teams[1] };
        const m1 = { id: 1, label: 'CHALLENGER', mode: 'BO1', teamA: getLoserTeam(0, match.teams[0], match.teams[1]), teamB: match.teams[2] };
        const m2 = { id: 2, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, match.teams[0], match.teams[1]), teamB: getWinnerTeam(1, m1.teamA, match.teams[2]) };
        return { quarterMatches: [], semiMatches: [m0, m1], grandFinalMatch: m2, allMatches: [m0, m1, m2], hasQuarterFinals: false };
      }

      // 5 TEAMS STEPLADDER (Sesuai mekanisme Bracket 3)
      if (match.teams.length === 5) {
        // M0: Penentuan Finalist Pertama
        const m0 = { id: 0, label: 'FINALIST SEEDING', mode: 'BO1', teamA: match.teams[0], teamB: match.teams[1] };

        // M1: Pecundang M0 melawan Tim 3 (Awal Tangga)
        const m1 = { id: 1, label: 'LOWER STAGE 1', mode: 'BO1', teamA: getLoserTeam(0, match.teams[0], match.teams[1]), teamB: match.teams[2] };

        // M2: Pemenang M1 melawan Tim 4
        const m2 = { id: 2, label: 'LOWER STAGE 2', mode: 'BO1', teamA: getWinnerTeam(1, m1.teamA, match.teams[2]), teamB: match.teams[3] };

        // M3: Pemenang M2 melawan Tim 5 (Penentuan Challenger)
        const m3 = { id: 3, label: 'CHALLENGER', mode: 'BO1', teamA: getWinnerTeam(2, m2.teamA, match.teams[3]), teamB: match.teams[4] };

        // M4: Pemenang M0 (Finalist 1) vs Pemenang M3 (Challenger)
        const m4 = { id: 4, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, match.teams[0], match.teams[1]), teamB: getWinnerTeam(3, m3.teamA, match.teams[4]) };

        return { quarterMatches: [], semiMatches: [m0, m1, m2, m3], grandFinalMatch: m4, allMatches: [m0, m1, m2, m3, m4], hasQuarterFinals: false };
      }

      // Logic for 7 teams (Following 3-team Survivor pattern)
      if (match.teams.length === 7) {
        const m0 = { id: 0, label: 'ELIMINATION 1', mode: 'BO1', teamA: match.teams[0], teamB: match.teams[1] };
        const m1 = { id: 1, label: 'ELIMINATION 2', mode: 'BO1', teamA: getLoserTeam(0, match.teams[0], match.teams[1]), teamB: match.teams[2] };
        const m2 = { id: 2, label: 'ELIMINATION 3', mode: 'BO1', teamA: getWinnerTeam(1, m1.teamA, match.teams[2]), teamB: match.teams[3] };
        const m3 = { id: 3, label: 'ELIMINATION 4', mode: 'BO1', teamA: getWinnerTeam(2, m2.teamA, match.teams[3]), teamB: match.teams[4] };
        const m4 = { id: 4, label: 'ELIMINATION 5', mode: 'BO1', teamA: getWinnerTeam(3, m3.teamA, match.teams[4]), teamB: match.teams[5] };
        const m5 = { id: 5, label: 'CHALLENGER', mode: 'BO1', teamA: getWinnerTeam(4, m4.teamA, match.teams[5]), teamB: match.teams[6] };
        const m6 = { id: 6, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, match.teams[0], match.teams[1]), teamB: getWinnerTeam(5, m5.teamA, match.teams[6]) };
        return { quarterMatches: [], semiMatches: [m0, m1, m2, m3, m4, m5], grandFinalMatch: m6, allMatches: [m0, m1, m2, m3, m4, m5, m6], hasQuarterFinals: false };
      }

      // Default logic for even/other counts
      const qMatches: any[] = [];
      if (hasQuarterFinals) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({ id: i, label: `QUARTER ${i + 1}`, mode: 'BO1', teamA: match.teams[i * 2] || null, teamB: match.teams[i * 2 + 1] || null });
          }
      }

      const sMatches: any[] = [];
      if (hasQuarterFinals) {
          sMatches.push({ id: 4, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(qMatches[0].id, qMatches[0].teamA, qMatches[0].teamB), teamB: getWinnerTeam(qMatches[1].id, qMatches[1].teamA, qMatches[1].teamB) });
          sMatches.push({ id: 5, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(qMatches[2].id, qMatches[2].teamA, qMatches[2].teamB), teamB: getWinnerTeam(qMatches[3].id, qMatches[3].teamA, qMatches[3].teamB) });
      } else {
          for (let i = 0; i < 2; i++) {
              sMatches.push({ id: i, label: `SEMI FINAL ${i + 1}`, mode: 'BO1', teamA: match.teams[i * 2] || null, teamB: match.teams[i * 2 + 1] || null });
          }
      }

      const gfIndex = hasQuarterFinals ? 6 : 2;
      const grandFinalMatch = { id: gfIndex, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB), teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB) };
      return { quarterMatches: qMatches, semiMatches: sMatches, grandFinalMatch, allMatches: [...qMatches, ...sMatches, grandFinalMatch], hasQuarterFinals };
  }, [match, scores]); 

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);
    if (m && !m.teamB) {
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }
    setCurrentMatchIdx(idx);
    if (idx === grandFinalMatch.id) setPhase('TRANSITION');
    else {
        setPhase('REVEAL');
        setRevealedSlots(new Set());
        setCurrentRoleIdx(-1);
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const EnergyConnector = ({ type, height, style }: { type: 'fork' | 'straight', height: number, style?: React.CSSProperties }) => (
    <div 
        className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" 
        style={{ height: `${height}px`, ...style }}
    >
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3" result="blur"/>
                <feComposite in="SourceGraphic" in2="blur" operator="over"/>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path 
                d={`M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          ) : (
             <path 
                d={`M 0,0 L 100,0`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          )}
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,0 L 100,0`} dur="2s" repeatCount="indefinite" />
          </circle>
          {type === 'fork' && (
            <circle r="3" fill="#fff" filter="url(#energyGlow)">
                <animateMotion path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} dur="2s" begin="1s" repeatCount="indefinite" />
            </circle>
          )}
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;
      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';
      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-md p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>
            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>
                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1"><div className="h-[1px] flex-1 bg-white"></div><span className="text-[8px] font-black italic text-[#8a9db8]">VS</span><div className="h-[1px] flex-1 bg-white"></div></div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>
            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input type="text" value={matchRoomIds[m.id] || ''} onChange={(e) => { const val = e.target.value.replace(/\D/g,'').slice(0,4); setMatchRoomIds(prev => ({ ...prev, [m.id]: val })); }} className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" placeholder="----" />
                        </div>
                        {!isDone && m.teamA && m.teamB && <Button onClick={() => startMatchFlow(m.id)} disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} size="sm" className="h-[28px] text-[8px] px-3">START</Button>}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const handleNextReveal = () => {
    if (!activeMatchData) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;
    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    const side = revealedSlots.has(azureId) ? 'crimson' : 'azure';
    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    const winner = teamData?.slots.find((s:TeamSlot) => s.role === role)?.player;
    if (!winner) return;
    const revealedPlayerIds = new Set<string>();
    activeMatchData.teamA?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-A-${s.role}`)) revealedPlayerIds.add(s.player.id); });
    activeMatchData.teamB?.slots.forEach((s: TeamSlot) => { if (revealedSlots.has(`m${currentMatchIdx}-B-${s.role}`)) revealedPlayerIds.add(s.player.id); });
    const candidates = activePlayers.filter(p => !revealedPlayerIds.has(p.id) && (p.isAllRoles || p.roles.includes(role)));
    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);
    const randomDuration = Math.floor(Math.random() * (9000 - 4500 + 1)) + 4500;
    setWheelState({ isOpen: true, type: 'reveal', team: side, role: role, winnerName: winner.name, candidates: candidateNames, duration: randomDuration });
  };

  const handleSkipAll = () => {
    const allCards = new Set<string>();
    ROLES_ORDER.forEach(r => { allCards.add(`m${currentMatchIdx}-A-${r}`); allCards.add(`m${currentMatchIdx}-B-${r}`); });
    setRevealedSlots(allCards);
    setCurrentRoleIdx(ROLES_ORDER.length - 1);
  };

  const handleRerollClick = (side: 'azure' | 'crimson', role: Role) => {
    const teamData = side === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    if (!teamData) return;
    const originalTeamIndex = match.teams.findIndex(t => t.name === teamData.name);
    if (originalTeamIndex === -1) return;
    const azureIds = new Set(activeMatchData?.teamA?.slots.map(s => s.player.id));
    const crimsonIds = new Set(activeMatchData?.teamB?.slots.map(s => s.player.id));
    const benchPlayers = activePlayers.filter(p => !azureIds.has(p.id) && !crimsonIds.has(p.id));
    if (benchPlayers.length === 0) return;
    const candidates = benchPlayers.filter(p => p.isAllRoles || p.roles.includes(role));
    if (candidates.length === 0) return;
    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const randomDuration = Math.floor(Math.random() * (8000 - 4000 + 1)) + 4000;
    setWheelState({ isOpen: true, type: 'reroll', team: side, role: role, winnerName: newPlayer.name, winnerPlayer: newPlayer, candidates: candidates.map(p => p.name), duration: randomDuration });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
        const { team, role } = wheelState;
        const id = `m${currentMatchIdx}-${team === 'azure' ? 'A' : 'B'}-${role}`;
        setRevealedSlots(prev => new Set(prev).add(id));
        if (team === 'crimson') setCurrentRoleIdx(prev => prev + 1);
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        const teamData = wheelState.team === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
        if (teamData) {
            const idx = match.teams.findIndex(t => t.name === teamData.name);
            if (idx !== -1) onReroll(idx, wheelState.role, wheelState.winnerPlayer);
        }
    }
    setWheelState(null);
  };

  const renderPlayerCard = (role: Role, teamSide: 'azure' | 'crimson') => {
    const teamData = teamSide === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    const slot = teamData?.slots.find(s => s.role === role);
    const id = `m${currentMatchIdx}-${teamSide === 'azure' ? 'A' : 'B'}-${role}`;
    if (!revealedSlots.has(id)) return <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group"><div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">{RoleIcons[role]}</div></div>;
    const theme = teamSide === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' } : { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#ef4444]/20 to-transparent' };
    return <div className="relative h-16 w-full animate-slide-in perspective-container group"><div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}><div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}><div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${teamSide === 'crimson' ? 'right' : 'left'} opacity-90`}>{RoleIcons[role]}</div><span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">{slot?.player.name}</span><div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div></div><button onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role); }} className={`absolute top-2 p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full opacity-0 group-hover:opacity-100 text-white hover:text-black z-50 transition-all ${teamSide === 'azure' ? 'right-4' : 'left-4'}`}><svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" /></svg></button></div></div>;
  };

  if (phase === 'TOURNAMENT_END') return <div className="fixed inset-0 z-[200] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden"><div className="god-rays opacity-20"></div><h3 className="text-[#dcb06b] font-orbitron font-bold tracking-[0.6em] text-lg uppercase mb-4 animate-pulse">GRAND FINAL WINNER</h3><h1 className="text-4xl md:text-7xl font-cinzel font-black text-white mb-8 tracking-widest">TOURNAMENT CHAMPION</h1><div className="bg-[#0a1a2f] border-4 border-[#dcb06b] px-16 py-8 clip-corner-md shadow-[0_0_60px_rgba(220,176,107,0.4)]"><h2 className="text-5xl md:text-7xl font-black font-cinzel text-white" style={{ color: tournamentChampion?.color || '#fff' }}>{tournamentChampion?.name}</h2></div><Button onClick={onReset} size="lg" className="mt-16 px-16">RETURN TO LOBBY</Button></div>;
  if (phase === 'TRANSITION' && activeMatchData) return <PortalTransition azureTeam={activeMatchData.teamA?.slots || []} crimsonTeam={activeMatchData.teamB?.slots || []} onComplete={() => setPhase('DECLARE_WIN')} />;
  if (phase === 'DECLARE_WIN' && activeMatchData) return <MatchSummary match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) return <VictoryCelebration winner={currentRoundWinner} teamSlots={(currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots) || []} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) return <EvaluationScreen match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>
      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16"><h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1><p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p></div>
          <div className="flex gap-24 md:gap-40 items-center justify-center relative py-20">
            {hasQuarterFinals && <div className="flex flex-col gap-16 relative">{quarterMatches.map((m, i) => <div key={m.id} className="relative">{renderBracketMatchCard(m)}{i % 2 === 0 && <EnergyConnector type="fork" height={274} />}</div>)}</div>}
            <div className={`flex flex-col ${match.teams.length === 7 ? 'gap-6' : (match.teams.length === 5 ? 'gap-12' : 'gap-32')} relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {/* Visual Connector for Gauntlet 3, 5, 7 */}
                  {match.teams.length === 3 && i === 0 && <EnergyConnector type="fork" height={338} />}
                  {match.teams.length === 5 && i === 3 && <EnergyConnector type="fork" height={666} style={{ transform: 'translateY(-666px)' }} />}
                  {match.teams.length === 7 && i === 5 && <EnergyConnector type="fork" height={1080} style={{ transform: 'translateY(-1080px)' }} />}
                  {hasQuarterFinals && i % 2 === 0 && <EnergyConnector type="fork" height={498} />}
                </div>
              ))}
            </div>
            {/* Grand Final positioning for Gauntlet Modes */}
            <div className={`relative scale-125 ml-10 ${match.teams.length === 7 ? 'translate-y-[-540px]' : (match.teams.length === 5 ? 'translate-y-[-333px]' : '')}`}>{renderBracketMatchCard(grandFinalMatch)}</div>
          </div>
          <button onClick={onReset} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState && wheelState.isOpen && <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} team={wheelState.team} roleName={wheelState.role} roomId={activeRoomId} duration={wheelState.duration} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}
            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center"><Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">BACK TO BRACKET</Button><div className="flex flex-col items-center gap-0 scale-[0.85] origin-top"><span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1 opacity-70">ROOM ID</span><div className="relative"><div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div><div className="relative bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]"><span className="text-2xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b]">{activeRoomId}</span></div></div></div>{revealedSlots.size < 10 ? <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">SKIP ALL</Button> : <div className="w-[120px]"></div>}</div>
            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6"><div className="text-left"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-cyan-600 tracking-widest drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]" style={{ color: activeMatchData?.teamA?.color }}>{activeMatchData?.teamA?.name.split(' ')[0]} <span className="hidden md:inline">{activeMatchData?.teamA?.name.split(' ')[1] || 'GOLEM'}</span></h2><div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div></div><div className="text-right"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-100 to-red-600 tracking-widest drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]" style={{ color: activeMatchData?.teamB?.color }}><span className="hidden md:inline">{activeMatchData?.teamB?.name.split(' ')[0] || 'CRIMSON'}</span> {activeMatchData?.teamB?.name.split(' ')[1] || 'GOLEM'}</h2><div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div></div></div>
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20"><span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span></div>
                <div className="space-y-4 relative z-10">{ROLES_ORDER.map((role) => <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center"><div>{renderPlayerCard(role, 'azure')}</div><div>{renderPlayerCard(role, 'crimson')}</div></div>)}</div>
            </div>
            <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none"><div className="pointer-events-auto">{revealedSlots.size < 10 ? <button onClick={handleNextReveal} className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]">{revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`}</button> : <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">INITIALIZE BATTLE</Button>}</div></div>
        </div>
      )}
    </div>
  );
};

