            <div className={`relative scale-125 ml-10`}>{renderBracketMatchCard(grandFinalMatch)}</div>
          </div>
          <button onClick={() => setShowAbortConfirm(true)} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState && wheelState.isOpen && <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} team={wheelState.team} roleName={wheelState.role} roomId={activeRoomId} duration={wheelState.duration} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}
            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center"><Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">BACK TO BRACKET</Button><div className="flex flex-col items-center gap-0 scale-[0.85] origin-top"><span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1 opacity-70">ROOM ID</span><div className="relative"><div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div><div className="relative bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]"><span className="text-2xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b]">{activeRoomId}</span></div></div></div>{revealedSlots.size < 10 ? <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">SKIP ALL</Button> : <div className="w-[120px]"></div>}</div>
            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6"><div className="text-left"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-cyan-600 tracking-widest drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]" style={{ color: activeMatchData?.teamA?.color }}>{activeMatchData?.teamA?.name.split(' ')[0]} <span className="hidden md:inline">{activeMatchData?.teamA?.name.split(' ')[1] || 'GOLEM'}</span></h2><div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div></div><div className="text-right"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-100 to-red-600 tracking-widest drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]" style={{ color: activeMatchData?.teamB?.color }}><span className="hidden md:inline">{activeMatchData?.teamB?.name.split(' ')[0] || 'CRIMSON'}</span> {activeMatchData?.teamB?.name.split(' ')[1] || 'GOLEM'}</h2><div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div></div></div>
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20"><span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span></div>
                <div className="space-y-4 relative z-10">{ROLES_ORDER.map((role) => <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center"><div>{renderPlayerCard(role, 'azure')}</div><div>{renderPlayerCard(role, 'crimson')}</div></div>)}</div>
            </div>
            <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none"><div className="pointer-events-auto">{revealedSlots.size < 10 ? <button onClick={handleNextReveal} className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]">{revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`}</button> : <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">INITIALIZE BATTLE</Button>}</div></div>
        </div>
      )}
    </div>
  );
};

import { Player, Role, TeamSlot, MatchResult, BracketMatchResult, BracketTeam } from '../types';
import { ROLES_ORDER } from '../constants';

const BRACKET_NAMES = ["Alpha", "Beta", "Charlie", "Delta", "Echo", "Foxtrot", "Golf", "Hotel"];
const BRACKET_COLORS = [
  "#00d2ff", // Cyan
  "#ef4444", // Red
  "#fbbf24", // Gold
  "#a855f7", // Purple
  "#10b981", // Emerald
  "#f97316", // Orange
  "#ec4899", // Pink
  "#ffffff"  // White
];

export const TBD_PLAYER: Player = {
  id: 'tbd',
  name: '?',
  roles: [],
  isAllRoles: false,
  isActive: true,
  stats: { matchesPlayed: 0, wins: 0, currentStreak: 0, maxStreak: 0 }
};

// Fisher-Yates Shuffle for true randomness
function shuffle<T>(array: T[]): T[] {
  const newArray = [...array];
  for (let i = newArray.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [newArray[i], newArray[j]] = [newArray[j], newArray[i]];
  }
  return newArray;
}

// Check if a player can play a specific role
export const canPlay = (player: Player, role: Role): boolean => {
  if (player.id === 'tbd') return true;

  if (role === Role.COACH) {
    return player.roles.includes(Role.COACH);
  }

  if (player.roles.includes(Role.COACH) && player.roles.length === 1 && !player.isAllRoles) {
     return false; 
  }

  if (player.isAllRoles) return true;
  return player.roles.includes(role);
};

// Calculate versatility score 
// Lower score = Less flexible (Higher priority to pick)
// Higher score = More flexible (Can wait)
const getPlayerVersatility = (player: Player): number => {
  if (player.isAllRoles) return 6; // Treat "All Roles" as effectively 6 roles
  return player.roles.length;
};

// Helper function to sort players with "Noise"
// This prevents players with 1 role from ALWAYS being picked first if a 2-role player is available.
// It creates a "soft priority" instead of a "hard priority".
const noisySort = (a: Player, b: Player) => {
  // Add random noise (0.0 to 2.0) to the score
  // 1 Role Player: 1.0 to 3.0
  // 2 Role Player: 2.0 to 4.0
  // There is overlap! A 2-role player can sometimes be prioritized over a 1-role player.
  const scoreA = getPlayerVersatility(a) + (Math.random() * 2.5);
  const scoreB = getPlayerVersatility(b) + (Math.random() * 2.5);
  return scoreA - scoreB;
};

// Helper to get a random valid candidate from a pool
// Used heavily in Bracket JIT logic
export const getFlexibleCandidate = (pool: Player[], role: Role): Player | null => {
  let candidates = pool.filter(p => canPlay(p, role));

  if (candidates.length === 0) return null;

  // 1. Shuffle first to ensure candidates with EQUAL specs are random
  candidates = shuffle(candidates);

  // 2. If we have a healthy number of candidates (> 2), use the Noisy Sort.
  // This ensures that "Kazehunt" (e.g., Farm only) isn't ALWAYS picked immediately 
  // if "Player B" (Farm + Mid) is also available.
  if (candidates.length > 1) {
      candidates.sort(noisySort);
  }

  // Return the best fit (first one after sort)
  return candidates[0];
};

export const generateMatch = (players: Player[], roomId: string, isCoachMode: boolean): MatchResult | null => {
  const requiredPlayers = isCoachMode ? 12 : 10;
  if (players.length < requiredPlayers) return null;

  const neededRoles: { team: 'azure' | 'crimson', role: Role }[] = [];
  ROLES_ORDER.forEach(role => neededRoles.push({ team: 'azure', role }));
  ROLES_ORDER.forEach(role => neededRoles.push({ team: 'crimson', role }));

  if (isCoachMode) {
    neededRoles.push({ team: 'azure', role: Role.COACH });
    neededRoles.push({ team: 'crimson', role: Role.COACH });
  }

  const totalSlots = neededRoles.length;

  // Shuffle the pool initially
  let pool = shuffle(players);

  // Sort pool using Noisy Sort to allow variation in standard matches too
  // This prevents the same roster configuration every time a match is generated with the same 10 people
  pool.sort(noisySort);

  const assignments: Map<number, Player> = new Map();
  const usedPlayerIds = new Set<string>();

  const solve = (slotIndex: number): boolean => {
    if (slotIndex >= totalSlots) return true;
    const currentSlot = neededRoles[slotIndex];

    // Create a local randomized version of the pool for this specific slot check
    // This adds another layer of randomness during the backtracking process
    // We only shuffle players who are roughly equally eligible to avoid breaking constraints too much
    // But since we already noisy-sorted the main pool, simple iteration is usually fine.
    // However, iterating strictly can still lead to patterns.

    for (const player of pool) {
      if (!usedPlayerIds.has(player.id)) {
        if (canPlay(player, currentSlot.role)) {
          assignments.set(slotIndex, player);
          usedPlayerIds.add(player.id);
          if (solve(slotIndex + 1)) return true;
          assignments.delete(slotIndex);
          usedPlayerIds.delete(player.id);
        }
      }
    }
    return false;
  };

  if (solve(0)) {
    const azureTeam: TeamSlot[] = [];
    const crimsonTeam: TeamSlot[] = [];
    for (let i = 0; i < totalSlots; i++) {
        const slot = neededRoles[i];
        const player = assignments.get(i)!;
        if (slot.team === 'azure') azureTeam.push({ role: slot.role, player });
        else crimsonTeam.push({ role: slot.role, player });
    }
    const roleOrderMap = [...ROLES_ORDER, Role.COACH];
    const sortTeam = (a: TeamSlot, b: TeamSlot) => roleOrderMap.indexOf(a.role) - roleOrderMap.indexOf(b.role);
    azureTeam.sort(sortTeam);
    crimsonTeam.sort(sortTeam);
    return { roomId, azureTeam, crimsonTeam, isCoachMode, timestamp: Date.now() };
  }
  return null;
};

// INSTANT GENERATION - Just creates the structure with TBD players
export const generateBracketMatch = (players: Player[], roomId: string, numTeams: number): BracketMatchResult | null => {
  const requiredPlayers = numTeams * 5;
  if (players.length < requiredPlayers) return null;

  const teams: BracketTeam[] = [];

  for (let t = 0; t < numTeams; t++) {
    const teamSlots: TeamSlot[] = [];

    ROLES_ORDER.forEach(role => {
        teamSlots.push({ role, player: TBD_PLAYER });
    });

    teams.push({
      name: `TEAM ${BRACKET_NAMES[t]}`,
      slots: teamSlots,
      color: BRACKET_COLORS[t]
    });
  }

  return { roomId, teams, timestamp: Date.now() };
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';
import { ConfirmModal } from './ConfirmModal';
import { getFlexibleCandidate, canPlay, TBD_PLAYER } from '../utils/matchmaker';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
  onUpdatePlayer: (updatedPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll, onUpdatePlayer }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // GLOBAL ASSIGNMENT TRACKING
  // Maps "teamIndex-role" string to Player ID
  const [globalAssignments, setGlobalAssignments] = useState<Record<string, string>>({});

  // State for Abort Confirmation
  const [showAbortConfirm, setShowAbortConfirm] = useState(false);

  // Rename State
  const [renameState, setRenameState] = useState<{ isOpen: boolean; player: Player | null; newName: string }>({
    isOpen: false,
    player: null,
    newName: ''
  });

  // State to track matches that have been fully revealed/spun
  const [completedReveals, setCompletedReveals] = useState<Set<number>>(new Set());

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // Helper to get the actual assigned player or TBD
  const getAssignedPlayer = useCallback((teamIdx: number, role: Role): Player => {
      const key = `${teamIdx}-${role}`;
      const pid = globalAssignments[key];
      if (pid) {
          return activePlayers.find(p => p.id === pid) || TBD_PLAYER;
      }
      return TBD_PLAYER;
  }, [globalAssignments, activePlayers]);

  // --- MEMOIZED BRACKET GENERATION ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const getTeamObj = (teamIndex: number) => {
          if (teamIndex < 0 || teamIndex >= match.teams.length) return null;
          const original = match.teams[teamIndex];
          // Reconstruct team with current assignments
          const updatedSlots = original.slots.map(s => ({
              ...s,
              player: getAssignedPlayer(teamIndex, s.role)
          }));
          return { ...original, slots: updatedSlots };
      };

      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const getLoserTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA || !teamB) return null;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > 0 || scoreB > 0) {
            if (scoreA < scoreB) return teamA;
            if (scoreB < scoreA) return teamB;
        }
        return null;
      };

      const numTeams = match.teams.length;

      // Case 1: 3 teams (Stepladder)
      if (numTeams === 3) {
        const m0 = { id: 0, label: 'ELIMINATION', mode: 'BO1', teamA: getTeamObj(0), teamB: getTeamObj(1) };
        const m1 = { id: 1, label: 'CHALLENGER', mode: 'BO1', teamA: getLoserTeam(0, m0.teamA, m0.teamB), teamB: getTeamObj(2) };
        const m2 = { id: 2, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, m0.teamA, m0.teamB), teamB: getWinnerTeam(1, m1.teamA, m1.teamB) };
        return { quarterMatches: [], semiMatches: [m0, m1], grandFinalMatch: m2, allMatches: [m0, m1, m2], hasQuarterFinals: false };
      }

      // Case 2: 5 or 6 teams (Challenger Style)
      if (numTeams === 5 || numTeams === 6) {
        const q0 = { id: 0, label: 'QUARTER 1', mode: 'BO1', teamA: getTeamObj(0), teamB: getTeamObj(1) };
        const q1 = { id: 1, label: 'QUARTER 2', mode: 'BO1', teamA: getTeamObj(2), teamB: getTeamObj(3) };
        const q2 = { id: 2, label: 'QUARTER 3', mode: 'BO1', teamA: getTeamObj(4), teamB: getTeamObj(5) || null };

        const s1 = { id: 3, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(0, q0.teamA, q0.teamB), teamB: getWinnerTeam(1, q1.teamA, q1.teamB) };
        const s2 = { id: 4, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(2, q2.teamA, q2.teamB), teamB: getLoserTeam(3, s1.teamA, s1.teamB) };

        const gf = { id: 5, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(3, s1.teamA, s1.teamB), teamB: getWinnerTeam(4, s2.teamA, s2.teamB) };

        return { 
          quarterMatches: [q0, q1, q2], 
          semiMatches: [s1, s2], 
          grandFinalMatch: gf, 
          allMatches: [q0, q1, q2, s1, s2, gf], 
          hasQuarterFinals: true 
        };
      }

      // Case 3: 4, 8 teams
      const hasQuarterFinals = numTeams === 8;
      const qMatches: any[] = [];
      if (numTeams === 8) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({ id: i, label: `QUARTER ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
      }

      const sMatches: any[] = [];
      if (numTeams === 8) {
          sMatches.push({ id: 4, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(0, qMatches[0].teamA, qMatches[0].teamB), teamB: getWinnerTeam(1, qMatches[1].teamA, qMatches[1].teamB) });
          sMatches.push({ id: 5, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(2, qMatches[2].teamA, qMatches[2].teamB), teamB: getWinnerTeam(3, qMatches[3].teamA, qMatches[3].teamB) });
      } else {
          // 4 teams
          for (let i = 0; i < 2; i++) {
              sMatches.push({ id: i, label: `SEMI FINAL ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
      }

      const gfIndex = numTeams === 8 ? 6 : 2;
      const gf = { id: gfIndex, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB), teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB) };
      return { quarterMatches: qMatches, semiMatches: sMatches, grandFinalMatch: gf, allMatches: [...qMatches, ...sMatches, gf], hasQuarterFinals };
  }, [match, scores, globalAssignments, getAssignedPlayer]); 

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);
    if (m && !m.teamB) {
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }
    setCurrentMatchIdx(idx);

    // LOGIC UPDATE: CHECK FOR QUARTER FINAL
    const isQuarterFinal = quarterMatches.some(q => q.id === idx);

    if (idx === grandFinalMatch.id) {
        setPhase('TRANSITION');
    } else {
        setPhase('REVEAL');

        // If it is NOT a Quarter Final (e.g. Semi Final), OR if it's already completed in the past:
        // We simulate "Skip All" immediately.
        if (!isQuarterFinal || completedReveals.has(idx)) {
            const allCards = new Set<string>();
            ROLES_ORDER.forEach(r => { 
                allCards.add(`m${idx}-A-${r}`); 
                allCards.add(`m${idx}-B-${r}`); 
            });
            setRevealedSlots(allCards);
            setCurrentRoleIdx(ROLES_ORDER.length - 1);
            setCompletedReveals(prev => new Set(prev).add(idx));
        } else {
            // It IS a Quarter Final and NOT completed -> Enable Rolling (Start empty)
            setRevealedSlots(new Set());
            setCurrentRoleIdx(-1);
        }
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const EnergyConnector = ({ type, height, style }: { type: 'fork' | 'straight', height: number, style?: React.CSSProperties }) => (
    <div 
        className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" 
        style={{ height: `${height}px`, ...style }}
    >
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3" result="blur"/>
                <feComposite in="SourceGraphic" in2="blur" operator="over"/>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path 
                d={`M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          ) : (
             <path 
                d={`M 0,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          )}
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,${height/2} L 100,${height/2}`} dur="2s" repeatCount="indefinite" />
          </circle>
          {type === 'fork' && (
            <circle r="3" fill="#fff" filter="url(#energyGlow)">
                <animateMotion path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} dur="2s" begin="1s" repeatCount="indefinite" />
            </circle>
          )}
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;
      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';
      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-md p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>
            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>
                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1"><div className="h-[1px] flex-1 bg-white"></div><span className="text-[8px] font-black italic text-[#8a9db8]">VS</span><div className="h-[1px] flex-1 bg-white"></div></div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>
            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input type="text" value={matchRoomIds[m.id] || ''} onChange={(e) => { const val = e.target.value.replace(/\D/g,'').slice(0,4); setMatchRoomIds(prev => ({ ...prev, [m.id]: val })); }} className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" placeholder="----" />
                        </div>
                        {!isDone && m.teamA && m.teamB && <Button onClick={() => startMatchFlow(m.id)} disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} size="sm" className="h-[28px] text-[8px] px-3">START</Button>}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = allMatches.find(m => m.id === currentMatchIdx);
  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const handleNextReveal = () => {
    if (!activeMatchData) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    const side = revealedSlots.has(azureId) ? 'crimson' : 'azure';

    // Determine which team in the original bracket structure this corresponds to
    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    // Find the index of this team in the original match.teams array
    const originalTeamIndex = match.teams.findIndex(t => t.name === teamData?.name);

    if (originalTeamIndex === -1) return;

    // Check if player already assigned
    let winner = getAssignedPlayer(originalTeamIndex, role);

    // JUST IN TIME ASSIGNMENT
    if (winner.id === 'tbd') {
        const currentlyAssignedIds = new Set(Object.values(globalAssignments));
        const availablePlayers = activePlayers.filter(p => !currentlyAssignedIds.has(p.id));

        // Pick a random valid player
        const pickedPlayer = getFlexibleCandidate(availablePlayers, role);

        if (pickedPlayer) {
            winner = pickedPlayer;
            // Lock them in
            const key = `${originalTeamIndex}-${role}`;
            setGlobalAssignments(prev => ({ ...prev, [key]: pickedPlayer.id }));
        } else {
            // Should rarely happen if pool is sufficient, but handle gracefully?
            // For now, if no player found, it stays TBD (or we could force a random fill ignoring roles)
            console.warn("No valid player found for", role);
        }
    }

    const revealedPlayerIds = new Set<string>();
    // Collect revealed IDs just for the wheel visual exclusion, if needed

    const candidates = activePlayers.filter(p => {
        // Filter out players already assigned to OTHER slots
        const assignedToOtherSlot = Object.entries(globalAssignments).some(([k, pid]) => k !== `${originalTeamIndex}-${role}` && pid === p.id);
        if (assignedToOtherSlot) return false;

        return canPlay(p, role);
    });

    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);
    const randomDuration = Math.floor(Math.random() * (9000 - 4500 + 1)) + 4500;

    setWheelState({ 
        isOpen: true, 
        type: 'reveal', 
        team: side, 
        role: role, 
        winnerName: winner.name, 
        winnerPlayer: winner, // Pass the player object
        candidates: candidateNames, 
        duration: randomDuration 
    });
  };

  const handleSkipAll = () => {
    // Greedy fill for the CURRENT MATCH only
    if (!activeMatchData) return;

    const newAssignments: Record<string, string> = {};
    const usedIds = new Set(Object.values(globalAssignments));

    const fillTeam = (teamName: string) => {
        const teamIdx = match.teams.findIndex(t => t.name === teamName);
        if (teamIdx === -1) return;

        ROLES_ORDER.forEach(role => {
            const key = `${teamIdx}-${role}`;
            if (globalAssignments[key]) return; // Already assigned

            // Find candidate
            const available = activePlayers.filter(p => !usedIds.has(p.id));
            const picked = getFlexibleCandidate(available, role);

            if (picked) {
                newAssignments[key] = picked.id;
                usedIds.add(picked.id);
            }
        });
    };

    if (activeMatchData.teamA) fillTeam(activeMatchData.teamA.name);
    if (activeMatchData.teamB) fillTeam(activeMatchData.teamB.name);

    setGlobalAssignments(prev => ({ ...prev, ...newAssignments }));

    const allCards = new Set<string>();
    ROLES_ORDER.forEach(r => { allCards.add(`m${currentMatchIdx}-A-${r}`); allCards.add(`m${currentMatchIdx}-B-${r}`); });
    setRevealedSlots(allCards);
    setCurrentRoleIdx(ROLES_ORDER.length - 1);

    // Mark as completed so we don't need to spin again
    setCompletedReveals(prev => new Set(prev).add(currentMatchIdx));
  };

  const handleRerollClick = (side: 'azure' | 'crimson', role: Role) => {
    const teamData = side === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    if (!teamData) return;
    const teamIndex = match.teams.findIndex(t => t.name === teamData.name);
    if (teamIndex === -1) return;

    // Filter candidates from unassigned players
    const currentlyAssignedIds = new Set(Object.values(globalAssignments));
    const benchPlayers = activePlayers.filter(p => !currentlyAssignedIds.has(p.id));

    if (benchPlayers.length === 0) return;

    const candidates = benchPlayers.filter(p => canPlay(p, role));
    if (candidates.length === 0) return;

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const randomDuration = Math.floor(Math.random() * (8000 - 4000 + 1)) + 4000;

    setWheelState({ 
        isOpen: true, 
        type: 'reroll', 
        team: side, 
        role: role, 
        winnerName: newPlayer.name, 
        winnerPlayer: newPlayer, 
        candidates: candidates.map(p => p.name), 
        duration: randomDuration 
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
        const { team, role, winnerPlayer } = wheelState;

        // Ensure assignment is recorded (in case it wasn't pre-filled logic)
        if (winnerPlayer && activeMatchData) {
             const teamData = team === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
             const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
             if (teamIdx !== -1) {
                 const key = `${teamIdx}-${role}`;
                 setGlobalAssignments(prev => ({ ...prev, [key]: winnerPlayer.id }));
             }
        }

        const id = `m${currentMatchIdx}-${team === 'azure' ? 'A' : 'B'}-${role}`;
        setRevealedSlots(prev => new Set(prev).add(id));
        if (team === 'crimson') {
            const nextIdx = currentRoleIdx + 1;
            setCurrentRoleIdx(nextIdx);

            // Check if this was the final reveal for the match
            if (nextIdx >= ROLES_ORDER.length) {
                setCompletedReveals(prev => new Set(prev).add(currentMatchIdx));
            }
        }
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        const teamData = wheelState.team === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
        if (teamData) {
            const idx = match.teams.findIndex(t => t.name === teamData.name);
            if (idx !== -1) {
                // Update Global Assignments directly
                const key = `${idx}-${wheelState.role}`;
                setGlobalAssignments(prev => ({ ...prev, [key]: wheelState.winnerPlayer!.id }));
            }
        }
    }
    setWheelState(null);
  };

  // Rename Logic
  const openRenameModal = (player: Player) => {
    setRenameState({ isOpen: true, player, newName: player.name });
  };

  const submitRename = () => {
    if (renameState.player && renameState.newName.trim()) {
        onUpdatePlayer({ ...renameState.player, name: renameState.newName.trim() });
        setRenameState({ isOpen: false, player: null, newName: '' });
    }
  };

  const renderPlayerCard = (role: Role, teamSide: 'azure' | 'crimson') => {
    const teamData = teamSide === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    // Find dynamic player based on assignment
    const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
    const player = teamIdx !== -1 ? getAssignedPlayer(teamIdx, role) : TBD_PLAYER;

    const id = `m${currentMatchIdx}-${teamSide === 'azure' ? 'A' : 'B'}-${role}`;
    if (!revealedSlots.has(id)) return <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group"><div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">{RoleIcons[role]}</div></div>;

    const theme = teamSide === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' } : { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#ef4444]/20 to-transparent' };

    return (
        <div className="relative h-16 w-full animate-slide-in perspective-container group">
            <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
                <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
                    <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${teamSide === 'crimson' ? 'right' : 'left'} opacity-90`}>{RoleIcons[role]}</div>
                    <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">{player.name}</span>
                    <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
                </div>

                <div className={`absolute top-2 z-50 flex gap-2 transition-all opacity-0 group-hover:opacity-100 ${teamSide === 'azure' ? 'right-4' : 'left-4'}`}>
                   {/* Reroll Button */}
                   <button 
                      onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role); }} 
                      className="p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full text-white hover:text-black transition-all"
                      title="Reroll Player"
                   >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                      </svg>
                   </button>

                   {/* Edit Name Button */}
                   <button 
                      onClick={(e) => { e.stopPropagation(); if(player) openRenameModal(player); }} 
                      className="p-2.5 bg-black/60 hover:bg-[#00d2ff] rounded-full text-white hover:text-black transition-all"
                      title="Change Nickname"
                   >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                      </svg>
                   </button>
                </div>
            </div>
        </div>
    );
  };

  // --- CHAMPION VICTORY SCREEN RENDERER ---
  const renderTournamentEnd = () => {
    return (
      <div className="fixed inset-0 z-[300] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
        {/* Automatic Music Background */}
        <iframe 
            width="0" 
            height="0" 
            src="https://www.youtube.com/embed/13ARO0HDZsQ?autoplay=1&loop=1&playlist=13ARO0HDZsQ" 
            frameBorder="0" 
            allow="autoplay" 
            className="hidden pointer-events-none"
        ></iframe>

        {/* Visual Background Effects */}
        <div className="god-rays opacity-40"></div>
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#05090f_90%)] z-10"></div>

        {/* Floating Embers / Confetti */}
        {Array.from({ length: 40 }).map((_, i) => (
          <div 
            key={i} 
            className="confetti-piece"
            style={{
              left: `${Math.random() * 100}%`,
              animationDelay: `${Math.random() * 5}s`,
              backgroundColor: Math.random() > 0.5 ? '#dcb06b' : '#ffffff',
              zIndex: 20
            }}
          ></div>
        ))}

        <div className="relative z-20 flex flex-col items-center animate-trophy-pop w-full max-w-4xl">
            <h3 className="text-[#dcb06b] font-orbitron font-black tracking-[0.8em] text-sm uppercase mb-4 animate-pulse opacity-80">
                TOURNAMENT CONCLUDED
            </h3>

            <h1 className="text-5xl md:text-8xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-[#dcb06b] mb-12 tracking-[0.2em] drop-shadow-[0_10px_30px_rgba(220,176,107,0.4)] text-center px-4">
                TOURNAMENT CHAMPIONS
            </h1>

            <div className="bg-[#0a1a2f]/80 border-4 border-[#dcb06b] px-12 md:px-24 py-10 clip-corner-md shadow-[0_0_100px_rgba(220,176,107,0.3)] relative overflow-hidden group mb-12 transform hover:scale-105 transition-transform duration-500">
                <div className="absolute inset-0 bg-gradient-to-br from-[#dcb06b]/10 to-transparent opacity-50"></div>
                <h2 className="text-6xl md:text-9xl font-black font-cinzel text-white text-center drop-shadow-[0_0_20px_#dcb06b]" style={{ color: tournamentChampion?.color || '#fff' }}>
                    {tournamentChampion?.name}
                </h2>
            </div>

            {/* Champions Roster Display */}
            <div className="grid grid-cols-2 md:grid-cols-5 gap-4 w-full px-6 mb-16">
               {tournamentChampion?.slots.map((slot: TeamSlot, idx: number) => (
                  <div 
                    key={idx} 
                    className="flex flex-col items-center p-4 bg-black/40 border border-[#dcb06b]/40 clip-corner-sm backdrop-blur-md transform transition-all duration-700 hover:border-[#dcb06b] hover:bg-[#dcb06b]/5 animate-slide-in"
                    style={{ animationDelay: `${idx * 150}ms` }}
                  >
                     <div className="text-[#dcb06b] mb-2 opacity-70 scale-90">
                        {RoleIcons[slot.role]}
                     </div>
                     <span className="text-white font-orbitron font-black text-sm md:text-base tracking-widest truncate max-w-full">
                        {slot.player.name}
                     </span>
                  </div>
               ))}
            </div>

            <Button onClick={onReset} size="lg" className="px-24 h-20 text-xl shadow-[0_0_50px_rgba(220,176,107,0.5)]">
                RETURN TO LOBBY
            </Button>
        </div>
      </div>
    );
  };

  if (phase === 'TOURNAMENT_END') return renderTournamentEnd();
  if (phase === 'TRANSITION' && activeMatchData) return <PortalTransition azureTeam={activeMatchData.teamA?.slots || []} crimsonTeam={activeMatchData.teamB?.slots || []} onComplete={() => setPhase('DECLARE_WIN')} />;
  if (phase === 'DECLARE_WIN' && activeMatchData) return <MatchSummary match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) return <VictoryCelebration winner={currentRoundWinner} teamSlots={(currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots) || []} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) return <EvaluationScreen match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <ConfirmModal 
        isOpen={showAbortConfirm}
        title="ABORT TOURNAMENT"
        message="Are you sure you want to end the tournament? All progress will be lost."
        onConfirm={onReset}
        onCancel={() => setShowAbortConfirm(false)}
        isDestructive={true}
      />

      {/* RENAME MODAL */}
      {renameState.isOpen && (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })}></div>
            <div className="relative w-full max-w-sm bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md shadow-[0_0_30px_rgba(220,176,107,0.3)] animate-slide-in p-6">
                <h3 className="text-[#dcb06b] font-cinzel font-bold text-lg mb-4 text-center tracking-widest">CHANGE NICKNAME</h3>
                <input 
                    type="text" 
                    value={renameState.newName} 
                    onChange={e => setRenameState({ ...renameState, newName: e.target.value })} 
                    className="w-full bg-black/50 border border-[#1e3a5f] p-3 text-white font-orbitron focus:border-[#dcb06b] outline-none mb-6 text-center"
                    autoFocus
                />
                <div className="flex gap-3">
                    <Button variant="secondary" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })} className="flex-1">CANCEL</Button>
                    <Button onClick={submitRename} className="flex-1">CONFIRM</Button>
                </div>
            </div>
        </div>
      )}

      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>
      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16"><h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1><p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p></div>
          <div className="flex gap-24 md:gap-40 items-center justify-center relative py-20">

            {/* COLUMN 1: QUARTER FINALS */}
            {hasQuarterFinals && (
              <div className="flex flex-col gap-16 relative">
                {quarterMatches.map((m, i) => (
                  <div key={m.id} className="relative">
                    {renderBracketMatchCard(m)}
                    {/* Connector logic */}
                    {match.teams.length === 5 || match.teams.length === 6 ? (
                      // Specialized layout for 5/6 teams: QF1 & QF2 fork to SF1, QF3 straight to SF2 (Team 5/6 flow)
                      i < 2 ? (i === 0 && <EnergyConnector type="fork" height={274} />) : <EnergyConnector type="straight" height={0} />
                    ) : (
                      i % 2 === 0 && <EnergyConnector type="fork" height={322} />
                    )}
                  </div>
                ))}
              </div>
            )}

            {/* COLUMN 2: SEMI FINALS */}
            <div className={`flex flex-col gap-32 relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {/* Fork to Grand Final */}
                  {i === 0 && <EnergyConnector type="fork" height={338} />}
                </div>
              ))}
            </div>

            {/* COLUMN 3: GRAND FINAL */}
            <div className={`relative scale-125 ml-10`}>{renderBracketMatchCard(grandFinalMatch)}</div>
          </div>
          <button onClick={() => setShowAbortConfirm(true)} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState && wheelState.isOpen && <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} team={wheelState.team} roleName={wheelState.role} roomId={activeRoomId} duration={wheelState.duration} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}
            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center"><Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">BACK TO BRACKET</Button><div className="flex flex-col items-center gap-0 scale-[0.85] origin-top"><span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1 opacity-70">ROOM ID</span><div className="relative"><div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div><div className="relative bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]"><span className="text-2xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b]">{activeRoomId}</span></div></div></div>{revealedSlots.size < 10 ? <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">SKIP ALL</Button> : <div className="w-[120px]"></div>}</div>
            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6"><div className="text-left"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-cyan-600 tracking-widest drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]" style={{ color: activeMatchData?.teamA?.color }}>{activeMatchData?.teamA?.name.split(' ')[0]} <span className="hidden md:inline">{activeMatchData?.teamA?.name.split(' ')[1] || 'GOLEM'}</span></h2><div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div></div><div className="text-right"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-100 to-red-600 tracking-widest drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]" style={{ color: activeMatchData?.teamB?.color }}><span className="hidden md:inline">{activeMatchData?.teamB?.name.split(' ')[0] || 'CRIMSON'}</span> {activeMatchData?.teamB?.name.split(' ')[1] || 'GOLEM'}</h2><div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div></div></div>
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20"><span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span></div>
                <div className="space-y-4 relative z-10">{ROLES_ORDER.map((role) => <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center"><div>{renderPlayerCard(role, 'azure')}</div><div>{renderPlayerCard(role, 'crimson')}</div></div>)}</div>
            </div>
            <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none"><div className="pointer-events-auto">{revealedSlots.size < 10 ? <button onClick={handleNextReveal} className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]">{revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`}</button> : <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">INITIALIZE BATTLE</Button>}</div></div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';
import { ConfirmModal } from './ConfirmModal';
import { getFlexibleCandidate, canPlay, TBD_PLAYER } from '../utils/matchmaker';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
  onUpdatePlayer: (updatedPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll, onUpdatePlayer }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // GLOBAL ASSIGNMENT TRACKING
  // Maps "teamIndex-role" string to Player ID
  const [globalAssignments, setGlobalAssignments] = useState<Record<string, string>>({});

  // State for Abort Confirmation
  const [showAbortConfirm, setShowAbortConfirm] = useState(false);

  // Rename State
  const [renameState, setRenameState] = useState<{ isOpen: boolean; player: Player | null; newName: string }>({
    isOpen: false,
    player: null,
    newName: ''
  });

  // State to track matches that have been fully revealed/spun
  const [completedReveals, setCompletedReveals] = useState<Set<number>>(new Set());

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // Helper to get the actual assigned player or TBD
  const getAssignedPlayer = useCallback((teamIdx: number, role: Role): Player => {
      const key = `${teamIdx}-${role}`;
      const pid = globalAssignments[key];
      if (pid) {
          return activePlayers.find(p => p.id === pid) || TBD_PLAYER;
      }
      return TBD_PLAYER;
  }, [globalAssignments, activePlayers]);

  // --- MEMOIZED BRACKET GENERATION ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const getTeamObj = (teamIndex: number) => {
          if (teamIndex < 0 || teamIndex >= match.teams.length) return null;
          const original = match.teams[teamIndex];
          // Reconstruct team with current assignments
          const updatedSlots = original.slots.map(s => ({
              ...s,
              player: getAssignedPlayer(teamIndex, s.role)
          }));
          return { ...original, slots: updatedSlots };
      };

      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const getLoserTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA || !teamB) return null;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > 0 || scoreB > 0) {
            if (scoreA < scoreB) return teamA;
            if (scoreB < scoreA) return teamB;
        }
        return null;
      };

      const numTeams = match.teams.length;

      // Case 1: 3 teams (Stepladder)
      if (numTeams === 3) {
        const m0 = { id: 0, label: 'ELIMINATION', mode: 'BO1', teamA: getTeamObj(0), teamB: getTeamObj(1) };
        const m1 = { id: 1, label: 'CHALLENGER', mode: 'BO1', teamA: getLoserTeam(0, m0.teamA, m0.teamB), teamB: getTeamObj(2) };
        const m2 = { id: 2, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, m0.teamA, m0.teamB), teamB: getWinnerTeam(1, m1.teamA, m1.teamB) };
        return { quarterMatches: [], semiMatches: [m0, m1], grandFinalMatch: m2, allMatches: [m0, m1, m2], hasQuarterFinals: false };
      }

      // Case 2: 5 or 6 teams (Challenger Style)
      if (numTeams === 5 || numTeams === 6) {
        const q0 = { id: 0, label: 'QUARTER 1', mode: 'BO1', teamA: getTeamObj(0), teamB: getTeamObj(1) };
        const q1 = { id: 1, label: 'QUARTER 2', mode: 'BO1', teamA: getTeamObj(2), teamB: getTeamObj(3) };
        const q2 = { id: 2, label: 'QUARTER 3', mode: 'BO1', teamA: getTeamObj(4), teamB: getTeamObj(5) || null };

        const s1 = { id: 3, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(0, q0.teamA, q0.teamB), teamB: getWinnerTeam(1, q1.teamA, q1.teamB) };
        const s2 = { id: 4, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(2, q2.teamA, q2.teamB), teamB: getLoserTeam(3, s1.teamA, s1.teamB) };

        const gf = { id: 5, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(3, s1.teamA, s1.teamB), teamB: getWinnerTeam(4, s2.teamA, s2.teamB) };

        return { 
          quarterMatches: [q0, q1, q2], 
          semiMatches: [s1, s2], 
          grandFinalMatch: gf, 
          allMatches: [q0, q1, q2, s1, s2, gf], 
          hasQuarterFinals: true 
        };
      }

      // Case 3: 4, 8 teams
      const hasQuarterFinals = numTeams === 8;
      const qMatches: any[] = [];
      if (numTeams === 8) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({ id: i, label: `QUARTER ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
      }

      const sMatches: any[] = [];
      if (numTeams === 8) {
          sMatches.push({ id: 4, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(0, qMatches[0].teamA, qMatches[0].teamB), teamB: getWinnerTeam(1, qMatches[1].teamA, qMatches[1].teamB) });
          sMatches.push({ id: 5, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(2, qMatches[2].teamA, qMatches[2].teamB), teamB: getWinnerTeam(3, qMatches[3].teamA, qMatches[3].teamB) });
      } else {
          // 4 teams
          for (let i = 0; i < 2; i++) {
              sMatches.push({ id: i, label: `SEMI FINAL ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
      }

      const gfIndex = numTeams === 8 ? 6 : 2;
      const gf = { id: gfIndex, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB), teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB) };
      return { quarterMatches: qMatches, semiMatches: sMatches, grandFinalMatch: gf, allMatches: [...qMatches, ...sMatches, gf], hasQuarterFinals };
  }, [match, scores, globalAssignments, getAssignedPlayer]); 

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);
    if (m && !m.teamB) {
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }
    setCurrentMatchIdx(idx);

    // LOGIC UPDATE: CHECK FOR QUARTER FINAL
    const isQuarterFinal = quarterMatches.some(q => q.id === idx);

    if (idx === grandFinalMatch.id) {
        setPhase('TRANSITION');
    } else {
        setPhase('REVEAL');

        // If it is NOT a Quarter Final (e.g. Semi Final), OR if it's already completed in the past:
        // We simulate "Skip All" immediately.
        if (!isQuarterFinal || completedReveals.has(idx)) {
            const allCards = new Set<string>();
            ROLES_ORDER.forEach(r => { 
                allCards.add(`m${idx}-A-${r}`); 
                allCards.add(`m${idx}-B-${r}`); 
            });
            setRevealedSlots(allCards);
            setCurrentRoleIdx(ROLES_ORDER.length - 1);
            setCompletedReveals(prev => new Set(prev).add(idx));
        } else {
            // It IS a Quarter Final and NOT completed -> Enable Rolling (Start empty)
            setRevealedSlots(new Set());
            setCurrentRoleIdx(-1);
        }
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const EnergyConnector = ({ type, height, style }: { type: 'fork' | 'straight', height: number, style?: React.CSSProperties }) => (
    <div 
        className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" 
        style={{ height: `${height}px`, ...style }}
    >
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3" result="blur"/>
                <feComposite in="SourceGraphic" in2="blur" operator="over"/>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path 
                d={`M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          ) : (
             <path 
                d={`M 0,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          )}
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,${height/2} L 100,${height/2}`} dur="2s" repeatCount="indefinite" />
          </circle>
          {type === 'fork' && (
            <circle r="3" fill="#fff" filter="url(#energyGlow)">
                <animateMotion path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} dur="2s" begin="1s" repeatCount="indefinite" />
            </circle>
          )}
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;
      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';
      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-md p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>
            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>
                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1"><div className="h-[1px] flex-1 bg-white"></div><span className="text-[8px] font-black italic text-[#8a9db8]">VS</span><div className="h-[1px] flex-1 bg-white"></div></div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>
            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input type="text" value={matchRoomIds[m.id] || ''} onChange={(e) => { const val = e.target.value.replace(/\D/g,'').slice(0,4); setMatchRoomIds(prev => ({ ...prev, [m.id]: val })); }} className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" placeholder="----" />
                        </div>
                        {!isDone && m.teamA && m.teamB && <Button onClick={() => startMatchFlow(m.id)} disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} size="sm" className="h-[28px] text-[8px] px-3">START</Button>}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = useMemo(() => {
    const data = allMatches.find(m => m.id === currentMatchIdx);
    if (!data) return undefined;

    // BO3 SIDE SWAP LOGIC FOR GRAND FINAL
    // Game 1: Standard
    // Game 2: Swap Sides
    // Game 3: Standard
    if (data.label === 'GRAND FINAL') {
        const sA = scores[`${currentMatchIdx}-A`] || 0;
        const sB = scores[`${currentMatchIdx}-B`] || 0;
        const gamesPlayed = sA + sB;

        // If total games played is odd (i.e. we are entering Game 2), SWAP TEAMS
        if (gamesPlayed % 2 !== 0) {
            return {
                ...data,
                teamA: data.teamB, // Original Team B becomes Azure (A)
                teamB: data.teamA  // Original Team A becomes Crimson (B)
            };
        }
    }
    return data;
  }, [allMatches, currentMatchIdx, scores]);

  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const handleNextReveal = () => {
    if (!activeMatchData) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    const side = revealedSlots.has(azureId) ? 'crimson' : 'azure';

    // Determine which team in the original bracket structure this corresponds to
    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    // Find the index of this team in the original match.teams array
    const originalTeamIndex = match.teams.findIndex(t => t.name === teamData?.name);

    if (originalTeamIndex === -1) return;

    // Check if player already assigned
    let winner = getAssignedPlayer(originalTeamIndex, role);

    // JUST IN TIME ASSIGNMENT
    if (winner.id === 'tbd') {
        const currentlyAssignedIds = new Set(Object.values(globalAssignments));
        const availablePlayers = activePlayers.filter(p => !currentlyAssignedIds.has(p.id));

        // Pick a random valid player
        const pickedPlayer = getFlexibleCandidate(availablePlayers, role);

        if (pickedPlayer) {
            winner = pickedPlayer;
            // Lock them in
            const key = `${originalTeamIndex}-${role}`;
            setGlobalAssignments(prev => ({ ...prev, [key]: pickedPlayer.id }));
        } else {
            // Should rarely happen if pool is sufficient, but handle gracefully?
            // For now, if no player found, it stays TBD (or we could force a random fill ignoring roles)
            console.warn("No valid player found for", role);
        }
    }

    const revealedPlayerIds = new Set<string>();
    // Collect revealed IDs just for the wheel visual exclusion, if needed

    const candidates = activePlayers.filter(p => {
        // Filter out players already assigned to OTHER slots
        const assignedToOtherSlot = Object.entries(globalAssignments).some(([k, pid]) => k !== `${originalTeamIndex}-${role}` && pid === p.id);
        if (assignedToOtherSlot) return false;

        return canPlay(p, role);
    });

    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);
    const randomDuration = Math.floor(Math.random() * (9000 - 4500 + 1)) + 4500;

    setWheelState({ 
        isOpen: true, 
        type: 'reveal', 
        team: side, 
        role: role, 
        winnerName: winner.name, 
        winnerPlayer: winner, // Pass the player object
        candidates: candidateNames, 
        duration: randomDuration 
    });
  };

  const handleSkipAll = () => {
    // Greedy fill for the CURRENT MATCH only
    if (!activeMatchData) return;

    const newAssignments: Record<string, string> = {};
    const usedIds = new Set(Object.values(globalAssignments));

    const fillTeam = (teamName: string) => {
        const teamIdx = match.teams.findIndex(t => t.name === teamName);
        if (teamIdx === -1) return;

        ROLES_ORDER.forEach(role => {
            const key = `${teamIdx}-${role}`;
            if (globalAssignments[key]) return; // Already assigned

            // Find candidate
            const available = activePlayers.filter(p => !usedIds.has(p.id));
            const picked = getFlexibleCandidate(available, role);

            if (picked) {
                newAssignments[key] = picked.id;
                usedIds.add(picked.id);
            }
        });
    };

    if (activeMatchData.teamA) fillTeam(activeMatchData.teamA.name);
    if (activeMatchData.teamB) fillTeam(activeMatchData.teamB.name);

    setGlobalAssignments(prev => ({ ...prev, ...newAssignments }));

    const allCards = new Set<string>();
    ROLES_ORDER.forEach(r => { allCards.add(`m${currentMatchIdx}-A-${r}`); allCards.add(`m${currentMatchIdx}-B-${r}`); });
    setRevealedSlots(allCards);
    setCurrentRoleIdx(ROLES_ORDER.length - 1);

    // Mark as completed so we don't need to spin again
    setCompletedReveals(prev => new Set(prev).add(currentMatchIdx));
  };

  const handleRerollClick = (side: 'azure' | 'crimson', role: Role) => {
    const teamData = side === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    if (!teamData) return;
    const teamIndex = match.teams.findIndex(t => t.name === teamData.name);
    if (teamIndex === -1) return;

    // Filter candidates from unassigned players
    const currentlyAssignedIds = new Set(Object.values(globalAssignments));
    const benchPlayers = activePlayers.filter(p => !currentlyAssignedIds.has(p.id));

    if (benchPlayers.length === 0) return;

    const candidates = benchPlayers.filter(p => canPlay(p, role));
    if (candidates.length === 0) return;

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const randomDuration = Math.floor(Math.random() * (8000 - 4000 + 1)) + 4000;

    setWheelState({ 
        isOpen: true, 
        type: 'reroll', 
        team: side, 
        role: role, 
        winnerName: newPlayer.name, 
        winnerPlayer: newPlayer, 
        candidates: candidates.map(p => p.name), 
        duration: randomDuration 
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
        const { team, role, winnerPlayer } = wheelState;

        // Ensure assignment is recorded (in case it wasn't pre-filled logic)
        if (winnerPlayer && activeMatchData) {
             const teamData = team === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
             const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
             if (teamIdx !== -1) {
                 const key = `${teamIdx}-${role}`;
                 setGlobalAssignments(prev => ({ ...prev, [key]: winnerPlayer.id }));
             }
        }

        const id = `m${currentMatchIdx}-${team === 'azure' ? 'A' : 'B'}-${role}`;
        setRevealedSlots(prev => new Set(prev).add(id));
        if (team === 'crimson') {
            const nextIdx = currentRoleIdx + 1;
            setCurrentRoleIdx(nextIdx);

            // Check if this was the final reveal for the match
            if (nextIdx >= ROLES_ORDER.length) {
                setCompletedReveals(prev => new Set(prev).add(currentMatchIdx));
            }
        }
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        const teamData = wheelState.team === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
        if (teamData) {
            const idx = match.teams.findIndex(t => t.name === teamData.name);
            if (idx !== -1) {
                // Update Global Assignments directly
                const key = `${idx}-${wheelState.role}`;
                setGlobalAssignments(prev => ({ ...prev, [key]: wheelState.winnerPlayer!.id }));
            }
        }
    }
    setWheelState(null);
  };

  // Rename Logic
  const openRenameModal = (player: Player) => {
    setRenameState({ isOpen: true, player, newName: player.name });
  };

  const submitRename = () => {
    if (renameState.player && renameState.newName.trim()) {
        onUpdatePlayer({ ...renameState.player, name: renameState.newName.trim() });
        setRenameState({ isOpen: false, player: null, newName: '' });
    }
  };

  const renderPlayerCard = (role: Role, teamSide: 'azure' | 'crimson') => {
    const teamData = teamSide === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    // Find dynamic player based on assignment
    const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
    const player = teamIdx !== -1 ? getAssignedPlayer(teamIdx, role) : TBD_PLAYER;

    const id = `m${currentMatchIdx}-${teamSide === 'azure' ? 'A' : 'B'}-${role}`;
    if (!revealedSlots.has(id)) return <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group"><div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">{RoleIcons[role]}</div></div>;

    const theme = teamSide === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' } : { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#ef4444]/20 to-transparent' };

    return (
        <div className="relative h-16 w-full animate-slide-in perspective-container group">
            <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
                <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
                    <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${teamSide === 'crimson' ? 'right' : 'left'} opacity-90`}>{RoleIcons[role]}</div>
                    <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">{player.name}</span>
                    <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
                </div>

                <div className={`absolute top-2 z-50 flex gap-2 transition-all opacity-0 group-hover:opacity-100 ${teamSide === 'azure' ? 'right-4' : 'left-4'}`}>
                   {/* Reroll Button */}
                   <button 
                      onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role); }} 
                      className="p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full text-white hover:text-black transition-all"
                      title="Reroll Player"
                   >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                      </svg>
                   </button>

                   {/* Edit Name Button */}
                   <button 
                      onClick={(e) => { e.stopPropagation(); if(player) openRenameModal(player); }} 
                      className="p-2.5 bg-black/60 hover:bg-[#00d2ff] rounded-full text-white hover:text-black transition-all"
                      title="Change Nickname"
                   >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                      </svg>
                   </button>
                </div>
            </div>
        </div>
    );
  };

  // --- CHAMPION VICTORY SCREEN RENDERER ---
  const renderTournamentEnd = () => {
    return (
      <div className="fixed inset-0 z-[300] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
        {/* Automatic Music Background */}
        <iframe 
            width="0" 
            height="0" 
            src="https://www.youtube.com/embed/13ARO0HDZsQ?autoplay=1&loop=1&playlist=13ARO0HDZsQ" 
            frameBorder="0" 
            allow="autoplay" 
            className="hidden pointer-events-none"
        ></iframe>

        {/* Visual Background Effects */}
        <div className="god-rays opacity-40"></div>
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#05090f_90%)] z-10"></div>

        {/* Floating Embers / Confetti */}
        {Array.from({ length: 40 }).map((_, i) => (
          <div 
            key={i} 
            className="confetti-piece"
            style={{
              left: `${Math.random() * 100}%`,
              animationDelay: `${Math.random() * 5}s`,
              backgroundColor: Math.random() > 0.5 ? '#dcb06b' : '#ffffff',
              zIndex: 20
            }}
          ></div>
        ))}

        <div className="relative z-20 flex flex-col items-center animate-trophy-pop w-full max-w-4xl">
            <h3 className="text-[#dcb06b] font-orbitron font-black tracking-[0.8em] text-sm uppercase mb-4 animate-pulse opacity-80">
                TOURNAMENT CONCLUDED
            </h3>

            <h1 className="text-5xl md:text-8xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-[#dcb06b] mb-12 tracking-[0.2em] drop-shadow-[0_10px_30px_rgba(220,176,107,0.4)] text-center px-4">
                TOURNAMENT CHAMPIONS
            </h1>

            <div className="bg-[#0a1a2f]/80 border-4 border-[#dcb06b] px-12 md:px-24 py-10 clip-corner-md shadow-[0_0_100px_rgba(220,176,107,0.3)] relative overflow-hidden group mb-12 transform hover:scale-105 transition-transform duration-500">
                <div className="absolute inset-0 bg-gradient-to-br from-[#dcb06b]/10 to-transparent opacity-50"></div>
                <h2 className="text-6xl md:text-9xl font-black font-cinzel text-white text-center drop-shadow-[0_0_20px_#dcb06b]" style={{ color: tournamentChampion?.color || '#fff' }}>
                    {tournamentChampion?.name}
                </h2>
            </div>

            {/* Champions Roster Display */}
            <div className="grid grid-cols-2 md:grid-cols-5 gap-4 w-full px-6 mb-16">
               {tournamentChampion?.slots.map((slot: TeamSlot, idx: number) => (
                  <div 
                    key={idx} 
                    className="flex flex-col items-center p-4 bg-black/40 border border-[#dcb06b]/40 clip-corner-sm backdrop-blur-md transform transition-all duration-700 hover:border-[#dcb06b] hover:bg-[#dcb06b]/5 animate-slide-in"
                    style={{ animationDelay: `${idx * 150}ms` }}
                  >
                     <div className="text-[#dcb06b] mb-2 opacity-70 scale-90">
                        {RoleIcons[slot.role]}
                     </div>
                     <span className="text-white font-orbitron font-black text-sm md:text-base tracking-widest truncate max-w-full">
                        {slot.player.name}
                     </span>
                  </div>
               ))}
            </div>

            <Button onClick={onReset} size="lg" className="px-24 h-20 text-xl shadow-[0_0_50px_rgba(220,176,107,0.5)]">
                RETURN TO LOBBY
            </Button>
        </div>
      </div>
    );
  };

  if (phase === 'TOURNAMENT_END') return renderTournamentEnd();
  if (phase === 'TRANSITION' && activeMatchData) return <PortalTransition azureTeam={activeMatchData.teamA?.slots || []} crimsonTeam={activeMatchData.teamB?.slots || []} onComplete={() => setPhase('DECLARE_WIN')} />;
  if (phase === 'DECLARE_WIN' && activeMatchData) return <MatchSummary match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) return <VictoryCelebration winner={currentRoundWinner} teamSlots={(currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots) || []} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) return <EvaluationScreen match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <ConfirmModal 
        isOpen={showAbortConfirm}
        title="ABORT TOURNAMENT"
        message="Are you sure you want to end the tournament? All progress will be lost."
        onConfirm={onReset}
        onCancel={() => setShowAbortConfirm(false)}
        isDestructive={true}
      />

      {/* RENAME MODAL */}
      {renameState.isOpen && (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })}></div>
            <div className="relative w-full max-w-sm bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md shadow-[0_0_30px_rgba(220,176,107,0.3)] animate-slide-in p-6">
                <h3 className="text-[#dcb06b] font-cinzel font-bold text-lg mb-4 text-center tracking-widest">CHANGE NICKNAME</h3>
                <input 
                    type="text" 
                    value={renameState.newName} 
                    onChange={e => setRenameState({ ...renameState, newName: e.target.value })} 
                    className="w-full bg-black/50 border border-[#1e3a5f] p-3 text-white font-orbitron focus:border-[#dcb06b] outline-none mb-6 text-center"
                    autoFocus
                />
                <div className="flex gap-3">
                    <Button variant="secondary" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })} className="flex-1">CANCEL</Button>
                    <Button onClick={submitRename} className="flex-1">CONFIRM</Button>
                </div>
            </div>
        </div>
      )}

      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>
      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16"><h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1><p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p></div>
          <div className="flex gap-24 md:gap-40 items-center justify-center relative py-20">

            {/* COLUMN 1: QUARTER FINALS */}
            {hasQuarterFinals && (
              <div className="flex flex-col gap-16 relative">
                {quarterMatches.map((m, i) => (
                  <div key={m.id} className="relative">
                    {renderBracketMatchCard(m)}
                    {/* Connector logic */}
                    {match.teams.length === 5 || match.teams.length === 6 ? (
                      // Specialized layout for 5/6 teams: QF1 & QF2 fork to SF1, QF3 straight to SF2 (Team 5/6 flow)
                      i < 2 ? (i === 0 && <EnergyConnector type="fork" height={274} />) : <EnergyConnector type="straight" height={0} />
                    ) : (
                      i % 2 === 0 && <EnergyConnector type="fork" height={322} />
                    )}
                  </div>
                ))}
              </div>
            )}

            {/* COLUMN 2: SEMI FINALS */}
            <div className={`flex flex-col gap-32 relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {/* Fork to Grand Final */}
                  {i === 0 && <EnergyConnector type="fork" height={338} />}
                </div>
              ))}
            </div>

            {/* COLUMN 3: GRAND FINAL */}
            <div className={`relative scale-125 ml-10`}>{renderBracketMatchCard(grandFinalMatch)}</div>
          </div>
          <button onClick={() => setShowAbortConfirm(true)} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState && wheelState.isOpen && <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} team={wheelState.team} roleName={wheelState.role} roomId={activeRoomId} duration={wheelState.duration} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}
            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center"><Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">BACK TO BRACKET</Button><div className="flex flex-col items-center gap-0 scale-[0.85] origin-top"><span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1 opacity-70">ROOM ID</span><div className="relative"><div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div><div className="relative bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]"><span className="text-2xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b]">{activeRoomId}</span></div></div></div>{revealedSlots.size < 10 ? <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">SKIP ALL</Button> : <div className="w-[120px]"></div>}</div>
            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6"><div className="text-left"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-cyan-600 tracking-widest drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]" style={{ color: activeMatchData?.teamA?.color }}>{activeMatchData?.teamA?.name.split(' ')[0]} <span className="hidden md:inline">{activeMatchData?.teamA?.name.split(' ')[1] || 'GOLEM'}</span></h2><div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div></div><div className="text-right"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-100 to-red-600 tracking-widest drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]" style={{ color: activeMatchData?.teamB?.color }}><span className="hidden md:inline">{activeMatchData?.teamB?.name.split(' ')[0] || 'CRIMSON'}</span> {activeMatchData?.teamB?.name.split(' ')[1] || 'GOLEM'}</h2><div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div></div></div>
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20"><span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span></div>
                <div className="space-y-4 relative z-10">{ROLES_ORDER.map((role) => <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center"><div>{renderPlayerCard(role, 'azure')}</div><div>{renderPlayerCard(role, 'crimson')}</div></div>)}</div>
            </div>
            <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none"><div className="pointer-events-auto">{revealedSlots.size < 10 ? <button onClick={handleNextReveal} className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]">{revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`}</button> : <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">INITIALIZE BATTLE</Button>}</div></div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';
import { ConfirmModal } from './ConfirmModal';
import { getFlexibleCandidate, canPlay, TBD_PLAYER } from '../utils/matchmaker';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
  onUpdatePlayer: (updatedPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll, onUpdatePlayer }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // GLOBAL ASSIGNMENT TRACKING
  // Maps "teamIndex-role" string to Player ID
  const [globalAssignments, setGlobalAssignments] = useState<Record<string, string>>({});

  // State for Abort Confirmation
  const [showAbortConfirm, setShowAbortConfirm] = useState(false);

  // Rename State
  const [renameState, setRenameState] = useState<{ isOpen: boolean; player: Player | null; newName: string }>({
    isOpen: false,
    player: null,
    newName: ''
  });

  // State to track matches that have been fully revealed/spun
  const [completedReveals, setCompletedReveals] = useState<Set<number>>(new Set());

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // Helper to get the actual assigned player or TBD
  const getAssignedPlayer = useCallback((teamIdx: number, role: Role): Player => {
      const key = `${teamIdx}-${role}`;
      const pid = globalAssignments[key];
      if (pid) {
          return activePlayers.find(p => p.id === pid) || TBD_PLAYER;
      }
      return TBD_PLAYER;
  }, [globalAssignments, activePlayers]);

  // --- MEMOIZED BRACKET GENERATION ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const getTeamObj = (teamIndex: number) => {
          if (teamIndex < 0 || teamIndex >= match.teams.length) return null;
          const original = match.teams[teamIndex];
          // Reconstruct team with current assignments
          const updatedSlots = original.slots.map(s => ({
              ...s,
              player: getAssignedPlayer(teamIndex, s.role)
          }));
          return { ...original, slots: updatedSlots };
      };

      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const getLoserTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA || !teamB) return null;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > 0 || scoreB > 0) {
            if (scoreA < scoreB) return teamA;
            if (scoreB < scoreA) return teamB;
        }
        return null;
      };

      const numTeams = match.teams.length;

      // Case 1: 3 teams (Stepladder)
      if (numTeams === 3) {
        const m0 = { id: 0, label: 'ELIMINATION', mode: 'BO1', teamA: getTeamObj(0), teamB: getTeamObj(1) };
        const m1 = { id: 1, label: 'CHALLENGER', mode: 'BO1', teamA: getLoserTeam(0, m0.teamA, m0.teamB), teamB: getTeamObj(2) };
        const m2 = { id: 2, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, m0.teamA, m0.teamB), teamB: getWinnerTeam(1, m1.teamA, m1.teamB) };
        return { quarterMatches: [], semiMatches: [m0, m1], grandFinalMatch: m2, allMatches: [m0, m1, m2], hasQuarterFinals: false };
      }

      // Case 2: 5 or 6 teams (Challenger Style)
      if (numTeams === 5 || numTeams === 6) {
        const q0 = { id: 0, label: 'QUARTER 1', mode: 'BO1', teamA: getTeamObj(0), teamB: getTeamObj(1) };
        const q1 = { id: 1, label: 'QUARTER 2', mode: 'BO1', teamA: getTeamObj(2), teamB: getTeamObj(3) };
        const q2 = { id: 2, label: 'QUARTER 3', mode: 'BO1', teamA: getTeamObj(4), teamB: getTeamObj(5) || null };

        const s1 = { id: 3, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(0, q0.teamA, q0.teamB), teamB: getWinnerTeam(1, q1.teamA, q1.teamB) };
        const s2 = { id: 4, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(2, q2.teamA, q2.teamB), teamB: getLoserTeam(3, s1.teamA, s1.teamB) };

        const gf = { id: 5, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(3, s1.teamA, s1.teamB), teamB: getWinnerTeam(4, s2.teamA, s2.teamB) };

        return { 
          quarterMatches: [q0, q1, q2], 
          semiMatches: [s1, s2], 
          grandFinalMatch: gf, 
          allMatches: [q0, q1, q2, s1, s2, gf], 
          hasQuarterFinals: true 
        };
      }

      // Case 3: 4, 8 teams
      const hasQuarterFinals = numTeams === 8;
      const qMatches: any[] = [];
      if (numTeams === 8) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({ id: i, label: `QUARTER ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
      }

      const sMatches: any[] = [];
      if (numTeams === 8) {
          sMatches.push({ id: 4, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(0, qMatches[0].teamA, qMatches[0].teamB), teamB: getWinnerTeam(1, qMatches[1].teamA, qMatches[1].teamB) });
          sMatches.push({ id: 5, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(2, qMatches[2].teamA, qMatches[2].teamB), teamB: getWinnerTeam(3, qMatches[3].teamA, qMatches[3].teamB) });
      } else {
          // 4 teams
          for (let i = 0; i < 2; i++) {
              sMatches.push({ id: i, label: `SEMI FINAL ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
      }

      const gfIndex = numTeams === 8 ? 6 : 2;
      const gf = { id: gfIndex, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB), teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB) };
      return { quarterMatches: qMatches, semiMatches: sMatches, grandFinalMatch: gf, allMatches: [...qMatches, ...sMatches, gf], hasQuarterFinals };
  }, [match, scores, globalAssignments, getAssignedPlayer]); 

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);
    if (m && !m.teamB) {
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }
    setCurrentMatchIdx(idx);

    const numTeams = match.teams.length;
    let shouldEnableRolling = false;

    // RULE: Rolling is enabled for the FIRST ROUND of matches to assign the initial roster.
    // For 8 Teams: Quarter Finals (0, 1, 2, 3)
    // For 5/6 Teams: Quarter Finals (0, 1, 2)
    // For 4 Teams: Semi Finals (0, 1) are the first round.
    // For 3 Teams: Elimination (0) and Challenger (1) are the first rounds.

    if (numTeams === 3 || numTeams === 4) {
        if (idx === 0 || idx === 1) {
            shouldEnableRolling = true;
        }
    } else {
        // Standard check for larger brackets
        shouldEnableRolling = quarterMatches.some(q => q.id === idx);
    }

    if (idx === grandFinalMatch.id) {
        setPhase('TRANSITION');
    } else {
        setPhase('REVEAL');

        // If it is NOT a "Rolling Match" (e.g. later stages), OR if it's already completed in the past:
        // We simulate "Skip All" immediately.
        if (!shouldEnableRolling || completedReveals.has(idx)) {
            const allCards = new Set<string>();
            ROLES_ORDER.forEach(r => { 
                allCards.add(`m${idx}-A-${r}`); 
                allCards.add(`m${idx}-B-${r}`); 
            });
            setRevealedSlots(allCards);
            setCurrentRoleIdx(ROLES_ORDER.length - 1);
            setCompletedReveals(prev => new Set(prev).add(idx));
        } else {
            // It IS a First Round Match and NOT completed -> Enable Rolling (Start empty)
            setRevealedSlots(new Set());
            setCurrentRoleIdx(-1);
        }
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;
     let newScoreA = currentScoreA + (currentRoundWinner === 'azure' ? 1 : 0);
     let newScoreB = currentScoreB + (currentRoundWinner === 'crimson' ? 1 : 0);

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const EnergyConnector = ({ type, height, style }: { type: 'fork' | 'straight', height: number, style?: React.CSSProperties }) => (
    <div 
        className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" 
        style={{ height: `${height}px`, ...style }}
    >
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3" result="blur"/>
                <feComposite in="SourceGraphic" in2="blur" operator="over"/>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path 
                d={`M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          ) : (
             <path 
                d={`M 0,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          )}
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,${height/2} L 100,${height/2}`} dur="2s" repeatCount="indefinite" />
          </circle>
          {type === 'fork' && (
            <circle r="3" fill="#fff" filter="url(#energyGlow)">
                <animateMotion path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} dur="2s" begin="1s" repeatCount="indefinite" />
            </circle>
          )}
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;
      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';
      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-md p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>
            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>
                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1"><div className="h-[1px] flex-1 bg-white"></div><span className="text-[8px] font-black italic text-[#8a9db8]">VS</span><div className="h-[1px] flex-1 bg-white"></div></div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>
            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input type="text" value={matchRoomIds[m.id] || ''} onChange={(e) => { const val = e.target.value.replace(/\D/g,'').slice(0,4); setMatchRoomIds(prev => ({ ...prev, [m.id]: val })); }} className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" placeholder="----" />
                        </div>
                        {!isDone && m.teamA && m.teamB && <Button onClick={() => startMatchFlow(m.id)} disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} size="sm" className="h-[28px] text-[8px] px-3">START</Button>}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = useMemo(() => {
    const data = allMatches.find(m => m.id === currentMatchIdx);
    if (!data) return undefined;

    // BO3 SIDE SWAP LOGIC FOR GRAND FINAL
    // Game 1: Standard
    // Game 2: Swap Sides
    // Game 3: Standard
    if (data.label === 'GRAND FINAL') {
        const sA = scores[`${currentMatchIdx}-A`] || 0;
        const sB = scores[`${currentMatchIdx}-B`] || 0;
        const gamesPlayed = sA + sB;

        // If total games played is odd (i.e. we are entering Game 2), SWAP TEAMS
        if (gamesPlayed % 2 !== 0) {
            return {
                ...data,
                teamA: data.teamB, // Original Team B becomes Azure (A)
                teamB: data.teamA  // Original Team A becomes Crimson (B)
            };
        }
    }
    return data;
  }, [allMatches, currentMatchIdx, scores]);

  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const handleNextReveal = () => {
    if (!activeMatchData) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    const side = revealedSlots.has(azureId) ? 'crimson' : 'azure';

    // Determine which team in the original bracket structure this corresponds to
    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    // Find the index of this team in the original match.teams array
    const originalTeamIndex = match.teams.findIndex(t => t.name === teamData?.name);

    if (originalTeamIndex === -1) return;

    // Check if player already assigned
    let winner = getAssignedPlayer(originalTeamIndex, role);

    // JUST IN TIME ASSIGNMENT
    if (winner.id === 'tbd') {
        const currentlyAssignedIds = new Set(Object.values(globalAssignments));
        const availablePlayers = activePlayers.filter(p => !currentlyAssignedIds.has(p.id));

        // Pick a random valid player
        const pickedPlayer = getFlexibleCandidate(availablePlayers, role);

        if (pickedPlayer) {
            winner = pickedPlayer;
            // Lock them in
            const key = `${originalTeamIndex}-${role}`;
            setGlobalAssignments(prev => ({ ...prev, [key]: pickedPlayer.id }));
        } else {
            // Should rarely happen if pool is sufficient, but handle gracefully?
            // For now, if no player found, it stays TBD (or we could force a random fill ignoring roles)
            console.warn("No valid player found for", role);
        }
    }

    const revealedPlayerIds = new Set<string>();
    // Collect revealed IDs just for the wheel visual exclusion, if needed

    const candidates = activePlayers.filter(p => {
        // Filter out players already assigned to OTHER slots
        const assignedToOtherSlot = Object.entries(globalAssignments).some(([k, pid]) => k !== `${originalTeamIndex}-${role}` && pid === p.id);
        if (assignedToOtherSlot) return false;

        return canPlay(p, role);
    });

    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);
    const randomDuration = Math.floor(Math.random() * (9000 - 4500 + 1)) + 4500;

    setWheelState({ 
        isOpen: true, 
        type: 'reveal', 
        team: side, 
        role: role, 
        winnerName: winner.name, 
        winnerPlayer: winner, // Pass the player object
        candidates: candidateNames, 
        duration: randomDuration 
    });
  };

  const handleSkipAll = () => {
    // Greedy fill for the CURRENT MATCH only
    if (!activeMatchData) return;

    const newAssignments: Record<string, string> = {};
    const usedIds = new Set(Object.values(globalAssignments));

    const fillTeam = (teamName: string) => {
        const teamIdx = match.teams.findIndex(t => t.name === teamName);
        if (teamIdx === -1) return;

        ROLES_ORDER.forEach(role => {
            const key = `${teamIdx}-${role}`;
            if (globalAssignments[key]) return; // Already assigned

            // Find candidate
            const available = activePlayers.filter(p => !usedIds.has(p.id));
            const picked = getFlexibleCandidate(available, role);

            if (picked) {
                newAssignments[key] = picked.id;
                usedIds.add(picked.id);
            }
        });
    };

    if (activeMatchData.teamA) fillTeam(activeMatchData.teamA.name);
    if (activeMatchData.teamB) fillTeam(activeMatchData.teamB.name);

    setGlobalAssignments(prev => ({ ...prev, ...newAssignments }));

    const allCards = new Set<string>();
    ROLES_ORDER.forEach(r => { allCards.add(`m${currentMatchIdx}-A-${r}`); allCards.add(`m${currentMatchIdx}-B-${r}`); });
    setRevealedSlots(allCards);
    setCurrentRoleIdx(ROLES_ORDER.length - 1);

    // Mark as completed so we don't need to spin again
    setCompletedReveals(prev => new Set(prev).add(currentMatchIdx));
  };

  const handleRerollClick = (side: 'azure' | 'crimson', role: Role) => {
    const teamData = side === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    if (!teamData) return;
    const teamIndex = match.teams.findIndex(t => t.name === teamData.name);
    if (teamIndex === -1) return;

    // Filter candidates from unassigned players
    const currentlyAssignedIds = new Set(Object.values(globalAssignments));
    const benchPlayers = activePlayers.filter(p => !currentlyAssignedIds.has(p.id));

    if (benchPlayers.length === 0) return;

    const candidates = benchPlayers.filter(p => canPlay(p, role));
    if (candidates.length === 0) return;

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const randomDuration = Math.floor(Math.random() * (8000 - 4000 + 1)) + 4000;

    setWheelState({ 
        isOpen: true, 
        type: 'reroll', 
        team: side, 
        role: role, 
        winnerName: newPlayer.name, 
        winnerPlayer: newPlayer, 
        candidates: candidates.map(p => p.name), 
        duration: randomDuration 
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
        const { team, role, winnerPlayer } = wheelState;

        // Ensure assignment is recorded (in case it wasn't pre-filled logic)
        if (winnerPlayer && activeMatchData) {
             const teamData = team === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
             const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
             if (teamIdx !== -1) {
                 const key = `${teamIdx}-${role}`;
                 setGlobalAssignments(prev => ({ ...prev, [key]: winnerPlayer.id }));
             }
        }

        const id = `m${currentMatchIdx}-${team === 'azure' ? 'A' : 'B'}-${role}`;
        setRevealedSlots(prev => new Set(prev).add(id));
        if (team === 'crimson') {
            const nextIdx = currentRoleIdx + 1;
            setCurrentRoleIdx(nextIdx);

            // Check if this was the final reveal for the match
            if (nextIdx >= ROLES_ORDER.length) {
                setCompletedReveals(prev => new Set(prev).add(currentMatchIdx));
            }
        }
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        const teamData = wheelState.team === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
        if (teamData) {
            const idx = match.teams.findIndex(t => t.name === teamData.name);
            if (idx !== -1) {
                // Update Global Assignments directly
                const key = `${idx}-${wheelState.role}`;
                setGlobalAssignments(prev => ({ ...prev, [key]: wheelState.winnerPlayer!.id }));
            }
        }
    }
    setWheelState(null);
  };

  // Rename Logic
  const openRenameModal = (player: Player) => {
    setRenameState({ isOpen: true, player, newName: player.name });
  };

  const submitRename = () => {
    if (renameState.player && renameState.newName.trim()) {
        onUpdatePlayer({ ...renameState.player, name: renameState.newName.trim() });
        setRenameState({ isOpen: false, player: null, newName: '' });
    }
  };

  const renderPlayerCard = (role: Role, teamSide: 'azure' | 'crimson') => {
    const teamData = teamSide === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    // Find dynamic player based on assignment
    const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
    const player = teamIdx !== -1 ? getAssignedPlayer(teamIdx, role) : TBD_PLAYER;

    const id = `m${currentMatchIdx}-${teamSide === 'azure' ? 'A' : 'B'}-${role}`;
    if (!revealedSlots.has(id)) return <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group"><div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">{RoleIcons[role]}</div></div>;

    const theme = teamSide === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' } : { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#ef4444]/20 to-transparent' };

    return (
        <div className="relative h-16 w-full animate-slide-in perspective-container group">
            <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
                <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
                    <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${teamSide === 'crimson' ? 'right' : 'left'} opacity-90`}>{RoleIcons[role]}</div>
                    <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">{player.name}</span>
                    <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
                </div>

                <div className={`absolute top-2 z-50 flex gap-2 transition-all opacity-0 group-hover:opacity-100 ${teamSide === 'azure' ? 'right-4' : 'left-4'}`}>
                   {/* Reroll Button */}
                   <button 
                      onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role); }} 
                      className="p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full text-white hover:text-black transition-all"
                      title="Reroll Player"
                   >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                      </svg>
                   </button>

                   {/* Edit Name Button */}
                   <button 
                      onClick={(e) => { e.stopPropagation(); if(player) openRenameModal(player); }} 
                      className="p-2.5 bg-black/60 hover:bg-[#00d2ff] rounded-full text-white hover:text-black transition-all"
                      title="Change Nickname"
                   >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                      </svg>
                   </button>
                </div>
            </div>
        </div>
    );
  };

  // --- CHAMPION VICTORY SCREEN RENDERER ---
  const renderTournamentEnd = () => {
    return (
      <div className="fixed inset-0 z-[300] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
        {/* Automatic Music Background */}
        <iframe 
            width="0" 
            height="0" 
            src="https://www.youtube.com/embed/13ARO0HDZsQ?autoplay=1&loop=1&playlist=13ARO0HDZsQ" 
            frameBorder="0" 
            allow="autoplay" 
            className="hidden pointer-events-none"
        ></iframe>

        {/* Visual Background Effects */}
        <div className="god-rays opacity-40"></div>
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#05090f_90%)] z-10"></div>

        {/* Floating Embers / Confetti */}
        {Array.from({ length: 40 }).map((_, i) => (
          <div 
            key={i} 
            className="confetti-piece"
            style={{
              left: `${Math.random() * 100}%`,
              animationDelay: `${Math.random() * 5}s`,
              backgroundColor: Math.random() > 0.5 ? '#dcb06b' : '#ffffff',
              zIndex: 20
            }}
          ></div>
        ))}

        <div className="relative z-20 flex flex-col items-center animate-trophy-pop w-full max-w-4xl">
            <h3 className="text-[#dcb06b] font-orbitron font-black tracking-[0.8em] text-sm uppercase mb-4 animate-pulse opacity-80">
                TOURNAMENT CONCLUDED
            </h3>

            <h1 className="text-5xl md:text-8xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-[#dcb06b] mb-12 tracking-[0.2em] drop-shadow-[0_10px_30px_rgba(220,176,107,0.4)] text-center px-4">
                TOURNAMENT CHAMPIONS
            </h1>

            <div className="bg-[#0a1a2f]/80 border-4 border-[#dcb06b] px-12 md:px-24 py-10 clip-corner-md shadow-[0_0_100px_rgba(220,176,107,0.3)] relative overflow-hidden group mb-12 transform hover:scale-105 transition-transform duration-500">
                <div className="absolute inset-0 bg-gradient-to-br from-[#dcb06b]/10 to-transparent opacity-50"></div>
                <h2 className="text-6xl md:text-9xl font-black font-cinzel text-white text-center drop-shadow-[0_0_20px_#dcb06b]" style={{ color: tournamentChampion?.color || '#fff' }}>
                    {tournamentChampion?.name}
                </h2>
            </div>

            {/* Champions Roster Display */}
            <div className="grid grid-cols-2 md:grid-cols-5 gap-4 w-full px-6 mb-16">
               {tournamentChampion?.slots.map((slot: TeamSlot, idx: number) => (
                  <div 
                    key={idx} 
                    className="flex flex-col items-center p-4 bg-black/40 border border-[#dcb06b]/40 clip-corner-sm backdrop-blur-md transform transition-all duration-700 hover:border-[#dcb06b] hover:bg-[#dcb06b]/5 animate-slide-in"
                    style={{ animationDelay: `${idx * 150}ms` }}
                  >
                     <div className="text-[#dcb06b] mb-2 opacity-70 scale-90">
                        {RoleIcons[slot.role]}
                     </div>
                     <span className="text-white font-orbitron font-black text-sm md:text-base tracking-widest truncate max-w-full">
                        {slot.player.name}
                     </span>
                  </div>
               ))}
            </div>

            <Button onClick={onReset} size="lg" className="px-24 h-20 text-xl shadow-[0_0_50px_rgba(220,176,107,0.5)]">
                RETURN TO LOBBY
            </Button>
        </div>
      </div>
    );
  };

  if (phase === 'TOURNAMENT_END') return renderTournamentEnd();
  if (phase === 'TRANSITION' && activeMatchData) return <PortalTransition azureTeam={activeMatchData.teamA?.slots || []} crimsonTeam={activeMatchData.teamB?.slots || []} onComplete={() => setPhase('DECLARE_WIN')} />;
  if (phase === 'DECLARE_WIN' && activeMatchData) return <MatchSummary match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) return <VictoryCelebration winner={currentRoundWinner} teamSlots={(currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots) || []} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) return <EvaluationScreen match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <ConfirmModal 
        isOpen={showAbortConfirm}
        title="ABORT TOURNAMENT"
        message="Are you sure you want to end the tournament? All progress will be lost."
        onConfirm={onReset}
        onCancel={() => setShowAbortConfirm(false)}
        isDestructive={true}
      />

      {/* RENAME MODAL */}
      {renameState.isOpen && (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })}></div>
            <div className="relative w-full max-w-sm bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md shadow-[0_0_30px_rgba(220,176,107,0.3)] animate-slide-in p-6">
                <h3 className="text-[#dcb06b] font-cinzel font-bold text-lg mb-4 text-center tracking-widest">CHANGE NICKNAME</h3>
                <input 
                    type="text" 
                    value={renameState.newName} 
                    onChange={e => setRenameState({ ...renameState, newName: e.target.value })} 
                    className="w-full bg-black/50 border border-[#1e3a5f] p-3 text-white font-orbitron focus:border-[#dcb06b] outline-none mb-6 text-center"
                    autoFocus
                />
                <div className="flex gap-3">
                    <Button variant="secondary" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })} className="flex-1">CANCEL</Button>
                    <Button onClick={submitRename} className="flex-1">CONFIRM</Button>
                </div>
            </div>
        </div>
      )}

      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>
      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16"><h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1><p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p></div>
          <div className="flex gap-24 md:gap-40 items-center justify-center relative py-20">

            {/* COLUMN 1: QUARTER FINALS */}
            {hasQuarterFinals && (
              <div className="flex flex-col gap-16 relative">
                {quarterMatches.map((m, i) => (
                  <div key={m.id} className="relative">
                    {renderBracketMatchCard(m)}
                    {/* Connector logic */}
                    {match.teams.length === 5 || match.teams.length === 6 ? (
                      // Specialized layout for 5/6 teams: QF1 & QF2 fork to SF1, QF3 straight to SF2 (Team 5/6 flow)
                      i < 2 ? (i === 0 && <EnergyConnector type="fork" height={274} />) : <EnergyConnector type="straight" height={0} />
                    ) : (
                      i % 2 === 0 && <EnergyConnector type="fork" height={322} />
                    )}
                  </div>
                ))}
              </div>
            )}

            {/* COLUMN 2: SEMI FINALS */}
            <div className={`flex flex-col gap-32 relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {/* Fork to Grand Final */}
                  {i === 0 && <EnergyConnector type="fork" height={338} />}
                </div>
              ))}
            </div>

            {/* COLUMN 3: GRAND FINAL */}
            <div className={`relative scale-125 ml-10`}>{renderBracketMatchCard(grandFinalMatch)}</div>
          </div>
          <button onClick={() => setShowAbortConfirm(true)} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState && wheelState.isOpen && <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} team={wheelState.team} roleName={wheelState.role} roomId={activeRoomId} duration={wheelState.duration} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}
            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center"><Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">BACK TO BRACKET</Button><div className="flex flex-col items-center gap-0 scale-[0.85] origin-top"><span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1 opacity-70">ROOM ID</span><div className="relative"><div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div><div className="relative bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]"><span className="text-2xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b]">{activeRoomId}</span></div></div></div>{revealedSlots.size < 10 ? <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">SKIP ALL</Button> : <div className="w-[120px]"></div>}</div>
            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6"><div className="text-left"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-cyan-600 tracking-widest drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]" style={{ color: activeMatchData?.teamA?.color }}>{activeMatchData?.teamA?.name.split(' ')[0]} <span className="hidden md:inline">{activeMatchData?.teamA?.name.split(' ')[1] || 'GOLEM'}</span></h2><div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div></div><div className="text-right"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-100 to-red-600 tracking-widest drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]" style={{ color: activeMatchData?.teamB?.color }}><span className="hidden md:inline">{activeMatchData?.teamB?.name.split(' ')[0] || 'CRIMSON'}</span> {activeMatchData?.teamB?.name.split(' ')[1] || 'GOLEM'}</h2><div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div></div></div>
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20"><span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span></div>
                <div className="space-y-4 relative z-10">{ROLES_ORDER.map((role) => <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center"><div>{renderPlayerCard(role, 'azure')}</div><div>{renderPlayerCard(role, 'crimson')}</div></div>)}</div>
            </div>
            <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none"><div className="pointer-events-auto">{revealedSlots.size < 10 ? <button onClick={handleNextReveal} className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]">{revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`}</button> : <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">INITIALIZE BATTLE</Button>}</div></div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useMemo, useCallback } from 'react';
import { BracketMatchResult, Role, TeamSlot, Player, MatchResult, BracketTeam } from '../types';
import { RoleIcons, ROLES_ORDER } from '../constants';
import { Button } from './Button';
import { SpinWheel } from './SpinWheel';
import { EvaluationScreen } from './EvaluationScreen';
import { MatchSummary } from './MatchSummary';
import { PortalTransition } from './PortalTransition';
import { VictoryCelebration } from './VictoryCelebration';
import { ConfirmModal } from './ConfirmModal';
import { getFlexibleCandidate, canPlay, TBD_PLAYER } from '../utils/matchmaker';

interface BracketDisplayProps {
  match: BracketMatchResult;
  onReset: () => void;
  activePlayers: Player[];
  onReroll: (teamIndex: number, role: Role, newPlayer: Player) => void;
  onUpdatePlayer: (updatedPlayer: Player) => void;
}

type BracketPhase = 'OVERVIEW' | 'REVEAL' | 'TRANSITION' | 'DECLARE_WIN' | 'CELEBRATION' | 'EVALUATION' | 'TOURNAMENT_END';

export const BracketDisplay: React.FC<BracketDisplayProps> = ({ match, onReset, activePlayers, onReroll, onUpdatePlayer }) => {
  const [phase, setPhase] = useState<BracketPhase>('OVERVIEW');
  const [currentMatchIdx, setCurrentMatchIdx] = useState(0);
  const [matchRoomIds, setMatchRoomIds] = useState<Record<number, string>>({});
  const [scores, setScores] = useState<Record<string, number>>({});
  const [matchEvaluations, setMatchEvaluations] = useState<Record<string, { mvpId?: string, ratings?: Record<string, number> }>>({});
  const [currentRoundWinner, setCurrentRoundWinner] = useState<'azure' | 'crimson' | null>(null);
  const [tournamentChampion, setTournamentChampion] = useState<any | null>(null);

  // GLOBAL ASSIGNMENT TRACKING
  // Maps "teamIndex-role" string to Player ID
  const [globalAssignments, setGlobalAssignments] = useState<Record<string, string>>({});

  // State for Abort Confirmation
  const [showAbortConfirm, setShowAbortConfirm] = useState(false);

  // Rename State
  const [renameState, setRenameState] = useState<{ isOpen: boolean; player: Player | null; newName: string }>({
    isOpen: false,
    player: null,
    newName: ''
  });

  // State to track matches that have been fully revealed/spun
  const [completedReveals, setCompletedReveals] = useState<Set<number>>(new Set());

  // State for Reveal flow
  const [revealedSlots, setRevealedSlots] = useState<Set<string>>(new Set());
  const [currentRoleIdx, setCurrentRoleIdx] = useState(-1);
  const [wheelState, setWheelState] = useState<{
    isOpen: boolean;
    type: 'reveal' | 'reroll';
    team: 'azure' | 'crimson';
    role: Role;
    winnerName: string;
    winnerPlayer?: Player;
    candidates: string[];
    duration: number;
  } | null>(null);

  // Helper to get the actual assigned player or TBD
  const getAssignedPlayer = useCallback((teamIdx: number, role: Role): Player => {
      const key = `${teamIdx}-${role}`;
      const pid = globalAssignments[key];
      if (pid) {
          return activePlayers.find(p => p.id === pid) || TBD_PLAYER;
      }
      return TBD_PLAYER;
  }, [globalAssignments, activePlayers]);

  // --- MEMOIZED BRACKET GENERATION ---
  const { quarterMatches, semiMatches, grandFinalMatch, allMatches, hasQuarterFinals } = useMemo(() => {
      const getTeamObj = (teamIndex: number) => {
          if (teamIndex < 0 || teamIndex >= match.teams.length) return null;
          const original = match.teams[teamIndex];
          // Reconstruct team with current assignments
          const updatedSlots = original.slots.map(s => ({
              ...s,
              player: getAssignedPlayer(teamIndex, s.role)
          }));
          return { ...original, slots: updatedSlots };
      };

      const getWinnerTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA) return null;
        if (!teamB) return teamA;

        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;

        if (scoreA > scoreB) return teamA;
        if (scoreB > scoreA) return teamB;
        return null;
      };

      const getLoserTeam = (matchIdx: number, teamA: any, teamB: any | null) => {
        if (!teamA || !teamB) return null;
        const scoreA = scores[`${matchIdx}-A`] || 0;
        const scoreB = scores[`${matchIdx}-B`] || 0;
        if (scoreA > 0 || scoreB > 0) {
            if (scoreA < scoreB) return teamA;
            if (scoreB < scoreA) return teamB;
        }
        return null;
      };

      const numTeams = match.teams.length;

      // Case 1: 3 teams (Stepladder)
      if (numTeams === 3) {
        const m0 = { id: 0, label: 'ELIMINATION', mode: 'BO1', teamA: getTeamObj(0), teamB: getTeamObj(1) };
        const m1 = { id: 1, label: 'CHALLENGER', mode: 'BO1', teamA: getLoserTeam(0, m0.teamA, m0.teamB), teamB: getTeamObj(2) };
        const m2 = { id: 2, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(0, m0.teamA, m0.teamB), teamB: getWinnerTeam(1, m1.teamA, m1.teamB) };
        return { quarterMatches: [], semiMatches: [m0, m1], grandFinalMatch: m2, allMatches: [m0, m1, m2], hasQuarterFinals: false };
      }

      // Case 2: 5 or 6 teams (Challenger Style)
      if (numTeams === 5 || numTeams === 6) {
        const q0 = { id: 0, label: 'QUARTER 1', mode: 'BO1', teamA: getTeamObj(0), teamB: getTeamObj(1) };
        const q1 = { id: 1, label: 'QUARTER 2', mode: 'BO1', teamA: getTeamObj(2), teamB: getTeamObj(3) };
        const q2 = { id: 2, label: 'QUARTER 3', mode: 'BO1', teamA: getTeamObj(4), teamB: getTeamObj(5) || null };

        const s1 = { id: 3, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(0, q0.teamA, q0.teamB), teamB: getWinnerTeam(1, q1.teamA, q1.teamB) };
        const s2 = { id: 4, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(2, q2.teamA, q2.teamB), teamB: getLoserTeam(3, s1.teamA, s1.teamB) };

        const gf = { id: 5, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(3, s1.teamA, s1.teamB), teamB: getWinnerTeam(4, s2.teamA, s2.teamB) };

        return { 
          quarterMatches: [q0, q1, q2], 
          semiMatches: [s1, s2], 
          grandFinalMatch: gf, 
          allMatches: [q0, q1, q2, s1, s2, gf], 
          hasQuarterFinals: true 
        };
      }

      // Case 3: 4, 8 teams
      const hasQuarterFinals = numTeams === 8;
      const qMatches: any[] = [];
      if (numTeams === 8) {
          for (let i = 0; i < 4; i++) {
              qMatches.push({ id: i, label: `QUARTER ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
      }

      const sMatches: any[] = [];
      if (numTeams === 8) {
          sMatches.push({ id: 4, label: 'SEMI FINAL 1', mode: 'BO1', teamA: getWinnerTeam(0, qMatches[0].teamA, qMatches[0].teamB), teamB: getWinnerTeam(1, qMatches[1].teamA, qMatches[1].teamB) });
          sMatches.push({ id: 5, label: 'SEMI FINAL 2', mode: 'BO1', teamA: getWinnerTeam(2, qMatches[2].teamA, qMatches[2].teamB), teamB: getWinnerTeam(3, qMatches[3].teamA, qMatches[3].teamB) });
      } else {
          // 4 teams
          for (let i = 0; i < 2; i++) {
              sMatches.push({ id: i, label: `SEMI FINAL ${i + 1}`, mode: 'BO1', teamA: getTeamObj(i * 2), teamB: getTeamObj(i * 2 + 1) });
          }
      }

      const gfIndex = numTeams === 8 ? 6 : 2;
      const gf = { id: gfIndex, label: 'GRAND FINAL', mode: 'BO3', teamA: getWinnerTeam(sMatches[0].id, sMatches[0].teamA, sMatches[0].teamB), teamB: getWinnerTeam(sMatches[1].id, sMatches[1].teamA, sMatches[1].teamB) };
      return { quarterMatches: qMatches, semiMatches: sMatches, grandFinalMatch: gf, allMatches: [...qMatches, ...sMatches, gf], hasQuarterFinals };
  }, [match, scores, globalAssignments, getAssignedPlayer]); 

  const startMatchFlow = (idx: number) => {
    const m = allMatches.find(m => m.id === idx);
    if (m && !m.teamB) {
        setScores(prev => ({ ...prev, [`${idx}-A`]: 1, [`${idx}-B`]: 0 }));
        return;
    }
    setCurrentMatchIdx(idx);

    const numTeams = match.teams.length;
    let shouldEnableRolling = false;

    // RULE: Rolling is enabled for the FIRST ROUND of matches to assign the initial roster.
    // For 8 Teams: Quarter Finals (0, 1, 2, 3)
    // For 5/6 Teams: Quarter Finals (0, 1, 2)
    // For 4 Teams: Semi Finals (0, 1) are the first round.
    // For 3 Teams: Elimination (0) and Challenger (1) are the first rounds.

    if (numTeams === 3 || numTeams === 4) {
        if (idx === 0 || idx === 1) {
            shouldEnableRolling = true;
        }
    } else {
        // Standard check for larger brackets
        shouldEnableRolling = quarterMatches.some(q => q.id === idx);
    }

    if (idx === grandFinalMatch.id) {
        setPhase('TRANSITION');
    } else {
        setPhase('REVEAL');

        // If it is NOT a "Rolling Match" (e.g. later stages), OR if it's already completed in the past:
        // We simulate "Skip All" immediately.
        if (!shouldEnableRolling || completedReveals.has(idx)) {
            const allCards = new Set<string>();
            ROLES_ORDER.forEach(r => { 
                allCards.add(`m${idx}-A-${r}`); 
                allCards.add(`m${idx}-B-${r}`); 
            });
            setRevealedSlots(allCards);
            setCurrentRoleIdx(ROLES_ORDER.length - 1);
            setCompletedReveals(prev => new Set(prev).add(idx));
        } else {
            // It IS a First Round Match and NOT completed -> Enable Rolling (Start empty)
            setRevealedSlots(new Set());
            setCurrentRoleIdx(-1);
        }
    }
  };

  const handleEvaluationComplete = (mvpId?: string, ratings?: Record<string, number>) => {
     const scoreKeyA = `${currentMatchIdx}-A`;
     const scoreKeyB = `${currentMatchIdx}-B`;
     const currentScoreA = scores[scoreKeyA] || 0;
     const currentScoreB = scores[scoreKeyB] || 0;

     // --- SCORING LOGIC FIX FOR SIDE SWAP ---
     // Check if sides are currently swapped (only in Grand Final, odd total games = Game 2)
     let isSwapped = false;
     if (currentMatchIdx === grandFinalMatch.id) {
         const gamesPlayed = currentScoreA + currentScoreB;
         if (gamesPlayed % 2 !== 0) {
             isSwapped = true;
         }
     }

     let incrementA = 0;
     let incrementB = 0;

     if (currentRoundWinner === 'azure') {
         // Visually Azure Won. 
         // If Swapped: Azure Slot holds Team B. So Score B increases.
         // If Normal: Azure Slot holds Team A. So Score A increases.
         if (isSwapped) incrementB = 1;
         else incrementA = 1;
     } else if (currentRoundWinner === 'crimson') {
         // Visually Crimson Won.
         // If Swapped: Crimson Slot holds Team A. So Score A increases.
         // If Normal: Crimson Slot holds Team B. So Score B increases.
         if (isSwapped) incrementA = 1;
         else incrementB = 1;
     }

     let newScoreA = currentScoreA + incrementA;
     let newScoreB = currentScoreB + incrementB;
     // ----------------------------------------

     setScores(prev => ({ ...prev, [scoreKeyA]: newScoreA, [scoreKeyB]: newScoreB }));
     setMatchEvaluations(prev => ({ ...prev, [`${currentMatchIdx}-${newScoreA + newScoreB}`]: { mvpId, ratings } }));

     if (currentMatchIdx === grandFinalMatch.id) {
         if (newScoreA >= 2 || newScoreB >= 2) {
             setTournamentChampion(newScoreA >= 2 ? grandFinalMatch.teamA : grandFinalMatch.teamB);
             setPhase('TOURNAMENT_END');
         } else setPhase('TRANSITION');
     } else setPhase('OVERVIEW');
  };

  const EnergyConnector = ({ type, height, style }: { type: 'fork' | 'straight', height: number, style?: React.CSSProperties }) => (
    <div 
        className="absolute top-1/2 -right-24 md:-right-40 w-24 md:w-40 pointer-events-none z-0 overflow-visible" 
        style={{ height: `${height}px`, ...style }}
    >
       <svg width="100%" height="100%" viewBox={`0 0 100 ${height}`} preserveAspectRatio="none" className="overflow-visible">
          <defs>
             <linearGradient id="energyLine" x1="0%" y1="0%" x2="100%" y2="0%">
                <stop offset="0%" stopColor="#1e3a5f" stopOpacity="0.4" />
                <stop offset="50%" stopColor="#dcb06b">
                   <animate attributeName="stop-opacity" values="0.2;1;0.2" dur="2s" repeatCount="indefinite" />
                </stop>
                <stop offset="100%" stopColor="#dcb06b" stopOpacity="0.8" />
             </linearGradient>
             <filter id="energyGlow" x="-20%" y="-20%" width="140%" height="140%">
                <feGaussianBlur stdDeviation="3" result="blur"/>
                <feComposite in="SourceGraphic" in2="blur" operator="over"/>
             </filter>
          </defs>
          {type === 'fork' ? (
             <path 
                d={`M 0,0 L 50,0 L 50,${height} L 0,${height} M 50,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          ) : (
             <path 
                d={`M 0,${height/2} L 100,${height/2}`} 
                stroke="url(#energyLine)" 
                strokeWidth="2.5" 
                fill="none" 
                filter="url(#energyGlow)"
                strokeLinecap="round"
             />
          )}
          <circle r="3" fill="#fff" filter="url(#energyGlow)">
              <animateMotion path={type === 'fork' ? `M 0,0 L 50,0 L 50,${height/2} L 100,${height/2}` : `M 0,${height/2} L 100,${height/2}`} dur="2s" repeatCount="indefinite" />
          </circle>
          {type === 'fork' && (
            <circle r="3" fill="#fff" filter="url(#energyGlow)">
                <animateMotion path={`M 0,${height} L 50,${height} L 50,${height/2} L 100,${height/2}`} dur="2s" begin="1s" repeatCount="indefinite" />
            </circle>
          )}
       </svg>
    </div>
  );

  const renderBracketMatchCard = (m: any) => {
      if (!m.teamA && !m.teamB) return <div className="w-80 h-[210px] bg-black/10 border border-white/5 clip-corner-sm flex items-center justify-center opacity-20"><span className="text-[10px] font-black font-orbitron text-white/40 tracking-widest">PENDING MATCH</span></div>;
      const sA = scores[`${m.id}-A`] || 0;
      const sB = scores[`${m.id}-B`] || 0;
      const isDone = sA > 0 || sB > 0;
      const isBye = !m.teamB;
      const isGrandFinal = m.label === 'GRAND FINAL';
      return (
        <div className={`w-80 bg-[#0a1a2f]/95 ${isGrandFinal ? 'border-2 border-[#dcb06b] shadow-[0_0_40px_rgba(220,176,107,0.4)]' : 'border border-[#1e3a5f]'} clip-corner-md p-0 relative transition-all duration-300 group hover:bg-[#0f223d] hover:border-[#dcb06b]/50 z-10`}>
            <div className={`flex justify-between items-center p-3 ${isGrandFinal ? 'bg-[#dcb06b]/30' : 'bg-[#05090f]/90'} border-b border-[#1e3a5f]`}>
                <h3 className={`${isGrandFinal ? 'text-[#dcb06b]' : 'text-[#8a9db8]'} font-orbitron font-black text-[10px] uppercase tracking-[0.2em]`}>{m.label}</h3>
                <span className={`text-[9px] px-2 py-0.5 font-bold border rounded ${isGrandFinal ? 'border-[#dcb06b] text-[#dcb06b]' : 'border-[#4a5f78] text-[#4a5f78] bg-black/30'}`}>{m.mode}</span>
            </div>
            <div className="p-4 space-y-3 h-[110px] flex flex-col justify-center">
                <div className={`flex items-center gap-3 relative transition-all duration-300 ${sA > sB || (isBye && !isDone) ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                    <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamA?.color }}></div>
                    <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sA > sB ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                        <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sA > sB ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamA?.name || 'TBD'}</span>
                        <span className={`font-orbitron font-bold text-lg ${sA > sB ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sA}</span>
                    </div>
                </div>
                {!isBye && (
                   <>
                    <div className="flex items-center gap-2 opacity-20 px-6 my-1"><div className="h-[1px] flex-1 bg-white"></div><span className="text-[8px] font-black italic text-[#8a9db8]">VS</span><div className="h-[1px] flex-1 bg-white"></div></div>
                    <div className={`flex items-center gap-3 relative transition-all duration-300 ${sB > sA ? 'opacity-100 scale-100' : (isDone ? 'opacity-40 grayscale scale-95' : 'opacity-100')}`}>
                        <div className="absolute left-0 top-0 bottom-0 w-1" style={{ backgroundColor: m.teamB?.color }}></div>
                        <div className={`flex-1 flex justify-between items-center ml-3 p-2 border-b ${sB > sA ? 'border-[#dcb06b]/50 bg-[#dcb06b]/5' : 'border-[#1e3a5f]/50'}`}>
                            <span className={`text-xs font-cinzel font-black tracking-widest truncate ${sB > sA ? 'text-[#dcb06b]' : 'text-white'}`}>{m.teamB?.name || 'TBD'}</span>
                            <span className={`font-orbitron font-bold text-lg ${sB > sA ? 'text-[#dcb06b]' : 'text-[#4a5f78]'}`}>{sB}</span>
                        </div>
                    </div>
                   </>
                )}
            </div>
            <div className="p-3 bg-black/40 border-t border-[#1e3a5f] flex items-center gap-3">
                {isBye ? (
                    <div className="flex-1 flex items-center justify-between">
                        <span className="text-[8px] text-[#dcb06b] font-black uppercase tracking-widest animate-pulse">BYE ROUND</span>
                        {!isDone && <Button onClick={() => startMatchFlow(m.id)} size="sm" className="h-[28px] text-[8px] px-4 bg-[#dcb06b]">ADVANCE</Button>}
                    </div>
                ) : (
                    <>
                        <div className="flex-1 relative">
                            <span className="absolute left-2 top-1/2 -translate-y-1/2 text-[8px] text-[#4a5f78] font-black">ID</span>
                            <input type="text" value={matchRoomIds[m.id] || ''} onChange={(e) => { const val = e.target.value.replace(/\D/g,'').slice(0,4); setMatchRoomIds(prev => ({ ...prev, [m.id]: val })); }} className="w-full bg-black/60 border border-[#1e3a5f] text-center text-xs font-orbitron font-black text-[#dcb06b] focus:outline-none focus:border-[#dcb06b] py-1 pl-6 tracking-[0.2em] rounded-sm" placeholder="----" />
                        </div>
                        {!isDone && m.teamA && m.teamB && <Button onClick={() => startMatchFlow(m.id)} disabled={!matchRoomIds[m.id] || matchRoomIds[m.id].length < 4} size="sm" className="h-[28px] text-[8px] px-3">START</Button>}
                    </>
                )}
            </div>
        </div>
      );
  };

  const activeMatchData = useMemo(() => {
    const data = allMatches.find(m => m.id === currentMatchIdx);
    if (!data) return undefined;

    // BO3 SIDE SWAP LOGIC FOR GRAND FINAL
    // Game 1: Standard
    // Game 2: Swap Sides
    // Game 3: Standard
    if (data.label === 'GRAND FINAL') {
        const sA = scores[`${currentMatchIdx}-A`] || 0;
        const sB = scores[`${currentMatchIdx}-B`] || 0;
        const gamesPlayed = sA + sB;

        // If total games played is odd (i.e. we are entering Game 2), SWAP TEAMS
        if (gamesPlayed % 2 !== 0) {
            return {
                ...data,
                teamA: data.teamB, // Original Team B becomes Azure (A)
                teamB: data.teamA  // Original Team A becomes Crimson (B)
            };
        }
    }
    return data;
  }, [allMatches, currentMatchIdx, scores]);

  const activeRoomId = matchRoomIds[currentMatchIdx] || 'AUTO';

  const handleNextReveal = () => {
    if (!activeMatchData) return;
    const nextRoleIdx = currentRoleIdx + 1;
    if (nextRoleIdx >= ROLES_ORDER.length) return;

    const role = ROLES_ORDER[nextRoleIdx];
    const azureId = `m${currentMatchIdx}-A-${role}`;
    const side = revealedSlots.has(azureId) ? 'crimson' : 'azure';

    // Determine which team in the original bracket structure this corresponds to
    const teamData = side === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
    // Find the index of this team in the original match.teams array
    const originalTeamIndex = match.teams.findIndex(t => t.name === teamData?.name);

    if (originalTeamIndex === -1) return;

    // Check if player already assigned
    let winner = getAssignedPlayer(originalTeamIndex, role);

    // JUST IN TIME ASSIGNMENT
    if (winner.id === 'tbd') {
        const currentlyAssignedIds = new Set(Object.values(globalAssignments));
        const availablePlayers = activePlayers.filter(p => !currentlyAssignedIds.has(p.id));

        // Pick a random valid player
        const pickedPlayer = getFlexibleCandidate(availablePlayers, role);

        if (pickedPlayer) {
            winner = pickedPlayer;
            // Lock them in
            const key = `${originalTeamIndex}-${role}`;
            setGlobalAssignments(prev => ({ ...prev, [key]: pickedPlayer.id }));
        } else {
            // Should rarely happen if pool is sufficient, but handle gracefully?
            // For now, if no player found, it stays TBD (or we could force a random fill ignoring roles)
            console.warn("No valid player found for", role);
        }
    }

    const revealedPlayerIds = new Set<string>();
    // Collect revealed IDs just for the wheel visual exclusion, if needed

    const candidates = activePlayers.filter(p => {
        // Filter out players already assigned to OTHER slots
        const assignedToOtherSlot = Object.entries(globalAssignments).some(([k, pid]) => k !== `${originalTeamIndex}-${role}` && pid === p.id);
        if (assignedToOtherSlot) return false;

        return canPlay(p, role);
    });

    const candidateNames = candidates.map(p => p.name);
    if (!candidateNames.includes(winner.name)) candidateNames.push(winner.name);
    const randomDuration = Math.floor(Math.random() * (9000 - 4500 + 1)) + 4500;

    setWheelState({ 
        isOpen: true, 
        type: 'reveal', 
        team: side, 
        role: role, 
        winnerName: winner.name, 
        winnerPlayer: winner, // Pass the player object
        candidates: candidateNames, 
        duration: randomDuration 
    });
  };

  const handleSkipAll = () => {
    // Greedy fill for the CURRENT MATCH only
    if (!activeMatchData) return;

    const newAssignments: Record<string, string> = {};
    const usedIds = new Set(Object.values(globalAssignments));

    const fillTeam = (teamName: string) => {
        const teamIdx = match.teams.findIndex(t => t.name === teamName);
        if (teamIdx === -1) return;

        ROLES_ORDER.forEach(role => {
            const key = `${teamIdx}-${role}`;
            if (globalAssignments[key]) return; // Already assigned

            // Find candidate
            const available = activePlayers.filter(p => !usedIds.has(p.id));
            const picked = getFlexibleCandidate(available, role);

            if (picked) {
                newAssignments[key] = picked.id;
                usedIds.add(picked.id);
            }
        });
    };

    if (activeMatchData.teamA) fillTeam(activeMatchData.teamA.name);
    if (activeMatchData.teamB) fillTeam(activeMatchData.teamB.name);

    setGlobalAssignments(prev => ({ ...prev, ...newAssignments }));

    const allCards = new Set<string>();
    ROLES_ORDER.forEach(r => { allCards.add(`m${currentMatchIdx}-A-${r}`); allCards.add(`m${currentMatchIdx}-B-${r}`); });
    setRevealedSlots(allCards);
    setCurrentRoleIdx(ROLES_ORDER.length - 1);

    // Mark as completed so we don't need to spin again
    setCompletedReveals(prev => new Set(prev).add(currentMatchIdx));
  };

  const handleRerollClick = (side: 'azure' | 'crimson', role: Role) => {
    const teamData = side === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    if (!teamData) return;
    const teamIndex = match.teams.findIndex(t => t.name === teamData.name);
    if (teamIndex === -1) return;

    // Filter candidates from unassigned players
    const currentlyAssignedIds = new Set(Object.values(globalAssignments));
    const benchPlayers = activePlayers.filter(p => !currentlyAssignedIds.has(p.id));

    if (benchPlayers.length === 0) return;

    const candidates = benchPlayers.filter(p => canPlay(p, role));
    if (candidates.length === 0) return;

    const newPlayer = candidates[Math.floor(Math.random() * candidates.length)];
    const randomDuration = Math.floor(Math.random() * (8000 - 4000 + 1)) + 4000;

    setWheelState({ 
        isOpen: true, 
        type: 'reroll', 
        team: side, 
        role: role, 
        winnerName: newPlayer.name, 
        winnerPlayer: newPlayer, 
        candidates: candidates.map(p => p.name), 
        duration: randomDuration 
    });
  };

  const handleWheelComplete = () => {
    if (!wheelState) return;
    if (wheelState.type === 'reveal') {
        const { team, role, winnerPlayer } = wheelState;

        // Ensure assignment is recorded (in case it wasn't pre-filled logic)
        if (winnerPlayer && activeMatchData) {
             const teamData = team === 'azure' ? activeMatchData.teamA : activeMatchData.teamB;
             const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
             if (teamIdx !== -1) {
                 const key = `${teamIdx}-${role}`;
                 setGlobalAssignments(prev => ({ ...prev, [key]: winnerPlayer.id }));
             }
        }

        const id = `m${currentMatchIdx}-${team === 'azure' ? 'A' : 'B'}-${role}`;
        setRevealedSlots(prev => new Set(prev).add(id));
        if (team === 'crimson') {
            const nextIdx = currentRoleIdx + 1;
            setCurrentRoleIdx(nextIdx);

            // Check if this was the final reveal for the match
            if (nextIdx >= ROLES_ORDER.length) {
                setCompletedReveals(prev => new Set(prev).add(currentMatchIdx));
            }
        }
    } else if (wheelState.type === 'reroll' && wheelState.winnerPlayer) {
        const teamData = wheelState.team === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
        if (teamData) {
            const idx = match.teams.findIndex(t => t.name === teamData.name);
            if (idx !== -1) {
                // Update Global Assignments directly
                const key = `${idx}-${wheelState.role}`;
                setGlobalAssignments(prev => ({ ...prev, [key]: wheelState.winnerPlayer!.id }));
            }
        }
    }
    setWheelState(null);
  };

  // Rename Logic
  const openRenameModal = (player: Player) => {
    setRenameState({ isOpen: true, player, newName: player.name });
  };

  const submitRename = () => {
    if (renameState.player && renameState.newName.trim()) {
        onUpdatePlayer({ ...renameState.player, name: renameState.newName.trim() });
        setRenameState({ isOpen: false, player: null, newName: '' });
    }
  };

  const renderPlayerCard = (role: Role, teamSide: 'azure' | 'crimson') => {
    const teamData = teamSide === 'azure' ? activeMatchData?.teamA : activeMatchData?.teamB;
    // Find dynamic player based on assignment
    const teamIdx = match.teams.findIndex(t => t.name === teamData?.name);
    const player = teamIdx !== -1 ? getAssignedPlayer(teamIdx, role) : TBD_PLAYER;

    const id = `m${currentMatchIdx}-${teamSide === 'azure' ? 'A' : 'B'}-${role}`;
    if (!revealedSlots.has(id)) return <div className="h-16 w-full relative overflow-hidden clip-corner-md border border-[#1e3a5f] bg-[#05090f]/80 flex flex-col items-center justify-center opacity-40 group"><div className="text-[#1e3a5f] group-hover:text-[#dcb06b]/50 transition-colors duration-500 transform scale-100 opacity-50">{RoleIcons[role]}</div></div>;

    const theme = teamSide === 'azure' ? { bg: 'bg-[#0a1a2f]', border: 'border-[#00d2ff]', glow: 'shadow-[0_0_15px_#00d2ff]', text: 'text-[#00d2ff]', gradient: 'from-[#00d2ff]/20 to-transparent' } : { bg: 'bg-[#1a0505]', border: 'border-[#ef4444]', glow: 'shadow-[0_0_15px_#ef4444]', text: 'text-[#ef4444]', gradient: 'from-[#ef4444]/20 to-transparent' };

    return (
        <div className="relative h-16 w-full animate-slide-in perspective-container group">
            <div className={`absolute inset-0 clip-corner-md border-l-4 tilt-card ${theme.bg} ${theme.border} ${theme.glow} shadow-[0_0_20px_rgba(0,0,0,0.6)] transition-all duration-300`}>
                <div className={`flex flex-col h-full relative z-10 px-6 py-0 justify-center ${teamSide === 'crimson' ? 'items-end text-right' : 'items-start text-left'}`}>
                    <div className={`mb-1 px-2 py-0.5 rounded-sm bg-black/50 border border-white/10 ${theme.text} scale-[0.8] origin-${teamSide === 'crimson' ? 'right' : 'left'} opacity-90`}>{RoleIcons[role]}</div>
                    <span className="block text-xl md:text-3xl font-bold text-white truncate font-orbitron drop-shadow-md w-full">{player.name}</span>
                    <div className={`absolute inset-0 bg-gradient-to-r ${theme.gradient} opacity-50 pointer-events-none`}></div>
                </div>

                <div className={`absolute top-2 z-50 flex gap-2 transition-all opacity-0 group-hover:opacity-100 ${teamSide === 'azure' ? 'right-4' : 'left-4'}`}>
                   {/* Reroll Button */}
                   <button 
                      onClick={(e) => { e.stopPropagation(); handleRerollClick(teamSide, role); }} 
                      className="p-2.5 bg-black/60 hover:bg-[#dcb06b] rounded-full text-white hover:text-black transition-all"
                      title="Reroll Player"
                   >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
                      </svg>
                   </button>

                   {/* Edit Name Button */}
                   <button 
                      onClick={(e) => { e.stopPropagation(); if(player) openRenameModal(player); }} 
                      className="p-2.5 bg-black/60 hover:bg-[#00d2ff] rounded-full text-white hover:text-black transition-all"
                      title="Change Nickname"
                   >
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4.5 w-4.5" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                      </svg>
                   </button>
                </div>
            </div>
        </div>
    );
  };

  // --- CHAMPION VICTORY SCREEN RENDERER ---
  const renderTournamentEnd = () => {
    return (
      <div className="fixed inset-0 z-[300] flex flex-col items-center justify-center bg-[#05090f] overflow-hidden">
        {/* Automatic Music Background */}
        <iframe 
            width="0" 
            height="0" 
            src="https://www.youtube.com/embed/13ARO0HDZsQ?autoplay=1&loop=1&playlist=13ARO0HDZsQ" 
            frameBorder="0" 
            allow="autoplay" 
            className="hidden pointer-events-none"
        ></iframe>

        {/* Visual Background Effects */}
        <div className="god-rays opacity-40"></div>
        <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#05090f_90%)] z-10"></div>

        {/* Floating Embers / Confetti */}
        {Array.from({ length: 40 }).map((_, i) => (
          <div 
            key={i} 
            className="confetti-piece"
            style={{
              left: `${Math.random() * 100}%`,
              animationDelay: `${Math.random() * 5}s`,
              backgroundColor: Math.random() > 0.5 ? '#dcb06b' : '#ffffff',
              zIndex: 20
            }}
          ></div>
        ))}

        <div className="relative z-20 flex flex-col items-center animate-trophy-pop w-full max-w-4xl">
            <h3 className="text-[#dcb06b] font-orbitron font-black tracking-[0.8em] text-sm uppercase mb-4 animate-pulse opacity-80">
                TOURNAMENT CONCLUDED
            </h3>

            <h1 className="text-5xl md:text-8xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-white to-[#dcb06b] mb-12 tracking-[0.2em] drop-shadow-[0_10px_30px_rgba(220,176,107,0.4)] text-center px-4">
                TOURNAMENT CHAMPIONS
            </h1>

            <div className="bg-[#0a1a2f]/80 border-4 border-[#dcb06b] px-12 md:px-24 py-10 clip-corner-md shadow-[0_0_100px_rgba(220,176,107,0.3)] relative overflow-hidden group mb-12 transform hover:scale-105 transition-transform duration-500">
                <div className="absolute inset-0 bg-gradient-to-br from-[#dcb06b]/10 to-transparent opacity-50"></div>
                <h2 className="text-6xl md:text-9xl font-black font-cinzel text-white text-center drop-shadow-[0_0_20px_#dcb06b]" style={{ color: tournamentChampion?.color || '#fff' }}>
                    {tournamentChampion?.name}
                </h2>
            </div>

            {/* Champions Roster Display */}
            <div className="grid grid-cols-2 md:grid-cols-5 gap-4 w-full px-6 mb-16">
               {tournamentChampion?.slots.map((slot: TeamSlot, idx: number) => (
                  <div 
                    key={idx} 
                    className="flex flex-col items-center p-4 bg-black/40 border border-[#dcb06b]/40 clip-corner-sm backdrop-blur-md transform transition-all duration-700 hover:border-[#dcb06b] hover:bg-[#dcb06b]/5 animate-slide-in"
                    style={{ animationDelay: `${idx * 150}ms` }}
                  >
                     <div className="text-[#dcb06b] mb-2 opacity-70 scale-90">
                        {RoleIcons[slot.role]}
                     </div>
                     <span className="text-white font-orbitron font-black text-sm md:text-base tracking-widest truncate max-w-full">
                        {slot.player.name}
                     </span>
                  </div>
               ))}
            </div>

            <Button onClick={onReset} size="lg" className="px-24 h-20 text-xl shadow-[0_0_50px_rgba(220,176,107,0.5)]">
                RETURN TO LOBBY
            </Button>
        </div>
      </div>
    );
  };

  if (phase === 'TOURNAMENT_END') return renderTournamentEnd();
  if (phase === 'TRANSITION' && activeMatchData) return <PortalTransition azureTeam={activeMatchData.teamA?.slots || []} crimsonTeam={activeMatchData.teamB?.slots || []} onComplete={() => setPhase('DECLARE_WIN')} />;
  if (phase === 'DECLARE_WIN' && activeMatchData) return <MatchSummary match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} onReset={(w) => { if(!w) setPhase('OVERVIEW'); else { setCurrentRoundWinner(w); setPhase('CELEBRATION'); } }} />;
  if (phase === 'CELEBRATION' && currentRoundWinner && activeMatchData) return <VictoryCelebration winner={currentRoundWinner} teamSlots={(currentRoundWinner === 'azure' ? activeMatchData.teamA?.slots : activeMatchData.teamB?.slots) || []} onDismiss={() => setPhase('EVALUATION')} />;
  if (phase === 'EVALUATION' && currentRoundWinner && activeMatchData) return <EvaluationScreen match={{ roomId: activeRoomId, azureTeam: activeMatchData.teamA?.slots || [], crimsonTeam: activeMatchData.teamB?.slots || [], isCoachMode: false, timestamp: Date.now() }} winner={currentRoundWinner} onComplete={handleEvaluationComplete} />;

  return (
    <div className="fixed inset-0 z-[100] bg-[#05090f] overflow-x-auto overflow-y-auto font-inter">
      <ConfirmModal 
        isOpen={showAbortConfirm}
        title="ABORT TOURNAMENT"
        message="Are you sure you want to end the tournament? All progress will be lost."
        onConfirm={onReset}
        onCancel={() => setShowAbortConfirm(false)}
        isDestructive={true}
      />

      {/* RENAME MODAL */}
      {renameState.isOpen && (
        <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4">
            <div className="absolute inset-0 bg-black/80 backdrop-blur-sm" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })}></div>
            <div className="relative w-full max-w-sm bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md shadow-[0_0_30px_rgba(220,176,107,0.3)] animate-slide-in p-6">
                <h3 className="text-[#dcb06b] font-cinzel font-bold text-lg mb-4 text-center tracking-widest">CHANGE NICKNAME</h3>
                <input 
                    type="text" 
                    value={renameState.newName} 
                    onChange={e => setRenameState({ ...renameState, newName: e.target.value })} 
                    className="w-full bg-black/50 border border-[#1e3a5f] p-3 text-white font-orbitron focus:border-[#dcb06b] outline-none mb-6 text-center"
                    autoFocus
                />
                <div className="flex gap-3">
                    <Button variant="secondary" onClick={() => setRenameState({ isOpen: false, player: null, newName: '' })} className="flex-1">CANCEL</Button>
                    <Button onClick={submitRename} className="flex-1">CONFIRM</Button>
                </div>
            </div>
        </div>
      )}

      <div className="absolute inset-0 bg-[radial-gradient(circle_at_top,#0a1a2f_0%,#05090f_60%)] pointer-events-none"></div>
      {phase === 'OVERVIEW' ? (
        <div className="relative z-10 w-full min-h-screen p-8 md:p-12 flex flex-col items-center min-w-max">
          <div className="text-center mb-16"><h1 className="text-4xl md:text-6xl font-cinzel font-black text-[#dcb06b] tracking-[0.3em] mb-4 uppercase">TOURNAMENT BRACKET</h1><p className="text-[10px] text-[#4a5f78] font-orbitron font-black tracking-[0.5em] uppercase border-y border-[#4a5f78]/30 py-2 inline-block">BATTLE FOR GLORY</p></div>
          <div className="flex gap-24 md:gap-40 items-center justify-center relative py-20">

            {/* COLUMN 1: QUARTER FINALS */}
            {hasQuarterFinals && (
              <div className="flex flex-col gap-16 relative">
                {quarterMatches.map((m, i) => (
                  <div key={m.id} className="relative">
                    {renderBracketMatchCard(m)}
                    {/* Connector logic */}
                    {match.teams.length === 5 || match.teams.length === 6 ? (
                      // Specialized layout for 5/6 teams: QF1 & QF2 fork to SF1, QF3 straight to SF2 (Team 5/6 flow)
                      i < 2 ? (i === 0 && <EnergyConnector type="fork" height={274} />) : <EnergyConnector type="straight" height={0} />
                    ) : (
                      i % 2 === 0 && <EnergyConnector type="fork" height={322} />
                    )}
                  </div>
                ))}
              </div>
            )}

            {/* COLUMN 2: SEMI FINALS */}
            <div className={`flex flex-col gap-32 relative`}>
              {semiMatches.map((m, i) => (
                <div key={m.id} className="relative">
                  {renderBracketMatchCard(m)}
                  {/* Fork to Grand Final */}
                  {i === 0 && <EnergyConnector type="fork" height={338} />}
                </div>
              ))}
            </div>

            {/* COLUMN 3: GRAND FINAL */}
            <div className={`relative scale-125 ml-10`}>{renderBracketMatchCard(grandFinalMatch)}</div>
          </div>
          <button onClick={() => setShowAbortConfirm(true)} className="mt-24 px-12 py-3 bg-red-900/10 border border-red-900/40 text-red-500 font-cinzel font-bold tracking-[0.3em] uppercase hover:bg-red-900 hover:text-white transition-all clip-corner-sm">ABORT TOURNAMENT</button>
        </div>
      ) : (
        <div className="w-full max-w-7xl mx-auto px-6 py-6 pb-28 relative h-screen flex flex-col justify-center overflow-hidden">
            {wheelState && wheelState.isOpen && <SpinWheel candidates={wheelState.candidates} winnerName={wheelState.winnerName} team={wheelState.team} roleName={wheelState.role} roomId={activeRoomId} duration={wheelState.duration} onComplete={handleWheelComplete} onCancel={() => setWheelState(null)} />}
            <div className="absolute top-8 left-8 right-8 z-50 flex justify-between items-center"><Button variant="outline" size="sm" onClick={() => setPhase('OVERVIEW')} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">BACK TO BRACKET</Button><div className="flex flex-col items-center gap-0 scale-[0.85] origin-top"><span className="text-[#dcb06b] font-orbitron text-[10px] tracking-[0.4em] font-black uppercase mb-1 opacity-70">ROOM ID</span><div className="relative"><div className="absolute -inset-2 bg-[#dcb06b] blur-[15px] opacity-20 pointer-events-none"></div><div className="relative bg-black/90 border border-[#dcb06b]/50 px-8 py-2 clip-corner-sm flex flex-col items-center shadow-[0_0_20px_rgba(220,176,107,0.3)]"><span className="text-2xl font-orbitron font-black text-white tracking-[0.4em] drop-shadow-[0_0_10px_#dcb06b]">{activeRoomId}</span></div></div></div>{revealedSlots.size < 10 ? <Button variant="outline" size="sm" onClick={handleSkipAll} className="border-[#dcb06b]/60 text-[#dcb06b] hover:bg-[#dcb06b]/10 text-xs px-6">SKIP ALL</Button> : <div className="w-[120px]"></div>}</div>
            <div className="relative max-w-7xl mx-auto w-full flex-1 flex flex-col justify-center px-10">
                <div className="grid grid-cols-2 gap-12 md:gap-32 items-end mb-6"><div className="text-left"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-cyan-600 tracking-widest drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]" style={{ color: activeMatchData?.teamA?.color }}>{activeMatchData?.teamA?.name.split(' ')[0]} <span className="hidden md:inline">{activeMatchData?.teamA?.name.split(' ')[1] || 'GOLEM'}</span></h2><div className="mt-2 h-1 w-full bg-gradient-to-r from-cyan-500 to-transparent shadow-[0_0_10px_#00d2ff]"></div></div><div className="text-right"><h2 className="text-2xl md:text-5xl font-cinzel font-black text-transparent bg-clip-text bg-gradient-to-b from-red-100 to-red-600 tracking-widest drop-shadow-[0_0_15px_rgba(239,68,68,0.4)]" style={{ color: activeMatchData?.teamB?.color }}><span className="hidden md:inline">{activeMatchData?.teamB?.name.split(' ')[0] || 'CRIMSON'}</span> {activeMatchData?.teamB?.name.split(' ')[1] || 'GOLEM'}</h2><div className="mt-2 h-1 w-full bg-gradient-to-l from-red-500 to-transparent shadow-[0_0_10px_#ef4444]"></div></div></div>
                <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 pointer-events-none opacity-20"><span className="text-[12rem] font-black italic text-[#dcb06b] font-orbitron select-none">VS</span></div>
                <div className="space-y-4 relative z-10">{ROLES_ORDER.map((role) => <div key={role} className="grid grid-cols-2 gap-12 md:gap-32 items-center"><div>{renderPlayerCard(role, 'azure')}</div><div>{renderPlayerCard(role, 'crimson')}</div></div>)}</div>
            </div>
            <div className="fixed bottom-0 left-0 right-0 p-8 z-50 flex justify-center items-end h-28 pointer-events-none"><div className="pointer-events-auto">{revealedSlots.size < 10 ? <button onClick={handleNextReveal} className="group relative px-16 h-16 bg-[#0a1a2f] border-2 border-[#dcb06b] clip-corner-md flex items-center justify-center text-[#dcb06b] font-cinzel font-bold text-base hover:bg-[#dcb06b] hover:text-[#05090f] transition-all duration-300 shadow-[0_0_30px_rgba(220,176,107,0.4)]">{revealedSlots.has(`m${currentMatchIdx}-A-${ROLES_ORDER[currentRoleIdx + 1]}`) ? `SELECT CRIMSON ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}` : `SELECT AZURE ${ROLES_ORDER[currentRoleIdx + 1].replace(' Lane', '').toUpperCase()}`}</button> : <Button onClick={() => setPhase('TRANSITION')} size="lg" className="px-24 h-16 text-lg animate-pulse shadow-[0_0_40px_rgba(220,176,107,0.5)]">INITIALIZE BATTLE</Button>}</div></div>
        </div>
      )}
    </div>
  );
};

import React from 'react';
import { Player, Role } from '../types';
import { Button } from './Button';
import { PlayerForm } from './PlayerForm';

interface LobbyControlModalProps {
  isOpen: boolean;
  onClose: () => void;

  // Game Modes
  isBracketMode: boolean;
  setIsBracketMode: (v: boolean) => void;
  isCoachMode: boolean;
  setIsCoachMode: (v: boolean) => void;

  // Room Settings
  roomId: string;
  setRoomId: (v: string) => void;
  isRoomReady: boolean;

  // Bracket Settings
  numBracketTeams: number;
  setNumBracketTeams: (v: number) => void;

  // Player Data
  playersLength: number;
  activePlayersLength: number;
  onBatchProcess: (batchData: any[]) => void;
  quickFill: () => void;

  // Actions
  onGenerate: () => void;
  errorMsg: string | null;
  copyShareLink: () => void;
}

export const LobbyControlModal: React.FC<LobbyControlModalProps> = ({
  isOpen, onClose,
  isBracketMode, setIsBracketMode,
  isCoachMode, setIsCoachMode,
  roomId, setRoomId, isRoomReady,
  numBracketTeams, setNumBracketTeams,
  playersLength, activePlayersLength,
  onBatchProcess, quickFill,
  onGenerate, errorMsg, copyShareLink
}) => {
  if (!isOpen) return null;

  return (
    <div className="fixed inset-0 z-[500] flex items-center justify-center p-4 bg-[#05090f]/95 backdrop-blur-xl animate-fade-in overflow-y-auto">
      <div className="relative w-full max-w-5xl bg-[#0a1a2f] border border-[#dcb06b] clip-corner-md shadow-[0_0_50px_rgba(0,0,0,0.8)] animate-slide-in my-8">

        {/* Modal Header */}
        <div className="bg-[#05090f] p-6 border-b border-[#1e3a5f] flex justify-between items-center sticky top-0 z-50">
          <div className="flex items-center gap-4">
             <div className="w-2 h-8 bg-[#dcb06b] shadow-[0_0_15px_#dcb06b]"></div>
             <div>
                <h2 className="text-[#dcb06b] font-cinzel font-black text-2xl tracking-[0.2em]">COMMAND CENTER</h2>
                <p className="text-[#4a5f78] text-[10px] uppercase font-bold tracking-widest">MATCH SETUP & CONFIGURATION</p>
             </div>
          </div>
          <button onClick={onClose} className="group flex items-center gap-2 text-[#4a5f78] hover:text-white transition-colors">
            <span className="text-xs font-bold uppercase tracking-widest group-hover:text-[#dcb06b]">Close Panel</span>
            <div className="w-10 h-10 border border-[#1e3a5f] flex items-center justify-center bg-[#0a1a2f] group-hover:border-[#dcb06b] group-hover:bg-[#dcb06b] group-hover:text-black transition-all clip-corner-sm">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-6 w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
            </div>
          </button>
        </div>

        <div className="p-6 md:p-8 grid grid-cols-1 lg:grid-cols-2 gap-8">

            {/* LEFT COLUMN: MODES & ROOM */}
            <div className="space-y-6">
                <div className="p-6 bg-[#05090f]/50 border border-[#1e3a5f] clip-corner-sm relative">
                    <h3 className="text-white font-orbitron font-bold text-sm tracking-widest mb-4 border-b border-white/10 pb-2">GAME MODE SELECTION</h3>

                    <div className="grid grid-cols-1 gap-3">
                        {/* COACH MODE */}
                        <button 
                            onClick={() => setIsCoachMode(!isCoachMode)}
                            disabled={isBracketMode}
                            className={`relative w-full group overflow-hidden p-[2px] clip-corner-sm transition-all duration-300 ${isBracketMode ? 'opacity-50 cursor-not-allowed' : ''}`}
                        >
                            <div className={`
                                relative z-10 py-4 px-6 flex items-center justify-between transition-all duration-300 clip-corner-sm border
                                ${isCoachMode 
                                    ? 'bg-black text-[#dcb06b] border-transparent shadow-[inset_0_0_20px_rgba(220,176,107,0.5)]' 
                                    : 'bg-[#0a1a2f]/80 border-[#1e3a5f] text-[#4a5f78]'}
                            `}>
                                <div className="flex flex-col items-start">
                                    <span className="font-cinzel font-black text-sm tracking-[0.2em] uppercase">COACH MODE</span>
                                    <span className="text-[9px] text-white/40 font-orbitron">12 Players (2 Coaches)</span>
                                </div>
                                <div className={`w-4 h-4 rounded-sm border ${isCoachMode ? 'bg-[#dcb06b] border-[#dcb06b]' : 'border-[#4a5f78]'}`}></div>
                            </div>
                        </button>

                        {/* BRACKET MODE */}
                        <button 
                            onClick={() => { 
                                const newVal = !isBracketMode;
                                setIsBracketMode(newVal); 
                                if(newVal) setIsCoachMode(false); 
                            }}
                            className="relative w-full group overflow-hidden p-[2px] clip-corner-sm transition-all duration-300"
                        >
                            <div className={`
                                relative z-10 py-4 px-6 flex items-center justify-between transition-all duration-300 clip-corner-sm border
                                ${isBracketMode 
                                    ? 'bg-black text-white border-transparent shadow-[inset_0_0_20px_rgba(255,255,255,0.4)]' 
                                    : 'bg-[#0a1a2f]/80 border-[#1e3a5f] text-[#4a5f78]'}
                            `}>
                                <div className="flex flex-col items-start">
                                    <span className="font-cinzel font-black text-sm tracking-[0.2em] uppercase">BRACKET MODE</span>
                                    <span className="text-[9px] text-white/40 font-orbitron">Tournament Generator</span>
                                </div>
                                <div className={`w-4 h-4 rounded-sm border ${isBracketMode ? 'bg-white border-white' : 'border-[#4a5f78]'}`}></div>
                            </div>
                        </button>
                    </div>

                    {/* BRACKET SETTINGS */}
                    {isBracketMode && (
                        <div className="mt-4 animate-slide-in">
                            <div className="bg-[#0a1a2f] border border-[#dcb06b]/30 p-4 clip-corner-sm">
                                <div className="text-[10px] text-[#8a9db8] font-black uppercase tracking-widest mb-3 flex justify-between">
                                    <span>Number of Teams</span>
                                    <span className="text-white font-orbitron">{numBracketTeams} TEAMS</span>
                                </div>
                                <div className="flex gap-1 mb-2">
                                    {[3, 4, 5, 6, 8].map(n => (
                                    <button 
                                        key={n}
                                        onClick={() => setNumBracketTeams(n)}
                                        className={`flex-1 py-3 font-orbitron font-bold text-sm clip-corner-sm border transition-all ${numBracketTeams === n ? 'bg-[#dcb06b] text-black border-[#dcb06b] shadow-[0_0_10px_#dcb06b]' : 'bg-black/40 text-[#4a5f78] border-[#1e3a5f]'}`}
                                    >
                                        {n}
                                    </button>
                                    ))}
                                </div>
                                <div className="text-[9px] text-[#4a5f78] uppercase text-center font-bold tracking-widest bg-black/40 py-1 rounded">Requires {numBracketTeams * 5} active players</div>
                            </div>
                        </div>
                    )}
                </div>

                {/* ROOM ID */}
                {!isBracketMode && (
                    <div className="relative group">
                        <div className="absolute -inset-[1px] bg-gradient-to-b from-[#dcb06b]/50 to-transparent clip-corner-md opacity-30"></div>
                        <div className="bg-[#0a1a2f] backdrop-blur-md p-6 clip-corner-md relative overflow-hidden">
                            <div className="flex items-center justify-between mb-4 border-b border-[#dcb06b]/20 pb-2">
                                <h3 className="text-sm text-[#dcb06b] font-cinzel font-bold tracking-[0.2em] uppercase">Battle Room ID</h3>
                                <span className={`text-[10px] font-orbitron font-bold transition-colors duration-300 ${isRoomReady ? 'text-green-500' : 'text-red-500'}`}>
                                    {isRoomReady ? 'READY' : 'REQUIRED'}
                                </span>
                            </div>
                            <input 
                                type="text" 
                                value={roomId} 
                                onChange={(e) => setRoomId(e.target.value.replace(/\D/g,'').slice(0,4))} 
                                placeholder="0000" 
                                className={`relative z-10 bg-black/40 border border-[#1e3a5f] p-4 text-5xl font-orbitron font-black w-full text-center focus:outline-none tracking-[0.4em] transition-all duration-300 clip-corner-sm
                                ${roomId ? 'text-white border-[#dcb06b] shadow-[0_0_15px_rgba(220,176,107,0.2)]' : 'text-[#4a5f78] opacity-60'}
                                placeholder-[#1e3a5f]`}
                            />
                        </div>
                    </div>
                )}
            </div>

            {/* RIGHT COLUMN: PLAYER MANAGEMENT */}
            <div className="space-y-6">
                <PlayerForm onBatchProcess={onBatchProcess} isCoachMode={isCoachMode} />

                {/* ACTIVE PLAYERS STATUS */}
                <div className="relative group">
                  <div className="absolute -inset-[1px] bg-gradient-to-b from-[#dcb06b]/50 to-transparent clip-corner-md opacity-30"></div>
                  <div className="bg-[#0a1a2f]/90 backdrop-blur-md p-6 clip-corner-md relative">
                     <div className="flex justify-between items-end mb-6">
                        <div>
                           <div className="text-[#8a9db8] text-[10px] uppercase font-bold mb-1">Active Roster</div>
                           <div className="flex items-baseline gap-2">
                              <div className={`text-5xl font-orbitron font-bold ${activePlayersLength >= (isBracketMode ? numBracketTeams * 5 : (isCoachMode ? 12 : 10)) ? 'text-white' : 'text-red-500'}`}>
                                  {activePlayersLength}
                              </div>
                              <div className="text-xl font-orbitron font-bold text-[#4a5f78]">/ {playersLength}</div>
                           </div>
                           <div className="text-[10px] text-[#4a5f78] uppercase mt-1">
                               Target: <span className="text-[#dcb06b] font-bold">{isBracketMode ? numBracketTeams * 5 : (isCoachMode ? 12 : 10)} Players</span>
                           </div>
                        </div>
                        <button onClick={quickFill} className="text-[10px] text-[#dcb06b] border border-[#dcb06b] px-4 py-2 hover:bg-[#dcb06b] hover:text-black transition-colors font-bold uppercase tracking-wider clip-corner-sm">
                            Quick Fill Bot
                        </button>
                     </div>

                     {errorMsg && (
                         <div className="mb-4 p-3 border-l-4 border-red-500 bg-red-900/20 text-red-200 text-xs font-orbitron flex items-center gap-2">
                             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" /></svg>
                             {errorMsg}
                         </div>
                     )}

                     <Button 
                        onClick={() => {
                            onGenerate();
                            // Only close if successful (errorMsg is set by parent, but we can't detect it easily here without effect, 
                            // so we assume validation happens inside onGenerate. 
                            // Actually, onGenerate sets errorMsg. 
                            // The parent should check validity. For now, user clicks close manually or we can close if no error?
                            // Let's keep it manual close or assume validation passed if visual feedback changes.
                        }} 
                        className="w-full h-16 text-lg tracking-[0.2em] shadow-[0_0_20px_rgba(220,176,107,0.3)]" 
                        disabled={activePlayersLength < (isBracketMode ? numBracketTeams * 5 : (isCoachMode ? 12 : 10)) || (!isBracketMode && !isRoomReady)}
                     >
                        START MATCHMAKING
                     </Button>
                  </div>
                </div>

                <button 
                  onClick={copyShareLink}
                  className="w-full py-3 px-4 border border-[#1e3a5f] bg-[#05090f] text-[#4a5f78] hover:text-[#dcb06b] hover:border-[#dcb06b] transition-all text-[10px] uppercase font-bold tracking-[0.2em] clip-corner-sm flex items-center justify-center gap-2"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
                  Share Squad Link
                </button>
            </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import { Player, Role } from '../types';
import { ROLES_ORDER } from '../constants';

interface PlayerListProps {
  players: Player[];
  onRemove: (id: string) => void;
  onToggleActive: (id: string) => void;
  onEdit: (player: Player) => void;
  isSidebarOpen?: boolean;
}

type FilterType = 'ALL' | 'ACTIVE' | 'BENCH' | Role;

export const PlayerList: React.FC<PlayerListProps> = ({ players, onRemove, onToggleActive, onEdit, isSidebarOpen = true }) => {
  const [filter, setFilter] = useState<FilterType>('ALL');
  const [searchQuery, setSearchQuery] = useState('');
  const [menuOpenId, setMenuOpenId] = useState<string | null>(null);
  const [menuPosition, setMenuPosition] = useState<{ top: number; left: number }>({ top: 0, left: 0 });

  useEffect(() => {
    const handleClickOutside = () => setMenuOpenId(null);
    if (menuOpenId) document.addEventListener('click', handleClickOutside);
    return () => document.removeEventListener('click', handleClickOutside);
  }, [menuOpenId]);

  const toggleMenu = (e: React.MouseEvent, id: string) => {
    e.stopPropagation();
    const rect = e.currentTarget.getBoundingClientRect();
    setMenuPosition({ top: rect.bottom + 5, left: rect.right - 128 });
    setMenuOpenId(menuOpenId === id ? null : id);
  };

  const handleFilterClick = (val: string) => {
      setFilter(val as FilterType);
  };

  const filteredPlayers = players.filter(p => {
    let matchesCategory = true;
    if (filter === 'ACTIVE') matchesCategory = p.isActive;
    else if (filter === 'BENCH') matchesCategory = !p.isActive;
    else if (Object.values(Role).includes(filter as Role)) {
       const targetRole = filter as Role;
       matchesCategory = p.roles.includes(targetRole) || (p.isAllRoles && targetRole !== Role.COACH);
    }
    const matchesSearch = p.name.toLowerCase().includes(searchQuery.toLowerCase());
    return matchesCategory && matchesSearch;
  });

  const getRoleBadgeStyle = (role: Role) => {
      switch (role) {
          case Role.COACH: return 'text-white border-white bg-white/10';
          case Role.CLASH: return 'text-orange-400 border-orange-500/50 bg-orange-900/20'; 
          case Role.JUNGLE: return 'text-emerald-400 border-emerald-500/50 bg-emerald-900/20'; 
          case Role.MID: return 'text-blue-400 border-blue-500/50 bg-blue-900/20'; 
          case Role.FARM: return 'text-yellow-400 border-yellow-500/50 bg-yellow-900/20'; 
          case Role.ROAM: return 'text-cyan-400 border-cyan-500/50 bg-cyan-900/20'; 
          default: return 'text-gray-400 border-gray-600 bg-gray-800/30';
      }
  };

  const renderRatingArrows = (rating: number) => {
    if (!rating || rating === 0) return null;

    // Pastikan panah dirender dua kali jika nilai mutlaknya adalah 2
    if (rating > 0) {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-green-400 items-center justify-center">
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>
           {Math.abs(rating) === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" /></svg>}
        </div>
      );
    } else {
      return (
        <div className="flex flex-col -space-y-1.5 ml-1 text-red-500 items-center justify-center">
           {Math.abs(rating) === 2 && <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>}
           <svg xmlns="http://www.w3.org/2000/svg" className="h-2.5 w-2.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={5}><path strokeLinecap="round" strokeLinejoin="round" d="M19 9l-7 7-7-7" /></svg>
        </div>
      );
    }
  };

  // UPDATED GRID CLASSES: Always assume a wide layout now
  const gridClasses = "grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5 2xl:grid-cols-6";

  return (
    <div>
      <div className="mb-6 flex flex-col xl:flex-row gap-4 items-start xl:items-center justify-between">
         <div className="w-full xl:flex-1 overflow-x-auto pb-2">
             <div className="flex gap-2 min-w-max">
                {['ALL', 'ACTIVE', 'BENCH', ...ROLES_ORDER, Role.COACH].map(val => (
                  <button key={val} onClick={() => handleFilterClick(val)} className={`px-4 py-2 text-[10px] uppercase font-bold tracking-wider clip-corner-sm border transition-all ${filter === val ? 'bg-[#dcb06b] text-[#05090f] border-[#dcb06b]' : 'bg-[#05090f] text-[#8a9db8] border-[#1e3a5f] hover:border-[#dcb06b]'}`}>
                    {val.split(' ')[0]}
                  </button>
                ))}
             </div>
         </div>
         <div className="relative w-full xl:w-64">
             <input type="text" placeholder="Find Player..." value={searchQuery} onChange={e => setSearchQuery(e.target.value)} className="w-full bg-[#05090f] border border-[#1e3a5f] px-3 py-1.5 pl-8 text-xs text-white focus:outline-none focus:border-[#dcb06b] clip-corner-sm font-orbitron"/>
             <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 absolute left-2 top-1.5 text-[#4a5f78]" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 21l-6-6m2-5a7 7 0 11-14 0 7 7 0 0114 0z" /></svg>
         </div>
      </div>

      <div className={`grid gap-3 ${gridClasses}`}>
        {filteredPlayers.map(player => {
          const ws = player.stats.currentStreak || 0;
          const isMvp = player.isLastMatchMvp;
          const isCoach = player.roles.includes(Role.COACH);

          let animationLayer = null;
          let glowColor = '';
          let primaryColor = '';

          // Hirarki Status & Warna Trace Border
          if (player.isActive) {
            if (isMvp) {
              primaryColor = '#fbbf24'; // Emas
              glowColor = 'drop-shadow-[0_0_12px_#fbbf24]';
            } else if (isCoach) {
              primaryColor = '#ffffff'; // Putih
              glowColor = 'drop-shadow-[0_0_12px_rgba(255,255,255,0.6)]';
            } else if (ws >= 2) {
              if (ws >= 5) primaryColor = '#ef4444'; // Merah
              else if (ws >= 4) primaryColor = '#f97316'; // Oren
              else if (ws >= 3) primaryColor = '#a855f7'; // Ungu
              else primaryColor = '#00d2ff'; // Biru Cyan

              glowColor = `drop-shadow-[0_0_10px_${primaryColor}]`;
            }

            if (primaryColor) {
               animationLayer = (
                 <div 
                   className="absolute inset-[-150%] animate-[spin_4s_linear_infinite]"
                   style={{
                     background: `conic-gradient(from 0deg, ${primaryColor} 0deg, ${primaryColor} 40deg, transparent 40deg, transparent 180deg, ${primaryColor} 180deg, ${primaryColor} 220deg, transparent 220deg, transparent 360deg)`
                   }}
                 />
               );
            }
          }

          return (
            <div key={player.id} className={`relative group h-full transition-all duration-300 min-h-[90px] ${glowColor}`}>
              {/* Animated Border Background */}
              <div className="absolute inset-0 clip-corner-sm overflow-hidden z-0 bg-[#1e3a5f]/20">
                 {animationLayer}
              </div>

              {/* Inner Card content */}
              <div className={`absolute inset-[2px] clip-corner-sm z-10 flex flex-col p-2 ${player.isActive ? (isCoach ? 'bg-[#000000]' : 'bg-[#05090f]') : 'bg-[#05090f]/80 grayscale backdrop-blur-sm'}`}>

                {/* BENCHED STAMP - Only for inactive players */}
                {!player.isActive && (
                    <div className="absolute inset-0 z-50 flex items-center justify-center pointer-events-none overflow-hidden">
                        <div className="absolute inset-0 bg-red-900/10 mix-blend-overlay"></div>
                        <div className="rotate-[-15deg] border-4 border-red-600/80 px-4 py-1 text-red-600/90 font-black text-2xl tracking-[0.3em] uppercase bg-black/40 backdrop-blur-sm shadow-[0_0_20px_rgba(220,38,38,0.4)] animate-pulse-fast">
                            BENCHED
                        </div>
                    </div>
                )}

                <div className="flex justify-between items-start mb-2 relative z-10">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-1">
                      <div className={`text-lg font-bold font-orbitron truncate ${isMvp ? 'text-yellow-400' : 'text-white'}`}>{player.name}</div>
                      {player.isActive && renderRatingArrows(player.lastMatchRating || 0)}
                    </div>
                    <div className="flex flex-wrap gap-1 mt-1">
                      {isCoach ? (
                        <span className="text-[7px] border border-white text-white px-1.5 py-0.5 rounded uppercase font-black bg-white/10">COACH</span>
                      ) : player.isAllRoles ? (
                        <span className="text-[7px] border border-purple-500 text-purple-400 px-1 py-0.5 rounded uppercase">All Roles</span>
                      ) : (
                        player.roles.map(r => <span key={r} className={`text-[7px] border px-1 py-0.5 rounded uppercase ${getRoleBadgeStyle(r)}`}>{r.split(' ')[0]}</span>)
                      )}
                    </div>
                  </div>

                  {/* Status Mini-Tags */}
                  <div className="flex flex-col items-end gap-1">
                    <button onClick={(e) => toggleMenu(e, player.id)} className="p-1 text-[#4a5f78] hover:text-[#dcb06b] mb-1">
                      <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 5v.01M12 12v.01M12 19v.01M12 6a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2zm0 7a1 1 0 110-2 1 1 0 010 2z" /></svg>
                    </button>

                    <div className="flex flex-col gap-1 items-end">
                       {/* MVP Mini-Tag */}
                       {isMvp && player.isActive && (
                         <div className="px-2 py-0.5 text-[8px] font-black uppercase tracking-tighter bg-[#fbbf24] text-black clip-corner-sm shadow-[0_0_8px_rgba(251,191,36,0.6)]">
                            MVP
                         </div>
                       )}

                       {/* Win Streak Mini-Tag */}
                       {ws >= 2 && player.isActive && (
                         <div 
                           className="px-2 py-0.5 text-[8px] font-black uppercase tracking-tighter text-white clip-corner-sm shadow-md"
                           style={{ backgroundColor: primaryColor }}
                         >
                            {ws} WS
                         </div>
                       )}
                    </div>
                  </div>
                </div>

                <div className="mt-auto flex justify-between text-[9px] font-mono border-t border-white/5 pt-1 relative z-10">
                  <span className="text-[#8a9db8]">Matches: <span className="text-white">{player.stats.matchesPlayed}</span></span>
                  <span className="text-[#8a9db8]">WR: <span className="text-white">{player.stats.matchesPlayed > 0 ? Math.round((player.stats.wins/player.stats.matchesPlayed)*100) : 0}%</span></span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
      {menuOpenId && createPortal(<div className="fixed z-[9999] w-32 bg-[#05090f] border border-[#dcb06b] clip-corner-sm flex flex-col shadow-2xl" style={{ top: menuPosition.top, left: menuPosition.left }} onClick={e => e.stopPropagation()}><button onClick={() => { onToggleActive(menuOpenId); }} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Toggle Active</button><button onClick={() => { onEdit(players.find(p => p.id === menuOpenId)!); }} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-white hover:bg-[#dcb06b] hover:text-black transition-colors">Edit</button><button onClick={() => { onRemove(menuOpenId); }} className="px-3 py-3 text-left text-[10px] uppercase font-bold text-red-500 hover:bg-red-500 hover:text-white transition-colors">Remove</button></div>, document.body)}
    </div>
  );
};

